-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date, ,>
-- Description:	<Description, ,>
-- =============================================
CREATE FUNCTION [dbo].[GroupID]
(
	-- Add the parameters for the function here
	@item_typeid int
)
RETURNS int
AS
BEGIN

	DECLARE @ret int

	SELECT @ret = y FROM dbo.shiftRight((@item_typeid & 0xFF000000), 24)

	-- Return the result of the function
	RETURN @ret

END
GO
