-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date, ,>
-- Description:	<Description, ,>
-- =============================================
CREATE FUNCTION [dbo].[UNIX_TIMESTAMP] 
(
	@date datetime
)
RETURNS BIGINT
AS
BEGIN
	-- Declare the return variable here
	DECLARE @Ret BIGINT

	-- Add the T-SQL statements to compute the return value here
	SELECT @Ret = DATEDIFF(SECOND, {d'1970-01-01'}, @date)

	-- Return the result of the function
	RETURN @Ret

END
GO
/****** Objeto:  UserDefinedFunction [m2ss].[substring_index]    Data do Script: 03/05/2026 15:40:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [m2ss].[substring_index](@str varchar(max), @delim varchar(max), @count int) RETURNS NVARCHAR(MAX)
AS
  BEGIN
      IF(@str IS NULL OR @delim IS NULL OR @count IS NULL)
            RETURN NULL
          
      IF(@count = 0 OR @delim = N'')
            RETURN N''
      
      IF(@count < 0)
            RETURN REVERSE(m2ss.substring_index(REVERSE(@str), REVERSE(@delim), -@count))
            
      DECLARE @dellen int
      SET @dellen = len(@delim + '.') - 1
      
      DECLARE @ocr int
      SET @ocr = 0
      
      DECLARE @cursor int
      SET @cursor = 1
      
      WHILE(1 = 1)
      BEGIN
        DECLARE @tmp INT
        SET @tmp = CHARINDEX(@delim, @str, @cursor)
        IF(@tmp = 0)
            RETURN @str
            
          SET @ocr = @ocr + 1
          IF(@ocr = @count)
            RETURN SUBSTRING(@str, 1, @tmp - 1)
            
          SET @cursor = @tmp + @dellen
      END
      
    RETURN NULL
  END
GO
/****** Objeto:  UserDefinedFunction [m2ss].[time_to_sec]    Data do Script: 03/05/2026 15:40:47 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE FUNCTION [m2ss].[time_to_sec](@time DATETIME) RETURNS INT
AS
  BEGIN
        RETURN DATEPART(HOUR, @time) * 3600 +
               DATEPART(MINUTE, @time) * 60 + DATEPART(SECOND, @time)
  END
GO
