*/

CREATE FUNCTION [pangya].[GetAchievementPoint] 
( 
   @IDUSER int
)
RETURNS int
WITH EXECUTE AS CALLER
AS 
   BEGIN
	RETURN 
	(
		SELECT
			COUNT_BIG(b.id) * 10 AS [LEVEL]
		FROM
			pangya.pangya_achievement a
			INNER JOIN
			pangya.pangya_quest b
			ON a.ID_ACHIEVEMENT = b.achievement_id
		WHERE 
			a.[UID] = @IDUSER
			AND b.[Date] IS NOT NULL
		GROUP BY a.[UID]
	)

	-- Old
	 /*RETURN 
        (
        SELECT count_big(C.Data_Sec) * 10 AS LEVEL
        FROM 
            (
                SELECT 
                    a.TypeID, 
                    D.IDX, 
                    D.UID, 
                    D.ID_ACHIEVEMENT, 
                    D.TypeID_ACHIEVE, 
                    D.Count_ID, 
                    D.Data_Sec, 
                    D.Objetivo_Quest
                FROM pangya.pangya_achievement  AS a, pangya.pangya_quest  AS D
                WHERE D.UID = @IDUSER AND a.ID_ACHIEVEMENT = D.ID_ACHIEVEMENT
            )  AS B 
                LEFT OUTER JOIN 
                (
                    SELECT 
                    count_item.UID, 
                    count_item.Nome, 
                    count_item.ID_ACHIEVEMENT, 
                    count_item.TypeID, 
                    count_item.Count_ID, 
                    count_item.Count_Num_Item, 
                    count_item.Data_Sec, 
                    count_item.TIPO
                    FROM pangya.pangya_counter_item
                    WHERE count_item.UID = @IDUSER
                )  AS C 
                ON C.Count_ID = B.Count_ID
        WHERE 
            B.[UID] = @IDUSER AND 
            C.Data_Sec <> 0 AND 
            C.Data_Sec IS NOT NULL
        )*/
END
GO
