CREATE FUNCTION [pangya].[GetCardExpRate] 
( 
   @IDUSER int
)
RETURNS int
WITH EXECUTE AS CALLER
AS 
   BEGIN

      DECLARE
         @qntd_efeito int = 0, 
         @qntd int = 0, 
         @FINISHED int = 0

      DECLARE
          TYPEID_CURSOR CURSOR LOCAL FORWARD_ONLY FOR 
            SELECT pangya_card_equip.Efeito_Qntd
            FROM pangya.pangya_card_equip
            WHERE 
               pangya_card_equip.UID = @IDUSER AND 
               pangya_card_equip.Efeito = 3 AND 
               pangya_card_equip.END_DT > getdate()

      OPEN TYPEID_CURSOR

      /*
      *   SSMA informational messages:
      *   M2SS0003: The following SQL clause was ignored during conversion:
      *   CARD_EXP : .
      *   M2SS0003: The following SQL clause was ignored during conversion:
      *   CARD_EXP.
      */

      WHILE (1 = 1)
      
         BEGIN

            FETCH TYPEID_CURSOR
                INTO @qntd_efeito

            IF @@FETCH_STATUS <> 0
               SET @FINISHED = 1

            IF @FINISHED = 1
               BREAK

            SET @qntd = @qntd + @qntd_efeito

         END

      CLOSE TYPEID_CURSOR

      DEALLOCATE TYPEID_CURSOR

      RETURN @qntd

   END
GO
