CREATE FUNCTION [pangya].[GetItensExpRate] 
( 
   @IDUSER int
)
RETURNS int
WITH EXECUTE AS CALLER
AS 
   BEGIN

      DECLARE
         @item_typeid int = 0, 
         @qntd int = 0, 
         @FINISHED int = 0

      DECLARE
          TYPEID_CURSOR CURSOR LOCAL FORWARD_ONLY FOR 
            /*
            *   SSMA warning messages:
            *   M2SS0219: Converted operator may not work exactly the same as in MySQL

            *   SSMA informational messages:
            *   M2SS0282: Binary value is converted to numeric value
