            *   M2SS0282: Binary value is converted to numeric value
            *   M2SS0282: Binary value is converted to numeric value
            *   M2SS0282: Binary value is converted to numeric value
            *   M2SS0282: Binary value is converted to numeric value
            *   M2SS0282: Binary value is converted to numeric value
            *   M2SS0282: Binary value is converted to numeric value
            */

            SELECT pangya_item_warehouse.typeid
            FROM pangya.pangya_item_warehouse
            WHERE 
               pangya_item_warehouse.UID = @IDUSER AND 
               pangya_item_warehouse.valid = 1 AND 
               pangya_item_warehouse.C0 > 0 AND 
               pangya_item_warehouse.typeid IN ( 
               436207626, 
               436207627, 
               436207629, 
               436207630, 
               436207631, 
               436207636, 
               436207669, 
               436207749, 
               436207769, 
               436207868 )

      OPEN TYPEID_CURSOR

      /*
      *   SSMA informational messages:
      *   M2SS0003: The following SQL clause was ignored during conversion:
      *   ITEM_EXP : .
      *   M2SS0003: The following SQL clause was ignored during conversion:
      *   ITEM_EXP.
      */

      WHILE (1 = 1)
      
         BEGIN

            FETCH TYPEID_CURSOR
                INTO @item_typeid

            IF @@FETCH_STATUS <> 0
               SET @FINISHED = 1

            IF @FINISHED = 1
               BREAK

            SET @qntd = @qntd + 200

         END

      CLOSE TYPEID_CURSOR

      DEALLOCATE TYPEID_CURSOR

      RETURN @qntd

   END
