SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

/*
*   SSMA informational messages:
*   M2SS0134: Conversion of following Comment(s) is not supported :  tira os 10 pangs da msg enviada
*
*/

CREATE PROCEDURE [pangya].[AddMsgOff]  
   @from_uid int,
   @uid_to int,
   @msg_in nvarchar(64)
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA informational messages:
      *   M2SS0231: Zero-date, zero-in-date and invalid dates to not null columns has been replaced with GetDate()/Constant date
      */

      INSERT pangya.pangya_msg_user(
         pangya.pangya_msg_user.uid, 
         pangya.pangya_msg_user.uid_from, 
         pangya.pangya_msg_user.valid, 
         pangya.pangya_msg_user.msg, 
         pangya.pangya_msg_user.reg_date)
         VALUES (
            @uid_to, 
            @from_uid, 
            1, 
            @msg_in, 
            isnull(getdate(), getdate()))

      UPDATE pangya.user_info
         SET 
            pang = user_info.Pang - 10
      WHERE user_info.UID = @from_uid

   END
GO
