GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[CheckDolfiniPassword]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported : Check Dolfini Senha USER
      *
      */

      IF 
         (
            SELECT pangya_dolfini_locker.uid
            FROM pangya.pangya_dolfini_locker
            WHERE pangya_dolfini_locker.uid = @IDUSER
         ) IS NULL
         BEGIN

            /*
            *   SSMA informational messages:
            *   M2SS0214: The Default Values for the Columns have been added in the Insert Statement based on Project setttings.
            */

            INSERT pangya.pangya_dolfini_locker(pangya.pangya_dolfini_locker.uid, pangya.pangya_dolfini_locker.pang, pangya.pangya_dolfini_locker.locker)
               VALUES (@IDUSER, 0, 0)

            SELECT 2 AS OPT

         END
      ELSE 
         IF 
            (
               SELECT pangya_dolfini_locker.senha
               FROM pangya.pangya_dolfini_locker
               WHERE pangya_dolfini_locker.uid = @IDUSER
            ) IS NULL
            SELECT 2 AS OPT
         ELSE 
            SELECT 76 AS OPT

   END
