/****** Objeto:  StoredProcedure [pangya].[CheckWeblink]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [pangya].[CheckWeblink]  
    @id_in nvarchar(25),
    @weblink_key nvarchar(8) 
AS 
BEGIN
    SET XACT_ABORT ON;

    DECLARE @RET int;
    
    -- Verifica se existe o registro com o weblink_key válido
    SELECT @RET = a.uid
    FROM pangya.pangya_weblink_key AS a
    INNER JOIN pangya.account AS b
        ON b.UID = a.uid
    WHERE 
        b.ID = @id_in
        AND a.[key] = @weblink_key
        AND a.valid = 1;

    -- Se um registro foi encontrado, atualiza o campo 'valid'
    IF @RET IS NOT NULL
    BEGIN
        UPDATE pangya.pangya_weblink_key
        SET valid = 0
        WHERE uid = @RET;
    END

    -- Retorna o uid encontrado ou 0 se não houver
    SELECT ISNULL(@RET, 0) AS [uid];
END
GO
