/****** Objeto:  StoredProcedure [pangya].[Event_SendBirthdayGifts]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [pangya].[Event_SendBirthdayGifts]
AS
BEGIN
    DECLARE @CurrentDate DATE = GETDATE()
    DECLARE @CurrentYear INT = YEAR(@CurrentDate)

    -- Cursor para iterar sobre os jogadores
    DECLARE PlayerCursor CURSOR FOR
    SELECT [UID], [ID], BirthDay
    FROM [pangya].[account]

    DECLARE @UID INT
    DECLARE @ID VARCHAR(50)
    DECLARE @BirthDay DATE
	DECLARE @TIME DATETIME2
	DECLARE @Age INT
	DECLARE  @MSGID INT
	 DECLARE @Message NVARCHAR(MAX);
    
	OPEN PlayerCursor

    FETCH NEXT FROM PlayerCursor INTO @UID, @ID, @BirthDay

    WHILE @@FETCH_STATUS = 0
    BEGIN
        IF DATEPART(MONTH, @BirthDay) = DATEPART(MONTH, @CurrentDate) AND DATEPART(DAY, @BirthDay) = DATEPART(DAY, @CurrentDate)
        BEGIN
            -- Verificar se já foi enviado presente este ano ou em anos anteriores
            IF NOT EXISTS (SELECT 1 FROM [pangya].[pangya_player_birth_day_log] WHERE UserID = @UID AND YEAR(SendDate) = @CurrentYear)
            BEGIN
                -- Enviar presente
                INSERT INTO [pangya].[pangya_player_birth_day_log] ([UserID], [LOGIN], [SendDate])
                VALUES (@UID, @ID, @CurrentDate)
				
SET @Message = N'Happy Birthday, ' + @ID + N'!';
               -- Calcular idade
                SET @Age = @CurrentYear - YEAR(@BirthDay)
				-- adiciona cookies para o jogador
				update pangya.user_info set cookie  = Cookie + @Age where UID = @UID;

				INSERT INTO pangya.pangya_gift_table(UID, FROMID, MESSAGE, GIFTDATE, LIDA_YN, VALID) VALUES(@UID, N'@ADM', @Message, getdate(), 0, 1)

    SET @MSGID = @@IDENTITY	
	SET @TIME =  CAST(GETDATE() AS DATETIME2)
	 EXECUTE pangya.ProcInsertItemNoEmail 
         0, 
         @UID, 
         @MSGID, 
         -1, 
         947912724, -- id do item
         0, 
         0, -- normal
         7 -- dias

EXEC pangya.ProcRegisterNoticeBroadcast 
    @Message, 
    3, 
    1, 
    1, 
  @TIME

            END
        END

        FETCH NEXT FROM PlayerCursor INTO @UID, @ID, @BirthDay
    END

    CLOSE PlayerCursor
    DEALLOCATE PlayerCursor
END
GO
