         pangya.pangya_gift_table.fromid, 
         pangya.pangya_gift_table.message, 
         pangya.pangya_gift_table.giftdate, 
         pangya.pangya_gift_table.Lida_YN, 
         pangya.pangya_gift_table.valid, 
         pangya.pangya_gift_table.Flag, 
         pangya.pangya_gift_table.Contador_Vista)
         VALUES (
            @IDUSER, 
            N'@NTREEV', 
            N'NICE FINISH TUTORIAL ROOKIE', 
            isnull(getdate(), getdate()), 
            0, 
            1, 
            0, 
            0)

      SELECT @MSGID = max(pangya_gift_table.Msg_ID)
      FROM pangya.pangya_gift_table

      DECLARE
         @temp int

      SET @temp = -1

      EXECUTE pangya.ProcInsertItemNoEmail 
         0, 
         @IDUSER, 
         @MSGID, 
         @temp, 
         0x1C000000, 
         0, 
         1, 
         0

      DECLARE
         @temp$2 int

      SET @temp$2 = -1

      EXECUTE pangya.ProcInsertItemNoEmail 
         0, 
         @IDUSER, 
         @MSGID, 
         @temp$2, 
         0x10000012, 
         0, 
         1, 
         0

      UPDATE pangya.account
         SET 
            Event1 = 1
      WHERE account.UID = @IDUSER

   END
