	/*
	* Total distancia 4 - o PangYa faz a divisão por 10k sozinho
	*/ 
	INSERT INTO @tabRank([index], [UID], valor)
	SELECT
		ROW_NUMBER() OVER (ORDER BY a.total_distancia DESC, a.[UID]) AS [index],
		a.[uid],
