	FROM 
		pangya.user_info a
		INNER JOIN
		pangya.account b
		ON a.[UID] = b.[UID]
	WHERE 
		(b.first_login + b.first_set) = 2
	ORDER BY a.total_distancia DESC, a.[uid]

	-- Insert Total Distância 4
    INSERT @tabRankTmp(position, [UID], tipo_rank, tipo_rank_seq, valor)
	SELECT [index], [UID], 2, 4, [valor] FROM @tabRank

	-- Clear @tabRank
	DELETE FROM @tabRank
   
	/*
	*       -------------- Normal --------------
	*       Nome            CODE            ESTRELA
	*       BL              0               *
	*       BW              1               ***
	*       SW              2               ***
	*       WH              3               *****
	*       WW              4               ****
	*       West            5               *
	*       BM              6               ***
	*       SC              7               ****
	*       IC              8               **
	*       WhW             9               ***
	*       SS              10              **
	*       PW              11              *
	*       DI              13              *****
	*       IS              14              *
	*       LS              15              *
	*       EV              16              **
	*       IF              18              ****
	*       WC              19              **
	*       AM              20              **
	*       MR              21              ***
	*       -----------------*------------------
	**/
	/*
	*   RECORD 1
	*   BL 0
	*/
	INSERT INTO @tabRank([index], [UID], valor)
	SELECT
			ROW_NUMBER() OVER (ORDER BY Z.best_score, Z.best_pang DESC, Z.[UID]) AS [index],
			Z.[UID],
			Z.best_score
	FROM
	(
			SELECT
					f.[uid],
					MIN(f.best_score) as best_score,
					MAX(f.best_pang) as best_pang
			FROM
					pangya.pangya_record f
					INNER JOIN
					pangya.account g
					ON f.[UID] = g.[UID]
			WHERE
					(g.FIRST_LOGIN + g.FIRST_SET) = 2
					AND f.best_score != 127 /*AND f.assist = 0*/
					AND f.course = 0 AND f.tipo = 0
			GROUP BY f.[UID]
	) Z
	ORDER BY
			Z.best_score,
			Z.best_pang DESC,
			Z.[uid]


	-- Insert Best Score Course (BL) 0
	INSERT @tabRankTmp(position, [UID], tipo_rank, tipo_rank_seq, valor)
