			GROUP BY f.[UID]
	) Z
	ORDER BY
			Z.best_score,
			Z.best_pang DESC,
			Z.[uid]


	-- Insert Best Score Course (BW) 1
	INSERT @tabRankTmp(position, [UID], tipo_rank, tipo_rank_seq, valor)
