	INSERT INTO @tabRank([index], [UID], valor)
	SELECT
			ROW_NUMBER() OVER (ORDER BY Z.best_score, Z.best_pang DESC, Z.[UID]) AS [index],
			Z.[UID],
			Z.best_score
	FROM
	(
			SELECT
