CREATE PROCEDURE [pangya].[ProcAddBall]
	-- Add the parameters for the stored procedure here
	@IDUSER INT,
	@GIFTFLAG INT,
	@PURCHASE_IN TINYINT,
	@IDITEM int,
	@ITEMTYPEID INT,
	@TYPEFLAG TINYINT,
	@TEMPO INT,
	@C_0 smallint,
	@C_1 smallint,
	@C_2 smallint,
	@C_3 smallint,
	@C_4 smallint
AS
BEGIN
