-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcAddCaddie] 
	-- Add the parameters for the stored procedure here
	@IDUSER INT,
	@IDITEM INT,
	@_TYPEID INT,
	@GIFT_FLAG INT,
	@PURCHASE INT,
	@RENT_FLAG INT,
	@TEMPO INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    IF @IDITEM <= 0
	BEGIN
		INSERT INTO pangya.pangya_caddie_information([UID], typeid, gift_flag, Purchase, RentFlag, [Period], RegDate, EndDate)
			VALUES(@IDUSER, @_TYPEID, @GIFT_FLAG, @PURCHASE, @RENT_FLAG, @TEMPO, getdate(), DATEADD(DAY, @TEMPO, getdate()))

		SELECT item_id, EndDate FROM pangya.pangya_caddie_information WHERE item_id = @@IDENTITY
	END
END
