	@PART18 INT,
	@PART19 INT,
	@PART20 INT,
	@PART21 INT,
	@PART22 INT,
	@PART23 INT,
	@PART24 INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	IF @IDITEM <= 0
	BEGIN
		SET @IDITEM = ISNULL((SELECT item_id FROM pangya.pangya_character_information WHERE [UID] = @IDUSER AND typeid = @_TYPEID), -1)
	END

	IF @IDITEM <= 0
	BEGIN
		INSERT INTO pangya.pangya_character_information([UID], TYPEID, default_hair, default_shirts, Purchase, gift_flag, 
			parts_1, parts_2, parts_3, parts_4, parts_5, parts_6, parts_7, parts_8, parts_9, parts_10, parts_11, parts_12,
			parts_13, parts_14, parts_15, parts_16, parts_17, parts_18, parts_19, parts_20, parts_21, parts_22, parts_23, parts_24) 
		VALUES(@IDUSER, @_TYPEID, @DEFAULT_HAIR, @DEFAULT_SHIRTS, @PURCHAGE, @GIFT_FLAG, @PART1, @PART2, @PART3, @PART4, @PART5, @PART6, @PART7, @PART8,
				@PART9, @PART10, @PART11, @PART12, @PART13, @PART14, @PART15, @PART16, @PART17, @PART18, @PART19, @PART20, @PART21, @PART22, @PART23, @PART24)

		-- Character ID
		SET @IDITEM = @@identity

		DECLARE @COUNT INT = 0
		WHILE @COUNT < 24
		BEGIN
			INSERT INTO pangya.td_char_equip_s4([UID], CHAR_ITEMID, IN_DATE, EQUIP_NUM, USE_YN)
				VALUES(@IDUSER, @IDITEM, getdate(), @COUNT + 1, N'Y')
			SET @COUNT += 1
		END
	END

	SELECT @IDITEM AS ITEM_ID;
END
GO
