CREATE PROCEDURE [pangya].[ProcAddMemorialCoin]
   @tipo INT,
    @_typeid INT,
    @probabilidade INT
AS
BEGIN
    IF EXISTS (
        SELECT 1
        FROM pangya.pangya_new_memorial_coin_item
        WHERE tipo = @tipo AND _typeid = @_typeid
    )
    BEGIN
        UPDATE pangya.pangya_new_memorial_coin_item
        SET probabilidade = @probabilidade
        WHERE tipo = @tipo AND _typeid = @_typeid;
    END
    ELSE
    BEGIN
        INSERT INTO pangya.pangya_new_memorial_coin_item (tipo, _typeid, probabilidade)
        VALUES (@tipo, @_typeid, @probabilidade);
    END
END;
