SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcAddUserFriend]  
   @IDUSER int,
   @friend_uid int,
   @nickname nvarchar(23)
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @OPT int = 0

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported :  user não existe
      *
      */

      IF 
         (
            SELECT account.UID
            FROM pangya.account
            WHERE account.UID = @friend_uid AND account.NICK = @nickname
         ) IS NOT NULL
         /*
         *   SSMA informational messages:
         *   M2SS0134: Conversion of following Comment(s) is not supported :  user list full
         *
         */

         IF 
            (
               SELECT count_big(pangya_friend_list.uid_friend)
               FROM pangya.pangya_friend_list
               WHERE pangya_friend_list.uid = @friend_uid
            ) < 50
            /*
            *   SSMA informational messages:
            *   M2SS0134: Conversion of following Comment(s) is not supported :  Wait
            *
            *   M2SS0134: Conversion of following Comment(s) is not supported :  user já é amigo
            *
            *   M2SS0134: Conversion of following Comment(s) is not supported :  Quem Add
            *    Request
            *
            *   M2SS0134: Conversion of following Comment(s) is not supported :  Quem Foi Add
            *
            */

            IF 
               (
                  SELECT pangya_friend_list.uid
                  FROM pangya.pangya_friend_list
                  WHERE pangya_friend_list.uid = @IDUSER AND pangya_friend_list.uid_friend = @friend_uid
               ) IS NULL
               BEGIN

                  INSERT pangya.pangya_friend_list(pangya.pangya_friend_list.uid, pangya.pangya_friend_list.uid_friend, pangya.pangya_friend_list.state_flag)
                     VALUES (@IDUSER, @friend_uid, 8)

                  INSERT pangya.pangya_friend_list(pangya.pangya_friend_list.uid, pangya.pangya_friend_list.uid_friend, pangya.pangya_friend_list.state_flag)
                     VALUES (@friend_uid, @IDUSER, 0)

               END
            ELSE 
               SET @OPT = 2
         ELSE 
            SET @OPT = 3
      ELSE 
         SET @OPT = 1

      SELECT @OPT AS retorno

   END
GO
