-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcBlockPlayerLuciaAttendance]
	-- Add the parameters for the stored procedure here
	@UID INT,
	@BLOCK_TYPE INT
AS
BEGIN
	
	IF @UID > 0 AND @BLOCK_TYPE > 0
	BEGIN
		
		DECLARE @END_DATE DATETIME2(7) = (CASE @BLOCK_TYPE
												WHEN 1 THEN
													DATEADD(DAY, 1, getdate())
												WHEN 2 THEN
													DATEADD(WEEK, 1, getdate())
												WHEN 3 THEN
													DATEADD(MONTH, 1, getdate())
												ELSE NULL
											END)

		UPDATE pangya.pangya_lucia_attendance 
			SET block_type = @BLOCK_TYPE, 
				block_end_date = @END_DATE,
				try_hacking_count = 0
		WHERE [UID] = @UID
	END
END
GO
