/****** Objeto:  StoredProcedure [pangya].[ProcChangeNickname]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcChangeNickname]
	-- Add the parameters for the stored procedure here
	@UID INT
AS
BEGIN
	
	DECLARE @RET INT = -1
	DECLARE @CP BIGINT = 0

	IF @UID > 0
	BEGIN

		IF (SELECT FIRST_LOGIN FROM pangya.account WHERE [UID] = @UID) = 1
		BEGIN

			IF (SELECT IIF(change_nick IS NULL, 1, DATEDIFF(MONTH, change_nick, getdate())) as diff FROM pangya.account WHERE [UID] = @UID) > 0
			BEGIN
		
				IF (SELECT cookie FROM pangya.user_info WHERE [uid] = @UID) >= 20
				BEGIN

					-- Update cookie, tira os 20 CP que gastar para trocar o nickname
					UPDATE pangya.user_info SET Cookie = Cookie - 20 WHERE [UID] = @UID;

					-- Atualiza CP que vai ser retornado
					SET @CP = (SELECT cookie FROM pangya.user_info WHERE [uid] = @UID);

					-- Insere o nickname antigo no log de change nickname
					INSERT INTO pangya.pangya_change_nickname_log([UID], nickname) SELECT TOP(1) [UID], NICK FROM pangya.account WHERE [UID] = @UID

					-- Atualiza a flag de first login e a data que o player pediu para trocar de nickname
					UPDATE pangya.account 
						SET FIRST_LOGIN = 0,			-- Ele pode trocar o nick quando ele logar no jogo
							change_nick = getdate()		-- Atualiza a data que ele atualizou o nickname
					WHERE [UID] = @UID;

					SET @RET = 1;	-- Fez o pedido de troca de nickname com sucesso

				END
				ELSE
					SET @RET = -2;	-- Não tem cookies suficiente

			END
			ELSE
				SET @RET = -3;	-- Ainda não deu um mês desde que ele trocou o nickname

		END
		ELSE
			SET @RET = -4;	-- Já pediu para trocar o nickname

	END

	SELECT @RET as RET, @CP as cookie
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcChangePassword]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcChangePassword]
	-- Add the parameters for the stored procedure here
	@UID INT,
	@PWD VARCHAR(33)
AS
BEGIN
	
	DECLARE @RET INT = -1
	DECLARE @EMAIL NVARCHAR(100) = N''

	IF @UID > 0 AND @PWD != ''
	BEGIN

		-- Pega email do player
		SET @EMAIL = (SELECT email FROM pangya.contas_beta WHERE [UID] = @UID)

		-- Verifica se tem log de troca de senha
		IF (SELECT [UID] FROM pangya.pangya_change_pwd_log WHERE [UID] = @UID) IS NOT NULL
		BEGIN

			DECLARE @COUNT INT = 0
			DECLARE @CHANGE_DATE DATETIME2

			-- Pega o contador de vez que o player trocou o login e a primeira data que ele trocou
			SELECT @COUNT = [count], @CHANGE_DATE = change_date
			FROM pangya.pangya_change_pwd_log
			WHERE [UID] = @UID
			
			IF DATEDIFF(MINUTE, @CHANGE_DATE, getdate()) >= 1440 -- 24 horas em minutos
			BEGIN
			
				-- Faz mais de 24 horas que ele trocou de senha	
				UPDATE pangya.pangya_change_pwd_log 
					SET last_change = getdate(),
						change_date = getdate(),
						[count] = 1
				WHERE [UID] = @UID

				-- Troca a senha
				UPDATE pangya.account SET [PASSWORD] = @PWD WHERE [UID] = @UID

				SET @RET = 1

			END
			ELSE IF @COUNT = 1
			BEGIN
				
				-- Menos de 24 horas que ele trocou de senha uma vez
				UPDATE pangya.pangya_change_pwd_log
					SET last_change = getdate(),
						[count] = @COUNT + 1
				WHERE [UID] = @UID

				-- Troca a senha
				UPDATE pangya.account SET [PASSWORD] = @PWD WHERE [UID] = @UID

				SET @RET = 1

			END
			ELSE
				SET @RET = -2

		END
		ELSE
		BEGIN
			
			-- Ele não tem log de troca de senha, cria um novo para ele
			INSERT INTO pangya.pangya_change_pwd_log([UID]) VALUES(@UID)

			-- Troca a senha
			UPDATE pangya.account SET [PASSWORD] = @PWD WHERE [UID] = @UID

			SET @RET = 1

		END
		
	END

	SELECT @RET AS RET, @EMAIL AS EMAIL
END
GO
