/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcCheckDailyQuest]
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      IF 
         (
            SELECT count_big(*)
            FROM pangya.pangya_daily_quest
         ) > 0
         SELECT ISNULL(datediff(day, pangya_daily_quest.Reg_Date, getdate()), 1) AS DATE
         FROM pangya.pangya_daily_quest
      ELSE 
         SELECT 1 AS DATE

   END
GO
