CREATE PROCEDURE [pangya].[ProcCheckGuildName]
    @NAME NVARCHAR(20)
AS
BEGIN
    SET NOCOUNT ON;

    -- Verifica se o nome já existe na tabela pangya_guild
    IF EXISTS (
        SELECT 1 
        FROM pangya.pangya_guild 
        WHERE GUILD_NAME COLLATE Latin1_General_CI_AS = @NAME COLLATE Latin1_General_CI_AS
    )
        SELECT 0 AS Available; -- Nome já em uso
    ELSE
        SELECT 1 AS Available; -- Nome disponível
END

GO
/****** Objeto:  StoredProcedure [pangya].[ProcCheckItemLimit]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	Verifica e ajusta o limite de itens no armazém de itens para um valor mínimo de 2000
-- =============================================
CREATE PROCEDURE [pangya].[ProcCheckItemLimit]
	@IDUSER INT
AS
BEGIN
DECLARE @Sucess int;

set @Sucess = 0;
	-- Verifica se existem itens com C0 maior que 20000 para o usuário
	IF EXISTS (SELECT [item_id] FROM [pangya].[pangya].[pangya_item_warehouse] WHERE UID = @IDUSER AND C0 > 20000)
	BEGIN
		-- Atualiza os valores de C0 para 2000 onde são maiores que 20000
		UPDATE [pangya].[pangya].[pangya_item_warehouse]
		SET C0 = C0 / 18000
		WHERE UID = @IDUSER AND C0 > 20000;
set @Sucess = 1;
	END  
	select @Sucess as Sucess
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcCheckPlayerDailyQuest]    Data do Script: 03/05/2026 15:40:48 ******/
