SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcCheckPlayerDailyQuest]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @RET int = 0

      IF 
         (
            SELECT pangya_daily_quest_player.today_quest
            FROM pangya.pangya_daily_quest_player
            WHERE pangya_daily_quest_player.uid = @IDUSER
         ) IS NULL
         SET @RET = 1
      ELSE 
         BEGIN
            IF 
               (
                  SELECT day(pangya_daily_quest_player.today_quest)
                  FROM pangya.pangya_daily_quest_player
                  WHERE pangya_daily_quest_player.uid = @IDUSER
               ) <> 
               (
                  SELECT day(pangya_daily_quest.Reg_Date)
                  FROM pangya.pangya_daily_quest
               )
               SET @RET = 1
         END

      SELECT @RET

   END
GO
