/****** Objeto:  StoredProcedure [pangya].[ProcColocaMsgNoGiftTable]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcColocaMsgNoGiftTable]  
   @From_UID int,
   @To_UID int,
   @MSG nvarchar(500)
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /* 
      *   SSMA error messages:
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion

      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported : Coloca MSG no Gift_Table
      **/

	  DECLARE @NICKNAME NVARCHAR(100)

      SELECT @NICKNAME = NICK FROM pangya.account WHERE [UID] = @From_UID
       
	  IF @NICKNAME IS NULL OR @NICKNAME = N''
         SET @NICKNAME = N''

      /* 
      *   SSMA error messages:
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion

      *   SSMA informational messages:
      *   M2SS0214: The Default Values for the Columns have been added in the Insert Statement based on Project setttings.
      *   M2SS0231: Zero-date, zero-in-date and invalid dates to not null columns has been replaced with GetDate()/Constant date
	  */

      INSERT pangya.pangya_gift_table(
         pangya.pangya_gift_table.UID, 
         pangya.pangya_gift_table.fromid, 
         pangya.pangya_gift_table.message, 
         pangya.pangya_gift_table.giftdate, 
         pangya.pangya_gift_table.Lida_YN, 
         pangya.pangya_gift_table.valid, 
         pangya.pangya_gift_table.Flag, 
         pangya.pangya_gift_table.Contador_Vista)
         VALUES (
            @To_UID, 
            @NICKNAME, 
            @MSG, 
            isnull(getdate(), getdate()), 
            0, 
            1, 
            0, 
            0)

      SELECT @@IDENTITY AS MSG_ID

   END
GO
