/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcDeletaQuestAnterior]
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported : Deleta todos os achievement do dia anterior
      *
      */

      DELETE 
      FROM pangya.achievement_quest
      WHERE achievement_quest.ID_ACHIEVEMENT IN 
         (
            SELECT achievement_tipo.ID_ACHIEVEMENT
            FROM pangya.achievement_tipo
            WHERE achievement_tipo.[Option] = 1
         )

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported : DECLARE ID_ACHIEVE INT;
      *   	DECLARE FINISHED INT DEFAULT 0;
      *   
      *   	DECLARE ACHIEVE_CURSOR CURSOR FOR
      *   		SELECT ID_ACHIEVEMENT FROM achievement_tipo WHERE `option` = 1;
      *   
      *   	DECLARE CONTINUE HANDLER
      *   		FOR NOT FOUND SET FINISHED = 1;
      *   	
      *       DELETE FROM achievement_tipo WHERE `option` = 1;
      *   
      *   	OPEN ACHIEVE_CURSOR;
      *   
      *   	DEL_QUEST: LOOP
      *   		FETCH ACHIEVE_CURSOR INTO ID_ACHIEVE;
      *   		
      *   		IF FINISHED = 1 THEN
      *   			LEAVE DEL_QUEST;
      *   		END IF;
      *   
      *   		DELETE FROM achievement_quest
      *   		WHERE ID_ACHIEVEMENT = ID_ACHIEVE AND Count_ID = 0;
      *   	
      *   	END LOOP DEL_QUEST;
      *   
      *   	CLOSE ACHIEVE_CURSOR;
      *
      */

      DELETE 
      FROM pangya.achievement_tipo
      WHERE achievement_tipo.[Option] = 1

   END
GO
