-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcDeleteGuildNotice]
	-- Add the parameters for the stored procedure here
	@OWNER_UID INT,
	@NOTICE_SEQ BIGINT
AS
BEGIN
	
	IF @NOTICE_SEQ > 0
		UPDATE notice
				SET notice.[STATE] = 2
		FROM
			pangya.pangya_guild_notice notice
			INNER JOIN
			pangya.pangya_guild b
			ON notice.GUILD_UID = b.GUILD_UID
		WHERE notice.SEQ = @NOTICE_SEQ
			AND (@OWNER_UID = notice.OWNER_UID OR b.GUILD_LEADER = @OWNER_UID)
END
GO
