-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcEquipCard]
	-- Add the parameters for the stored procedure here
	@IDUSER INT,
	@CARD_TYPEID INT,
	@PART_ID INT,
	@PART_TYPEID INT,
	@EFEITO INT,
	@EFEITO_QNTD INT,
	@SLOT INT,
	@TIPO INT,
	@TEMPO INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	DECLARE @INDEX BIGINT = -1

    -- Insert statements for procedure here
	IF @IDUSER > 0 AND @CARD_TYPEID > 0
	BEGIN
		DECLARE @REG_DT datetime2 = NULL
		DECLARE @END_DT datetime2 = NULL

		IF @TEMPO > 0
		BEGIN
			SET @REG_DT = getdate()
			SET @END_DT = DATEADD(MINUTE, @TEMPO, @REG_DT)
		END

		INSERT INTO pangya.pangya_card_equip(UID, parts_id, parts_typeid, card_typeid, Efeito, Efeito_Qntd, Slot, USE_DT, END_DT, Tipo, USE_YN)
			VALUES(@IDUSER, @PART_ID, @PART_TYPEID, @CARD_TYPEID, @EFEITO, @EFEITO_QNTD, @SLOT, @REG_DT, @END_DT, @TIPO, 1)

		SET @INDEX = @@IDENTITY
	END

	SELECT @INDEX AS [INDEX]
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcExchangeCookiePointByEpin]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcExchangeCookiePointByEpin]
	@EPIN_ID BIGINT,
	@UID INT,
	@VALUE BIGINT
AS
BEGIN
	
	IF @EPIN_ID > 0 AND @UID > 0 AND @VALUE > 0
	BEGIN

		-- Update Epin to valid = 0, já trocou o epin e o uid de quem trocou o epin por CP
		UPDATE pangya.pangya_donation_epin
			SET
				[retrive_uid] = @UID,
				[valid] = 0
		WHERE
			[index] = @EPIN_ID

		-- Adiciona os CPs para o player
		UPDATE pangya.user_info
			SET
				[Cookie] = [Cookie] + @VALUE
		WHERE
			[UID] = @UID

		-- CP Log
		INSERT INTO pangya.pangya_cookie_point_log([UID], [TYPE], [mail_id], [cookie], [item_qnty])
		VALUES(@UID, 4/*ADD CP FROM EPIN DONATION*/, -1, @VALUE, 0)

		SELECT @EPIN_ID AS ID

	END
	ELSE
		SELECT -1 AS ID
END
GO
