*/

CREATE PROCEDURE [pangya].[ProcExtendeDiasCaddie]  
   @IDUSER int,
   @Caddie_ID int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      UPDATE pangya.pangya_caddie_information
         SET 
            EndDate = dateadd(day, 30, getdate())
      WHERE pangya_caddie_information.UID = @IDUSER AND pangya_caddie_information.item_id = @Caddie_ID

      SELECT pangya_caddie_information.typeid
      FROM pangya.pangya_caddie_information
      WHERE pangya_caddie_information.UID = @IDUSER AND pangya_caddie_information.item_id = @caddie_id

   END
GO
