      */*/

      SELECT @Auth_Key = upper(convert(varchar(32), hashbytes('md5', convert(varchar(32), rand(), 2)), 2));



      SELECT @COUNTER = count_big(*)
      FROM pangya.authkey_game
      WHERE [UID] = @IDUSER AND ServerID = @SERVERID

      IF @COUNTER > 0
         BEGIN
            UPDATE pangya.authkey_game
               SET 
                  AuthKey = @Auth_Key, 
                  valid = 1
            WHERE [UID] = @IDUSER AND ServerID = @SERVERID
         END
      ELSE 
         BEGIN
            INSERT pangya.authkey_game([UID], AuthKey, ServerID, valid)
               VALUES (@IDUSER, @Auth_Key, @SERVERID, 1)
         END

      SELECT AuthKey
      FROM pangya.authkey_game
      WHERE [UID] = @IDUSER AND ServerID = @SERVERID

   END
