CREATE PROCEDURE [pangya].[ProcGeraWeblinkKey]
	-- Add the parameters for the stored procedure here
	@IDUSER int
AS
BEGIN
	DECLARE @WEBLINK_KEY VARCHAR(6);
    
	--upper(convert(varchar(32), hashbytes('md5', convert(varchar(32), rand(), 2)), 2))

    SELECT @WEBLINK_KEY = upper(convert(varchar(32), hashbytes('md5', convert(varchar(32), rand(), 2)), 2));
    
    IF (SELECT uid FROM pangya.pangya_weblink_key WHERE UID = @IDUSER) IS NOT NULL
