/****** Objeto:  StoredProcedure [pangya].[ProcGetAchievement]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetAchievement]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported : Retorno o Achievement do Usuario	
      *
      */

      SELECT 
         Z.TIPO AS ACHIEVEMENT_TIPO, 
         Z.TypeID AS ACHIEVEMENT_TYPEID, 
         Z.ID_ACHIEVEMENT AS ACHIEVEMENT_ID, 
         Z.[Option] AS ACHIEVEMENT_OPTION, 
         A.TypeID_ACHIEVE AS ACHIEVEMENT_QUEST_TYPEID, 
         A.COUNT_TYPEID AS ACHIEVEMENT_COUNTER_TYPEID, 
         A.Count_ID AS ACHIEVEMENT_COUNTER_ID, 
         A.Data_Sec AS ACHIEVEMENT_COUNTER_DATA_SEC
      FROM 
         (
            /*
            *   SSMA informational messages:
            *   M2SS0282: Binary value is converted to numeric value
            */

            SELECT TOP (9223372036854775807) achievement_tipo.TypeID, achievement_tipo.ID_ACHIEVEMENT, achievement_tipo.TIPO, achievement_tipo.[Option]
            FROM pangya.achievement_tipo
            WHERE achievement_tipo.UID = @IDUSER AND achievement_tipo.TypeID < 2030043136
               ORDER BY achievement_tipo.ID_ACHIEVEMENT
         )  AS Z 
            LEFT OUTER JOIN 
            (
               SELECT 
                  X.IDX, 
                  X.ID_ACHIEVEMENT, 
                  X.TypeID_ACHIEVE, 
                  X.Data_Sec, 
                  Y.Count_ID, 
                  Y.TypeID AS COUNT_TYPEID
               FROM 
                  (
                     SELECT 
                        achievement_quest.IDX, 
                        achievement_quest.ID_ACHIEVEMENT, 
                        achievement_quest.TypeID_ACHIEVE, 
                        achievement_quest.Data_Sec, 
                        achievement_quest.Count_ID
                     FROM pangya.achievement_quest
                     WHERE achievement_quest.UID = @IDUSER
                  )  AS X 
                     INNER JOIN 
                     (
                        SELECT count_item.TypeID, count_item.Count_ID
                        FROM pangya.count_item
                        WHERE count_item.UID = @IDUSER
                     )  AS Y 
                     ON X.Count_ID = Y.Count_ID
            )  AS A 
            ON Z.ID_ACHIEVEMENT = A.ID_ACHIEVEMENT
         ORDER BY A.IDX

   END
GO
