/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetAchieveQuest]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported : Get achievement_quest
      *
      */

      SELECT B.TypeID_ACHIEVE, ISNULL(C.TypeID, 0) AS TypeID, ISNULL(C.Count_ID, 0) AS Count_ID, ISNULL(C.Data_Sec, 0) AS Data_Sec
      FROM 
         (
            SELECT 
               a.TypeID, 
               D.IDX, 
               D.UID, 
               D.ID_ACHIEVEMENT, 
               D.TypeID_ACHIEVE, 
               D.Count_ID, 
               D.Data_Sec, 
               D.Objetivo_Quest
            FROM pangya.achievement_tipo  AS a, pangya.achievement_quest  AS D
            WHERE D.UID = @IDUSER AND a.ID_ACHIEVEMENT = D.ID_ACHIEVEMENT
         )  AS B 
            LEFT OUTER JOIN 
            (
               SELECT 
                  count_item.UID, 
                  count_item.Nome, 
                  count_item.ID_ACHIEVEMENT, 
                  count_item.TypeID, 
                  count_item.Count_ID, 
                  count_item.Count_Num_Item, 
                  count_item.Data_Sec, 
                  count_item.TIPO
               FROM pangya.count_item
               WHERE count_item.UID = @IDUSER
            )  AS C 
            ON C.Count_ID = B.Count_ID
      WHERE B.UID = @IDUSER
         ORDER BY B.IDX

   END
GO
