CREATE PROCEDURE [pangya].[ProcGetAchieveType]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported : Get achievement_tipo
      *
      */

      /*
      *   SSMA warning messages:
      *   M2SS0104: Non aggregated column TIPO is aggregated with Min(..) in Select, Orderby and Having clauses.
      *   M2SS0104: Non aggregated column TYPEID is aggregated with Min(..) in Select, Orderby and Having clauses.
      *   M2SS0104: Non aggregated column ID_ACHIEVEMENT is aggregated with Min(..) in Select, Orderby and Having clauses.
      *   M2SS0104: Non aggregated column OPTION is aggregated with Min(..) in Select, Orderby and Having clauses.
      */

      SELECT 
         min(A.TIPO) AS TIPO, 
         min(A.TypeID) AS TypeID, 
         min(A.ID_ACHIEVEMENT) AS ID_ACHIEVEMENT, 
         min(A.[Option]) AS [Option], 
         count_big(b.ID_ACHIEVEMENT) AS COUNTER
      FROM pangya.achievement_tipo  AS A, pangya.achievement_quest  AS b
      WHERE 
         A.ID_ACHIEVEMENT = b.ID_ACHIEVEMENT AND 
         A.UID = @IDUSER AND 
         A.TIPO <> 2
      GROUP BY b.ID_ACHIEVEMENT
         ORDER BY b.ID_ACHIEVEMENT

   END
