-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetAllDonationAndEpinByPlayer]
	@UID INT
AS
BEGIN
	
	IF @UID > 0
	BEGIN
		
		SELECT
			a.code,
			a.plataforma,
			a.[date],
			a.gross_amount,
			a.[status],
			b.epin,
			b.qntd as cp_qntd,
			b.valid as epin_valid
		FROM
			pangya.pangya_donation_new a
			LEFT OUTER JOIN
			pangya.pangya_donation_epin b
			ON a.[index] = b.[donation_id] AND a.[epin_id] = b.[index]
		WHERE
			a.[UID] = @UID
	END
	ELSE
		SELECT -1 AS CODE
END
GO
