CREATE PROCEDURE [pangya].[ProcGetAllDonationsAndEpin]
AS
BEGIN
	
	SELECT
		a.code,
		a.[date],
		a.email,
		a.escrow,
		a.gross_amount,
		a.net_amount,
		a.plataforma,
		a.epin_id,
		a.reference,
		a.reg_date,
		a.[status],
		a.[type],
		a.[update],
		a.[uid],
		a.[index],
		b.epin,
		b.qntd as cp_qntd,
		b.retrive_uid as epin_get_uid,
		b.valid as epin_valid
	FROM
		pangya.pangya_donation_new a
		LEFT OUTER JOIN
		pangya.pangya_donation_epin b
		ON a.[index] = b.[donation_id] AND a.[epin_id] = b.[index]
END
