/****** Objeto:  StoredProcedure [pangya].[ProcGetAllEmailFromMailBox]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetAllEmailFromMailBox]
	@IDUSER INT
AS
BEGIN
	
	IF @IDUSER > 0
	BEGIN
		
        SELECT 
            A.Msg_ID, 
            A.fromid,  
			A.giftdate, 
            A.[message], 
            A.Contador_Vista, 
            A.Lida_YN, 
            ISNULL(B.item_id, 0) AS ITEM_ID,
            ISNULL(B.item_typeid, 0) AS ITEM_TYPEID, 
            ISNULL(B.Flag, 0) AS FLAG, 
			ISNULL(B.Quantidade_item, 0) AS QUANTIDADE_ITEM, 
			ISNULL(B.Quantidade_Dia, 0) AS QUANTIDADE_DIA, 
            ISNULL(B.Pang, 0) AS PANG, 
			ISNULL(B.Cookie, 0) AS COOKIE, 
			ISNULL(B.GM_ID, 0) AS GM_ID, 
			ISNULL(B.Flag_Gift, 0) AS FLAG_GIFT,  
			ISNULL((SELECT UCCIDX FROM pangya.tu_ucc WHERE item_id = B.item_id), N'0') AS UCC_IMG_MARK, 
            ISNULL(B.[Type], 0) AS [TYPE]
        FROM 
        (
            SELECT 
				[UID], 
				Msg_ID, 
				fromid, 
				[message], 
				giftdate, 
				Flag, 
				Contador_Vista, 
				Lida_YN
            FROM pangya.pangya_gift_table
            WHERE valid = 1
        )  AS A 
        LEFT OUTER JOIN 
        (
            SELECT 
				Msg_ID AS ID_MSG, 
				item_id, 
				item_typeid, 
				Flag, 
				Quantidade_item, 
				Quantidade_Dia, 
				Pang, 
				Cookie, 
				GM_ID, 
				Flag_Gift, 
				UCC_IMG_MARK, 
				[Type]
            FROM pangya.pangya_item_mail
            WHERE valid = 1
        )  AS B 
        ON A.Msg_ID = B.ID_MSG
		WHERE [UID] = @IDUSER

	END
END
GO
