/****** Objeto:  StoredProcedure [pangya].[ProcGetAuthKeyLogin]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetAuthKeyLogin]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported : Obtêm as Auth Keys do Usuario
      *
      */

      SELECT AuthKey, valid
      FROM pangya.authkey_login
      WHERE [UID] = @IDUSER

	  DECLARE @mac VARCHAR(256);
	  DECLARE @isBan int;

	  SET @mac = (SELECT MacAddress FROM pangya.account WHERE [UID] = @IDUSER);
	  SET @isBan = (SELECT COUNT(1) FROM pangya.pangya_mac_table WHERE mac = @mac);

	  if @isBan > 0
		begin
			  UPDATE pangya.account set IDState = 1 WHERE UID = @IDUSER
			  UPDATE pangya.authkey_login SET valid = 0 WHERE [UID] = @IDUSER
		end 
		else 
		begin
			UPDATE pangya.authkey_login SET valid = 0 WHERE [UID] = @IDUSER
		END
   END
GO
