/****** Objeto:  StoredProcedure [pangya].[ProcGetCardEquip]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetCardEquip]  
   @IDUSER int,
   @OPT int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      IF @OPT = 0
	  BEGIN

         SELECT 
			pangya_card_equip.[index],
            pangya_card_equip.card_typeid, 
            pangya_card_equip.[UID], 
            pangya_card_equip.parts_typeid, 
            pangya_card_equip.parts_id, 
            pangya_card_equip.Efeito, 
            pangya_card_equip.Efeito_Qntd, 
            pangya_card_equip.Slot, 
             COALESCE(CONVERT(VARCHAR, USE_DT, 121), N'') AS USE_DT, 
             COALESCE(CONVERT(VARCHAR, END_DT, 121), N'') AS END_DT, 
			 NULL AS TEMPO,
            pangya_card_equip.Tipo, 
            pangya_card_equip.USE_YN
         FROM pangya.pangya_card_equip
         WHERE 
            pangya_card_equip.UID = @IDUSER AND 
            pangya_card_equip.USE_YN = 1 AND 
            dbo.GroupID(pangya_card_equip.card_typeid) BETWEEN 124 AND 125 AND (USE_DT IS NULL OR datediff(minute, getdate(), pangya_card_equip.END_DT) > 0)
            ORDER BY pangya_card_equip.card_typeid         

		END
      ELSE 
         BEGIN
            IF @OPT = 1

               SELECT 
			      -1 as [index],
                  pangya_card_equip.card_typeid, 
                  pangya_card_equip.UID, 
                  pangya_card_equip.parts_typeid, 
                  pangya_card_equip.parts_id, 
                  pangya_card_equip.Efeito, 
                  pangya_card_equip.Efeito_Qntd, 
                  pangya_card_equip.Slot, 
                   COALESCE(CONVERT(VARCHAR, USE_DT, 121), N'') AS USE_DT, 
				   COALESCE(CONVERT(VARCHAR, END_DT, 121), N'') AS END_DT,
                   datediff(second, getdate(), pangya_card_equip.END_DT) AS TEMPO, 
                  pangya_card_equip.Tipo, 
                  pangya_card_equip.USE_YN
               FROM pangya.pangya_card_equip
               WHERE 
                  pangya_card_equip.UID = @IDUSER AND 
                  pangya_card_equip.USE_YN = 1 AND 
                  dbo.GroupID(pangya_card_equip.card_typeid) = 26 AND (USE_DT IS NULL OR datediff(minute, getdate(), pangya_card_equip.END_DT) > 0)
                  ORDER BY pangya_card_equip.card_typeid               
         END

   END
GO
