      *   M2SS0052: string literal was converted to NUMERIC literal
      */*/

      SELECT 
         pangya_card.card_itemid, 
         pangya_card.UID, 
         pangya_card.card_typeid, 
         pangya_card.Slot, 
         pangya_card.Efeito, 
         pangya_card.Efeito_Qntd, 
         pangya_card.QNTD, 
          (CASE 
            WHEN CAST(REPLACE((REPLACE((REPLACE((CONVERT(varchar(20), pangya_card.USE_DT, 120)), '-', '')), ' ', '')), ':', '') AS bigint) <> 0 THEN pangya_card.USE_DT
            ELSE NULL
         END) AS USE_DT, 
          (CASE 
            WHEN CAST(REPLACE((REPLACE((REPLACE((CONVERT(varchar(20), pangya_card.END_DT, 120)), '-', '')), ' ', '')), ':', '') AS bigint) <> 0 THEN pangya_card.END_DT
            ELSE NULL
         END) AS END_DT, 
         pangya_card.card_type, 
          (CASE 
            WHEN pangya_card.USE_YN = N'N' THEN 0
            ELSE 1
         END) AS USE_YN
      FROM pangya.pangya_card
      WHERE pangya_card.UID = @IDUSER AND pangya_card.QNTD > 0
         ORDER BY pangya_card.card_itemid      



   END
