/****** Objeto:  StoredProcedure [pangya].[ProcGetDailyAchieveQuest]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetDailyAchieveQuest]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported : Get Daily Quest "Quest"
      *
      */

      /*
      *   SSMA warning messages:
      *   M2SS0104: Non aggregated column IDX is aggregated with Min(..) in Select, Orderby and Having clauses.
      *   M2SS0104: Non aggregated column TYPEID is aggregated with Min(..) in Select, Orderby and Having clauses.
      *   M2SS0104: Non aggregated column COUNT_ID is aggregated with Min(..) in Select, Orderby and Having clauses.
      *   M2SS0104: Non aggregated column DATA_SEC is aggregated with Min(..) in Select, Orderby and Having clauses.

      *   SSMA informational messages:
      *   M2SS0282: Binary value is converted to numeric value
      *   M2SS0282: Binary value is converted to numeric value
      */

      SELECT B.TypeID_ACHIEVE, ISNULL(min(C.TypeID), 0) AS TypeID, ISNULL(min(C.Count_ID), 0) AS Count_ID, ISNULL(min(C.Data_Sec), 0) AS Data_Sec
      FROM 
         (
            SELECT 
               a.TypeID, 
               a.[Option], 
               D.IDX, 
               D.UID, 
               D.ID_ACHIEVEMENT, 
               D.TypeID_ACHIEVE, 
               D.Count_ID, 
               D.Data_Sec, 
               D.Objetivo_Quest
            FROM pangya.achievement_tipo  AS a, pangya.achievement_quest  AS D
            WHERE D.UID = @IDUSER AND a.ID_ACHIEVEMENT = D.ID_ACHIEVEMENT
         )  AS B 
            LEFT OUTER JOIN 
            (
               SELECT 
                  count_item.UID, 
                  count_item.Nome, 
                  count_item.ID_ACHIEVEMENT, 
                  count_item.TypeID, 
                  count_item.Count_ID, 
                  count_item.Count_Num_Item, 
                  count_item.Data_Sec, 
                  count_item.TIPO
               FROM pangya.count_item
               WHERE count_item.UID = @IDUSER
            )  AS C 
            ON C.Count_ID = B.Count_ID
      WHERE 
         B.UID = @IDUSER AND 
         B.[Option] = 3 AND 
         B.TypeID >= 2013265920 AND 
         B.TypeID < 2017460224
      GROUP BY B.TypeID_ACHIEVE
         ORDER BY min(B.IDX)

   END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGetDailyAchieveType]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetDailyAchieveType]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported : Get Daily Quest tipo
      *   SELECT A.TIPO, a.TypeID, A.ID_ACHIEVEMENT, A.`Option`, COUNT(b.ID_ACHIEVEMENT) AS COUNTER
      *   				 FROM achievement_tipo A, achievement_quest b
      *   				 WHERE  a.ID_ACHIEVEMENT = b.ID_ACHIEVEMENT AND a.UID = IDUSER AND a.`OPTION` = 3
      *   				 AND a.TypeID >= 0x78000000 AND a.TypeID < 0x78800001
      *   				 GROUP BY b.ID_ACHIEVEMENT
      *   				 ORDER BY b.ID_ACHIEVEMENT;
      *
      */

      /*
      *   SSMA warning messages:
      *   M2SS0104: Non aggregated column TIPO is aggregated with Min(..) in Select, Orderby and Having clauses.
      *   M2SS0104: Non aggregated column TYPEID is aggregated with Min(..) in Select, Orderby and Having clauses.
      *   M2SS0104: Non aggregated column OPTION is aggregated with Min(..) in Select, Orderby and Having clauses.
      */

      SELECT 
         min(A.TIPO) AS TIPO, 
         min(A.TypeID) AS TypeID, 
         A.ID_ACHIEVEMENT, 
         min(A.[Option]) AS [Option], 
         count_big(B.ID_ACHIEVEMENT) AS COUNTER
      FROM 
         (
            /*
            *   SSMA informational messages:
            *   M2SS0282: Binary value is converted to numeric value
            *   M2SS0282: Binary value is converted to numeric value
            */

            SELECT achievement_tipo.TIPO, achievement_tipo.TypeID, achievement_tipo.ID_ACHIEVEMENT, achievement_tipo.[Option]
            FROM pangya.achievement_tipo
            WHERE 
               achievement_tipo.UID = @IDUSER AND 
               achievement_tipo.[Option] = 3 AND 
               achievement_tipo.TypeID >= 2013265920 AND 
               achievement_tipo.TypeID < 2021654529
         )  AS A 
            INNER JOIN 
            (
               SELECT achievement_quest.ID_ACHIEVEMENT
               FROM pangya.achievement_quest
            )  AS B 
            ON A.ID_ACHIEVEMENT = B.ID_ACHIEVEMENT
      GROUP BY A.ID_ACHIEVEMENT
         ORDER BY A.ID_ACHIEVEMENT

   END
GO
