/****** Objeto:  StoredProcedure [pangya].[ProcGetDailyQuest_New]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetDailyQuest_New]
	-- Add the parameters for the stored procedure here
	@IDUSER int
AS
BEGIN
	--Get Daily Quest
	DECLARE @today datetime2
	DECLARE @last_accept datetime2

	SET @last_accept = (SELECT last_quest_accept FROM pangya.pangya_daily_quest_player WHERE uid = @IDUSER);
	SET @today = (SELECT today_quest FROM pangya.pangya_daily_quest_player WHERE uid = @IDUSER);
    
	SELECT CAST(dbo.UNIX_TIMESTAMP(Reg_Date) AS bigint) AS Reg_Date,	-- Deprecated Column
			CASE WHEN @last_accept IS NULL THEN 0 ELSE CAST(dbo.UNIX_TIMESTAMP(@last_accept) AS bigint) END AS Reg_Date_player, 
			CASE WHEN @today IS NULL THEN 0 ELSE CAST(dbo.UNIX_TIMESTAMP(@today) AS bigint) END AS today_quest,
			achieve_quest_1, achieve_quest_2, achieve_quest_3
	FROM pangya.pangya_daily_quest;
END
GO
