-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetDolfiniLockerItemOne]
	-- Add the parameters for the stored procedure here
	@IDUSER INT,
	@ITEM_ID INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	IF @IDUSER > 0 AND @ITEM_ID > 0
	BEGIN
		SELECT
			a.item_id,
			a.[uid],
			a.typeid,
			CASE WHEN b.UCC_NAME IS NULL THEN N'' ELSE b.UCC_NAME END as SD_NAME,
			CASE WHEN b.UCCIDX IS NULL THEN N'' ELSE b.UCCIDX END as SD_IDX,
			CASE WHEN b.SEQ IS NULL THEN 0 ELSE b.SEQ END as SD_SEQ,
			CASE WHEN b.COPIER_NICK IS NULL THEN N'' ELSE b.COPIER_NICK END as SD_COPIER_NICK,
			--CASE WHEN b.COPIER IS NULL THEN 0 ELSE b.COPIER END as SD_COPIER,
			--CASE WHEN b.TRADE IS NULL THEN 0 ELSE b.TRADE END as SD_TRADE,
			--CASE WHEN b.Flag IS NULL THEN 0 ELSE b.Flag END as SD_FLAG,
			CASE WHEN b.[STATUS] IS NULL THEN 0 ELSE b.[STATUS] END as SD_STATUS,
			c.idx as IDX_DOLFINI_LOCKER_ITEM,
			c.flag as FLAG_DOLFINI_LOCKER_ITEM
		FROM 
			pangya.pangya_item_warehouse a
			LEFT OUTER JOIN
			pangya.tu_ucc b
		ON	a.item_id = b.ITEM_ID
		INNER JOIN pangya.pangya_dolfini_locker_item c
		ON a.item_id = c.item_id
		WHERE a.[uid] = @IDUSER AND a.item_id = @ITEM_ID AND c.flag = 1
	END

END
