-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetDonationInfo]
AS
BEGIN

    SELECT	a.ADM_uid,
		a.[uid],
		a.plataforma,
		a.cash,
		a.cookie_point,
		(SELECT COUNT_BIG(donation_id) FROM pangya.pangya_donation_item_log WHERE donation_id = a.[index]) as count_item,
		a.email,
		a.obs,
		CAST(a.red_date AS NVARCHAR(19)) AS red_date
	FROM pangya.pangya_donation_log a
	ORDER BY a.[index]

END
