*/

CREATE PROCEDURE [pangya].[ProcGetGachaPlayerStatus]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

     -- SET  NOCOUNT  ON

      /* 
      *   SSMA error messages:
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion

      /*
      *   SSMA warning messages:
      *   M2SS0250: Parameters used in N'ISNULL' function/operator are not of same data type so they are casted to Character datatype.
      *   M2SS0284: Numeric value is converted to string value
      */*/

      SELECT 
         a.ID AS UserId, 
         ISNULL(
            (
               SELECT TOP 1 pangya.pangya_item_warehouse.C0
               FROM pangya.pangya_item_warehouse
               WHERE pangya.pangya_item_warehouse.UID = @IDUSER AND pangya.pangya_item_warehouse.typeid = 436207832 AND valid = 1
            ), N'0') AS UserCoupon, 
         c.numero AS Verno, 
         c.townno AS Townno, 
         b.Cookie AS UserNTreevCoin
      FROM pangya.account  AS a, pangya.user_info  AS b, pangya.pangya_gacha  AS c
      WHERE a.UID = @IDUSER AND b.UID = a.UID      



   END
