/****** Objeto:  StoredProcedure [pangya].[ProcGetGachaRareListSorteio]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetGachaRareListSorteio]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      --SET  NOCOUNT  ON

      /* 
      *   SSMA error messages:
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
	  */

      SELECT 
         X.[index], 
         X.prob, 
         X.typeid, 
         X.nome, 
         X.tipo, 
         X.premio, 
         X.secret
      FROM 
         (
            SELECT TOP (9223372036854775807) 
               a.[index], 
                CASE 
                  WHEN (a.tipo = 1) THEN floor(a.probabilidade * b.rate * 1.0 / 100)
                  ELSE a.probabilidade
               END AS prob, 
               a.typeid, 
               a.nome, 
               a.tipo, 
               a.premio, 
               a.secret
            FROM pangya.pangya_gacha_items  AS a, pangya.pangya_gacha  AS b
            WHERE a.gacha_num = b.numero
               ORDER BY rand()
         )  AS X
      WHERE X.typeid NOT IN 
         (
            SELECT c.item_typeid AS typeid
            FROM pangya.pangya_gacha  AS a, pangya.pangya_gacha_user_won  AS c
            WHERE a.numero = c.gacha_num AND c.uid = @IDUSER
            GROUP BY c.item_typeid
         )      



   END
GO
