CREATE PROCEDURE [pangya].[ProcGetGiftPart]
	-- Add the parameters for the stored procedure here
	@IDUSER INT,
	@IDITEM INT,
	@ITEMTYPEID INT,
	@TYPE_IFF TINYINT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	IF @IDITEM > 0 AND @ITEMTYPEID > 0
	BEGIN
		UPDATE pangya.pangya_item_warehouse SET [UID] = @IDUSER, valid = 1, Gift_flag = 0
		WHERE item_id = @IDITEM

		IF @TYPE_IFF = 8 OR @TYPE_IFF = 9
			UPDATE pangya.tu_ucc SET [UID] = @IDUSER WHERE ITEM_ID = @IDITEM

		exec pangya.ProcGetWareHouseItem_One @IDUSER, @IDITEM
	END
	ELSE
		SELECT -1 AS ITEM_ID,
				0 as [UID], 
				0 as typeid, 
				0 as Ano, 
				0 as C0, 
				0 as C1, 
				0 as C2, 
				0 as C3, 
				0 as C4, 
				0 as Purchase, 
				0 as Gift_flag, 
				0 as Flag, 
				0 as APPLY_DATE, 
				0 as END_DATE, 
				0 as ItemType, 
				0 as CARD_CHARACTER_1, 
				0 as CARD_CHARACTER_2, 
				0 as CARD_CHARACTER_3, 
				0 as CARD_CHARACTER_4, 
				0 as CARD_CADDIE_1, 
				0 as CARD_CADDIE_2, 
				0 as CARD_CADDIE_3, 
				0 as CARD_CADDIE_4, 
				0 as CARD_NPC_1, 
				0 as CARD_NPC_2, 
				0 as CARD_NPC_3, 
				0 as CARD_NPC_4, 
				0 as ClubSet_WorkShop_Flag, 
				0 as ClubSet_WorkShop_C0, 
				0 as ClubSet_WorkShop_C1, 
				0 as ClubSet_WorkShop_C2, 
				0 as ClubSet_WorkShop_C3, 
				0 as ClubSet_WorkShop_C4, 
				0 as Mastery_Pts, 
				0 as Recovery_Pts, 
				0 as [Level], 
				0 as Up, 
				null as SD_NAME, 
				null as SD_IDX, 
				0 as SD_SEQ, 
				null as SD_COPIER_NICK, 
				0 as SD_COPIER, 
				0 as SD_TRADE, 
				0 as SD_FLAG, 
				0 as SD_STATUS;
END
