-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetGMGiftWebInfo]
	-- Add the parameters for the stored procedure here
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	
	SELECT 
		a.GM_UID,
		a.PLAYER_UID,
		COUNT_BIG(c.MSG_ID) as COUNT_ITEM,
		b.[message],
		CAST(a.REG_DATE AS NVARCHAR(19)) AS REG_DATE
	FROM 
		pangya.pangya_gm_gift_web_log a
		INNER JOIN
		pangya.pangya_gift_table b
		ON a.MSG_ID = b.Msg_ID
		LEFT OUTER JOIN
		pangya.pangya_item_mail c
		ON b.Msg_ID = c.Msg_ID
	GROUP BY a.MSG_ID, a.GM_UID, a.PLAYER_UID, b.[message], a.REG_DATE
	ORDER BY a.REG_DATE

END
