-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetGuildBBSInfo]
	-- Add the parameters for the stored procedure here
	@BBS_SEQ BIGINT
AS
BEGIN
	
	IF @BBS_SEQ > 0
	BEGIN

		-- Update VIEWS BBS
		UPDATE pangya.pangya_guild_bbs SET [VIEWS] = [VIEWS] + 1 WHERE [SEQ] = @BBS_SEQ AND [STATE] = 1
		
		-- BBS
		SELECT
			a.SEQ,
			a.TITLE,
			a.[TEXT],
			a.[TYPE],
			a.OWNER_UID,
			(SELECT nick FROM pangya.account WHERE [UID] = a.OWNER_UID) AS NICKNAME,
			a.[VIEWS],
			CAST(a.REG_DATE AS NVARCHAR(19)) AS REG_DATE
		FROM
			pangya.pangya_guild_bbs a
		WHERE a.SEQ = @BBS_SEQ AND a.[STATE] = 1

		-- Reply
		SELECT
			b.SEQ,
			b.[TEXT],
			b.OWNER_UID,
			(SELECT nick FROM pangya.account WHERE [UID] = b.OWNER_UID) AS NICKNAME,
			CAST(b.REG_DATE AS NVARCHAR(19)) AS REG_DATE
		FROM
			pangya.pangya_guild_bbs a
			INNER JOIN
			pangya.pangya_guild_bbs_res b
			ON a.SEQ = b.BBS_SEQ
		WHERE a.SEQ = @BBS_SEQ AND a.[STATE] = 1 AND b.[STATE] = 1
		ORDER BY b.REG_DATE

	END
END
GO
