-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetGuildInfoComplete]
	-- Add the parameters for the stored procedure here
	@UID INT
AS
BEGIN
	
	SELECT 
		a.GUILD_UID, 
		a.GUILD_NAME, 
		(SELECT NICK FROM pangya.account WHERE [UID] = a.GUILD_LEADER) AS GUILD_MASTER,
		ISNULL((SELECT NICK FROM pangya.account WHERE [UID] = a.GUILD_SUB_MASTER), '') AS GUILD_SUB_MASTER,
		(SELECT count_big(GUILD_UID) FROM pangya.pangya_guild_member WHERE GUILD_UID = a.GUILD_UID AND MEMBER_STATE_FLAG < 9) AS GUILD_MEMBERS,
		a.GUILD_STATE,
		a.GUILD_FLAG,
		a.GUILD_CONDITION_LEVEL,
		a.GUILD_PERMITION_JOIN,
		CAST(a.GUILD_REG_DATE AS NVARCHAR(10)) AS GUILD_REG_DATE,
		a.GUILD_INFO,
		a.GUILD_NOTICE,
		a.GUILD_MARK_IMG_IDX,
		a.GUILD_NEW_MARK_IDX,
		a.GUILD_INTRO_IMG,
		CAST(a.GUILD_CLOSURE_DATE AS NVARCHAR(19)) AS GUILD_CLOSURE_DATE
	FROM
		pangya.pangya_guild a
		WHERE a.GUILD_UID = @UID
			AND (a.GUILD_STATE NOT IN(4, 5) OR a.GUILD_CLOSURE_DATE IS NULL OR getdate() < a.GUILD_CLOSURE_DATE)
END
