/****** Objeto:  StoredProcedure [pangya].[ProcGetGuildMatchList]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetGuildMatchList]
	-- Add the parameters for the stored procedure here
	@GUILD_UID INT,
	@PAGE INT
AS
BEGIN
	
	IF @GUILD_UID > 0 AND @PAGE >= 0
	BEGIN

		DECLARE @OTHER_GUILD INT = (
			SELECT
				b.GUILD_UID
			FROM
				pangya.pangya_guild b
			WHERE b.GUILD_UID = @GUILD_UID
				AND (b.GUILD_STATE NOT IN(4, 5) OR b.GUILD_CLOSURE_DATE IS NULL OR getdate() < b.GUILD_CLOSURE_DATE)
		)

		-- Está em uma Guild válida
		IF @OTHER_GUILD IS NOT NULL
		BEGIN

			DECLARE @LINHAS BIGINT = 

			-- Total de linhas da consulta
			(SELECT
				COUNT_BIG(a.[index]) AS LINHAS
			FROM
				pangya.pangya_guild_match a
			WHERE a.GUILD_1_UID = @GUILD_UID OR a.guild_2_uid = @GUILD_UID)

			SELECT
				@LINHAS AS LINHAS,
				a.GUILD_1_UID,
				(SELECT GUILD_NAME FROM pangya.pangya_guild WHERE GUILD_UID = a.GUILD_1_UID) AS GUILD_1_NAME,
				(SELECT GUILD_MARK_IMG_IDX FROM pangya.pangya_guild WHERE GUILD_UID = a.GUILD_1_UID) AS GUILD_1_MARK_INDEX,
				a.GUILD_1_POINT,
				a.GUILD_1_PANG,
				a.GUILD_2_UID,
				(SELECT GUILD_NAME FROM pangya.pangya_guild WHERE GUILD_UID = a.GUILD_2_UID) AS GUILD_2_NAME,
				(SELECT GUILD_MARK_IMG_IDX FROM pangya.pangya_guild WHERE GUILD_UID = a.GUILD_2_UID) AS GUILD_2_MARK_INDEX,
				a.GUILD_2_POINT,
				a.GUILD_2_PANG,
				CAST(a.REG_DATE AS NVARCHAR(16)) AS REG_DATE
			FROM
				pangya.pangya_guild_match a
			WHERE a.GUILD_1_UID = @GUILD_UID OR a.guild_2_uid = @GUILD_UID
			ORDER BY a.reg_date DESC
			OFFSET (@PAGE * 13) ROWS
			FETCH NEXT 13 ROWS ONLY

		END
		ELSE
			SELECT 0 AS LINHAS	-- ERROR

	END
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGetGuildMemberInfo]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
