/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetGuildMemberInfo]  
   @UID_GUILD int
AS 
BEGIN

	IF @UID_GUILD > 0
	BEGIN

      SELECT 
         a.GUILD_UID, 
         a.GUILD_NAME, 
         b.GUILD_PANG, 
         b.GUILD_POINT, 
         b.MEMBER_STATE_FLAG AS GUILD_MEMBER_IDENTITY, 
         b.MEMBER_UID AS GUILD_MEMBER_UID, 
         b.MEMBER_MSG AS GUILD_MEMBER_MSG, 
         c.NICK AS GUILD_MEMBER_NICK, 
         c.Logon AS GUILD_MEMBER_ON
      FROM 
		pangya.pangya_guild AS a
		INNER JOIN
		pangya.pangya_guild_member AS b
		ON a.GUILD_UID = b.GUILD_UID
		INNER JOIN
		pangya.account AS c
		ON b.MEMBER_UID = c.[UID]
      WHERE 
         a.GUILD_UID = @UID_GUILD
		 AND (b.MEMBER_STATE_FLAG < 9)
		 AND (a.GUILD_STATE NOT IN(4, 5) OR a.GUILD_CLOSURE_DATE IS NULL OR getdate() < a.GUILD_CLOSURE_DATE)

	END

END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGetGuildMemberList]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetGuildMemberList]
	-- Add the parameters for the stored procedure here
	@UID INT,
	@PAGE INT,
	@OPT INT,
	@MAX_LINE_PAGE INT
AS
BEGIN

	IF @MAX_LINE_PAGE <= 0
		SET @MAX_LINE_PAGE = 14
	
	IF @UID > 0 AND @PAGE >= 0
	BEGIN

		DECLARE @OTHER_GUILD INT = (
			SELECT
				b.GUILD_UID
			FROM
				pangya.pangya_guild b
			WHERE b.GUILD_UID = @UID
				AND (b.GUILD_STATE NOT IN(4, 5) OR b.GUILD_CLOSURE_DATE IS NULL OR getdate() < b.GUILD_CLOSURE_DATE)
		)

		-- Está em uma Guild válida
		IF @OTHER_GUILD IS NOT NULL
		BEGIN

			DECLARE @LINHAS BIGINT = 

			-- Total de linhas da consulta
			(SELECT 
				COUNT_BIG(b.MEMBER_UID) AS LINHAS
			FROM 
				pangya.pangya_guild a
				INNER JOIN
				pangya.pangya_guild_member b
				ON a.GUILD_UID = b.GUILD_UID
			WHERE a.GUILD_UID = @UID
				AND (@OPT = 0 OR (@OPT = 1 AND b.MEMBER_STATE_FLAG = 9) OR (@OPT = 2 AND b.MEMBER_STATE_FLAG < 9)))

			SELECT 
				@LINHAS as LINHAS,
				b.MEMBER_UID,
				b.MEMBER_STATE_FLAG,
				(SELECT nick FROM pangya.account WHERE [uid] = b.MEMBER_UID) AS NICKNAME,
				CAST(b.REG_DATE AS NVARCHAR(10)) AS REG_DATE
			FROM 
				pangya.pangya_guild a
				INNER JOIN
				pangya.pangya_guild_member b
				ON a.GUILD_UID = b.GUILD_UID
			WHERE a.GUILD_UID = @UID
				AND (@OPT = 0 OR (@OPT = 1 AND b.MEMBER_STATE_FLAG = 9) OR (@OPT = 2 AND b.MEMBER_STATE_FLAG < 9))
			ORDER BY b.MEMBER_STATE_FLAG, b.REG_DATE
			OFFSET (@PAGE * @MAX_LINE_PAGE) ROWS
			FETCH NEXT @MAX_LINE_PAGE ROWS ONLY

		END
		ELSE
			SELECT 0 AS LINHAS -- Erro
	
	END
END
GO
