-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetGuildNewsCreate]
AS
BEGIN
	
	SELECT 
		GUILD_UID, 
		GUILD_NAME, 
		GUILD_INFO, 
		GUILD_MARK_IMG_IDX, 
		CAST(GUILD_REG_DATE AS DATE) AS GUILD_REG_DATE 
	FROM 
		pangya.pangya_guild 
	WHERE GUILD_ACCEPT_DATE IS NOT NULL AND CAST(getdate() AS DATE) = CAST(GUILD_ACCEPT_DATE AS DATE) AND GUILD_STATE >= 1 AND GUILD_MARK_IMG_IDX > 0
		AND (GUILD_STATE NOT IN(4, 5) OR GUILD_CLOSURE_DATE IS NULL OR getdate() < GUILD_CLOSURE_DATE)
	ORDER BY GUILD_REG_DATE DESC
END
