-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetGuildNoticeInfo]
	-- Add the parameters for the stored procedure here
	@NOTICE_SEQ BIGINT
AS
BEGIN
	
	IF @NOTICE_SEQ > 0
	BEGIN

		DECLARE @OTHER_GUILD INT = (
			SELECT
				a.GUILD_UID
			FROM
				pangya.pangya_guild_notice a
				INNER JOIN
				pangya.pangya_guild b
				ON a.GUILD_UID = b.GUILD_UID
			WHERE a.SEQ = @NOTICE_SEQ
				AND (b.GUILD_STATE NOT IN(4, 5) OR b.GUILD_CLOSURE_DATE IS NULL OR getdate() < b.GUILD_CLOSURE_DATE)
		)

		-- Está em uma Guild válida
		IF @OTHER_GUILD IS NOT NULL
		BEGIN

			-- Update VIEWS BBS
			UPDATE pangya.pangya_guild_notice SET [VIEWS] = [VIEWS] + 1 WHERE [SEQ] = @NOTICE_SEQ AND [STATE] = 1
		
			-- BBS
			SELECT
				a.SEQ,
				a.TITLE,
				a.[TEXT],
				a.OWNER_UID,
				(SELECT nick FROM pangya.account WHERE [UID] = a.OWNER_UID) AS NICKNAME,
				a.[VIEWS],
				CAST(a.REG_DATE AS NVARCHAR(19)) AS REG_DATE
			FROM
				pangya.pangya_guild_notice a
			WHERE a.SEQ = @NOTICE_SEQ AND a.[STATE] = 1

		END

	END
