			(SELECT 
				COUNT_BIG(b.SEQ) AS LINHAS
			FROM 
				pangya.pangya_guild a
				INNER JOIN
				pangya.pangya_guild_notice b
				ON a.GUILD_UID = b.GUILD_UID
			WHERE a.GUILD_UID = @UID AND b.[STATE] = 1)
		
			SELECT 
