-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetGuildPrivateBBSInfo]
	-- Add the parameters for the stored procedure here
	@BBS_SEQ BIGINT
AS
BEGIN
	
	IF @BBS_SEQ > 0
	BEGIN

		DECLARE @OTHER_GUILD INT = (
			SELECT
				a.GUILD_UID
			FROM
				pangya.pangya_guild_private_bbs a
				INNER JOIN
				pangya.pangya_guild b
				ON a.GUILD_UID = b.GUILD_UID
			WHERE a.SEQ = @BBS_SEQ
				AND (b.GUILD_STATE NOT IN(4, 5) OR b.GUILD_CLOSURE_DATE IS NULL OR getdate() < b.GUILD_CLOSURE_DATE)
		)

		-- Está em uma Guild válida
		IF @OTHER_GUILD IS NOT NULL
		BEGIN

			-- Update VIEWS BBS
			UPDATE pangya.pangya_guild_private_bbs SET [VIEWS] = [VIEWS] + 1 WHERE [SEQ] = @BBS_SEQ AND [STATE] = 1
		
			-- BBS
			SELECT
				a.SEQ,
				a.TITLE,
				a.[TEXT],
				a.OWNER_UID,
				(SELECT nick FROM pangya.account WHERE [UID] = a.OWNER_UID) AS NICKNAME,
				a.[VIEWS],
				CAST(a.REG_DATE AS NVARCHAR(19)) AS REG_DATE
			FROM
				pangya.pangya_guild_private_bbs a
			WHERE a.SEQ = @BBS_SEQ AND a.[STATE] = 1

			-- Reply
			SELECT
				b.SEQ,
				b.[TEXT],
				b.OWNER_UID,
				(SELECT nick FROM pangya.account WHERE [UID] = b.OWNER_UID) AS NICKNAME,
				CAST(b.REG_DATE AS NVARCHAR(19)) AS REG_DATE
			FROM
				pangya.pangya_guild_private_bbs a
				INNER JOIN
				pangya.pangya_guild_private_bbs_res b
				ON a.SEQ = b.GUILD_BBS_SEQ
			WHERE a.SEQ = @BBS_SEQ AND a.[STATE] = 1 AND b.[STATE] = 1
			ORDER BY b.REG_DATE

		END

	END
END
GO
