/****** Objeto:  StoredProcedure [pangya].[ProcGetHioEventStatus]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [pangya].[ProcGetHioEventStatus]
    @UserID INT,
    @HoleCount INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @UserExists BIT;
    DECLARE @UserStatus INT;
    DECLARE @UserHolesProcessed INT;
    DECLARE @ItemsExist BIT;
	DECLARE @EventStatus int;
    -- Verificar se o usuário está cadastrado
    set @UserExists = CASE WHEN EXISTS (SELECT 1 FROM [pangya].[pangya_hio_event] WHERE UID = @UserID) THEN 1 ELSE 0 END;
    set @EventStatus = 1; 
    IF @UserExists = 0
    BEGIN
        set @EventStatus = 0; -- Usuário não cadastrado
    END

    -- Obter o status e a quantidade de buracos processados do usuário
    set @UserStatus = ( select [STATUS] FROM [pangya].[pangya_hio_event] WHERE UID = @UserID);
	set @UserHolesProcessed =  ( select PROCESS_HIOS  FROM [pangya].[pangya_hio_event] WHERE UID = @UserID);
    -- Verificar se o status é menor que 5
    IF @UserStatus >= 5
    BEGIN
        set @EventStatus = 0; -- Status do usuário deve ser menor que 5
    END

    -- Verificar se o usuário atingiu a meta de hio_count
    IF @UserHolesProcessed < @HoleCount
    BEGIN
        set @EventStatus = 0; -- Usuário não atingiu a meta de hio_count
    END

    -- Verificar se o hio_count fornecido é maior do que o processado
    IF @HoleCount > @UserHolesProcessed
    BEGIN
        set @EventStatus = 0; -- hio_count fornecido é maior do que os buracos processados
    END

    -- Verificar se o usuário já recebeu o item correspondente ao hio_count
    DECLARE @RequiredStatus INT; 
    -- Mapear hio_count para status
	 IF @HoleCount > (select HIO_COUNT  FROM [pangya].[pangya_hio_event_items] where IDX = 5)
        SET @RequiredStatus = 6;
    ELSE IF @HoleCount = ( select HIO_COUNT  FROM [pangya].[pangya_hio_event_items] where IDX = 1)
        SET @RequiredStatus = 1;
    ELSE IF @HoleCount = ( select HIO_COUNT  FROM [pangya].[pangya_hio_event_items] where IDX = 2)
        SET @RequiredStatus = 2;
    ELSE IF @HoleCount = ( select HIO_COUNT  FROM [pangya].[pangya_hio_event_items] where IDX = 3)
        SET @RequiredStatus = 3;
    ELSE IF @HoleCount = ( select HIO_COUNT  FROM [pangya].[pangya_hio_event_items] where IDX = 4)
        SET @RequiredStatus = 4;
		 ELSE IF @HoleCount = ( select HIO_COUNT  FROM [pangya].[pangya_hio_event_items] where IDX = 5)
        SET @RequiredStatus = 5;
    ELSE
        set @EventStatus = 0; -- hio_count inválido 

    IF @UserStatus >= @RequiredStatus
    BEGIN
        set @EventStatus = 0; -- Usuário já recebeu o item correspondente
    END

    -- Verificar se existem itens relacionados ao evento
    set @ItemsExist = (CASE WHEN EXISTS (SELECT 1 FROM [pangya].[pangya_hio_event_items] WHERE HIO_COUNT = @HoleCount) THEN 1 ELSE 0 END);

    IF @ItemsExist = 0
    BEGIN
        set @EventStatus = 0; -- Não existem itens relacionados ao evento
    END

    select @EventStatus as 'EventStatus'; -- Sucesso
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGetHioEventUser]    Data do Script: 03/05/2026 15:40:48 ******/
