CREATE PROCEDURE [pangya].[ProcGetHioEventUser]
    @UserID INT,
    @HoleCount INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @UserStatus INT;
    DECLARE @UserHolesProcessed INT;
    DECLARE @ItemName NVARCHAR(50);
    DECLARE @ItemTypeID INT;
    DECLARE @ItemQuantity INT;

    -- Obter o status e a quantidade de buracos processados do usuário
    set @UserHolesProcessed = ( select PROCESS_HIOS 
    FROM [pangya].[pangya_hio_event] 
    WHERE UID = @UserID);

	set @UserStatus =( select [STATUS] FROM [pangya].[pangya_hio_event] WHERE UID = @UserID); 
	 
    -- Obter informações do item com base no hio_count
       SELECT ITEM_NAME as 'ItemName', 
                  ITEM_TYPEID as 'ItemTypeID', 
                 ITEM_QNTD as 'ItemQuantity' 
    FROM [pangya].[pangya_hio_event_items] 
    WHERE HIO_COUNT = (select HIO_COUNT  FROM [pangya].[pangya_hio_event_items] where IDX = @UserStatus); 

END
