CREATE PROCEDURE [pangya].[ProcGetHoleEvent]
    -- Add the parameters for the stored procedure here
    @UID INT 
AS
BEGIN
     
    -- Select the updated or inserted record
	SELECT a.UID, a.NICK AS NICKNAME, a.ID, a.IDState, p.PROCESS_HOLES as 'MY_HOLES', p.START_HOLES as 'START_PROCESS', P.[STATUS] AS 'STAGE', P.FINISH_DATE 
                      FROM pangya.account a
                      LEFT JOIN pangya.pangya_hole_event p ON a.UID = p.UID
                      WHERE a.UID = @UID;
END
