CREATE PROCEDURE [pangya].[ProcGetHoleEventItems]   
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

     SELECT 
    phe.[HOLE_COUNT],
    phe.[ITEM_NAME],
    phe.[ITEM_TYPEID],
    phe.[ITEM_QNTD],
    phe.[ITEM_QNTD_TIME],
    phe.[EVENT_DESCRIPTION],
    it.icon AS [ITEM_ICON]      -- Seleciona a coluna 'icon' da tabela item_typelist
FROM 
    [pangya].[pangya_hole_event_items] phe
JOIN 
    [pangya].[pangya_item_typelist] it
ON 
    phe.item_typeid = it.typeid order by phe.EVENT_ID;  -- Interliga as duas tabelas com base no typeid

   END
