/****** Objeto:  StoredProcedure [pangya].[ProcGetHoleEventStatus]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [pangya].[ProcGetHoleEventStatus]
    @UserID INT,
    @HoleCount INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @UserExists BIT;
    DECLARE @UserStatus INT;
    DECLARE @UserHolesProcessed INT;
    DECLARE @ItemsExist BIT;
	DECLARE @EventStatus int;
    -- Verificar se o usuário está cadastrado
    set @UserExists = CASE WHEN EXISTS (SELECT 1 FROM [pangya].[pangya_hole_event] WHERE UID = @UserID) THEN 1 ELSE 0 END;
    set @EventStatus = 1; 
    IF @UserExists = 0
    BEGIN
        set @EventStatus = 0; -- Usuário não cadastrado
    END

    -- Obter o status e a quantidade de buracos processados do usuário
    set @UserStatus = ( select [STATUS] FROM [pangya].[pangya_hole_event] WHERE UID = @UserID);
	set @UserHolesProcessed =  ( select PROCESS_HOLES  FROM [pangya].[pangya_hole_event] WHERE UID = @UserID);
    -- Verificar se o status é menor que 5
    IF @UserStatus >= 5
    BEGIN
        set @EventStatus = 0; -- Status do usuário deve ser menor que 5
    END

    -- Verificar se o usuário atingiu a meta de hole_count
    IF @UserHolesProcessed < @HoleCount
    BEGIN
        set @EventStatus = 0; -- Usuário não atingiu a meta de hole_count
    END

    -- Verificar se o hole_count fornecido é maior do que o processado
    IF @HoleCount > @UserHolesProcessed
    BEGIN
        set @EventStatus = 0; -- hole_count fornecido é maior do que os buracos processados
    END
	 
    select @EventStatus as 'EventStatus'; -- Sucesso
END
GO
