CREATE PROCEDURE [pangya].[ProcGetHoleEventUser]
    @UserID INT,
    @HoleCount INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @UserStatus INT;
    DECLARE @UserHolesProcessed INT;
    DECLARE @ItemName NVARCHAR(50);
    DECLARE @ItemTypeID INT;
    DECLARE @ItemQuantity INT;

    -- Obter o status e a quantidade de buracos processados do usuário
    set @UserHolesProcessed = ( select PROCESS_HOLES 
    FROM [pangya].[pangya_hole_event] 
    WHERE UID = @UserID);

	set @UserStatus =( select [STATUS] FROM [pangya].[pangya_hole_event] WHERE UID = @UserID); 
	 
    -- Obter informações do item com base no hole_count
       SELECT ITEM_NAME as 'ItemName', 
                  ITEM_TYPEID as 'ItemTypeID', 
                 ITEM_QNTD as 'ItemQuantity' 
    FROM [pangya].[pangya_hole_event_items] 
    WHERE HOLE_COUNT = (select HOLE_COUNT  FROM [pangya].[pangya_hole_event_items] where EVENT_ID = @UserStatus); 

END
