/****** Objeto:  StoredProcedure [pangya].[ProcGetInfoPlayerToWeb]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetInfoPlayerToWeb]
	@TYPE INT
AS
BEGIN
	
	IF @TYPE = 0 -- Default Todas as contas que já fizeram logon pelo menos uma vez
	BEGIN
		
		SELECT 
				a.[uid], 
				a.id, 
				a.nick, 
				c.[level], 
				a.idstate, 
				a.capability as cap, 
				c.pang, 
				c.cookie, 
				d.channel, 
				d.lobby, 
				d.room, 
				d.place, 
				a.logonCount, 
				e.[counter],
				a.userip,
				CAST(a.LastLogonTime AS NVARCHAR(16)) AS LastLogonTime, 
				a.logon, 
				a.game_server_id, 
				b.[name] 
		FROM pangya.account a, pangya.user_info c, pangya.pangya_server_list b, pangya.pangya_player_location d, pangya.pangya_attendance_reward e
		WHERE a.game_server_id = b.[uid]  AND a.[uid] = c.[uid] AND a.[uid] = d.[uid] AND a.[UID] = e.[UID]

	END
	ELSE IF @TYPE = 1 -- Todas as contas que não fizeram login
	BEGIN

		SELECT 
				a.[uid], 
				a.id, 
				a.nick, 
				c.[level], 
				a.idstate, 
				a.capability as cap, 
				c.pang, 
				c.cookie, 
				d.channel, 
				d.lobby, 
				d.room, 
				d.place, 
				a.logonCount,
				e.[counter],
				a.userip,
				CAST(a.LastLogonTime AS NVARCHAR(16)) AS LastLogonTime, 
				a.logon, 
				a.game_server_id, 
				'unknown' as [name] 
		FROM pangya.account a, pangya.user_info c, pangya.pangya_player_location d, pangya.pangya_attendance_reward e
		WHERE  a.[uid] = c.[uid] AND a.[uid] = d.[uid] AND a.[UID] = e.[UID] AND (a.first_login = 0 OR a.first_set = 0)

	END
	ELSE IF @TYPE = 2 -- Todas as contas online no momento
	BEGIN
		
		SELECT 
				a.[uid], 
				a.id, 
				a.nick, 
				c.[level], 
				a.idstate, 
				a.capability as cap, 
				c.pang, c.cookie, 
				d.channel, 
				d.lobby, 
				d.room, 
				d.place, 
				a.logonCount, 
				e.[counter],
				a.userip,
				CAST(a.LastLogonTime AS NVARCHAR(16)) AS LastLogonTime,
				a.logon, 
				a.game_server_id, 
				b.[name] 
		FROM pangya.account a, pangya.user_info c, pangya.pangya_server_list b, pangya.pangya_player_location d, pangya.pangya_attendance_reward e
		WHERE a.logon = 1 AND a.game_server_id = b.[uid] AND a.[uid] = c.[uid] AND a.[uid] = d.[uid] AND a.[UID] = e.[UID]

	END
	ELSE IF @TYPE = 4 -- Todas as contas banidas
	BEGIN
		
		SELECT 
				a.[uid], 
				a.id, 
				a.nick, 
				c.[level], 
				a.idstate, 
				a.capability as cap, 
				c.pang, 
				c.cookie, 
				d.channel, 
				d.lobby, 
				d.room, 
				d.place, 
				a.logonCount,
				e.[counter],
				a.userip,
				CAST(a.LastLogonTime AS NVARCHAR(16)) AS LastLogonTime, 
				a.logon, 
				a.game_server_id, 
				ISNULL(b.[Name], 'unknown') as [name] 
		FROM 
			pangya.account a
			INNER JOIN
			pangya.user_info c
			ON a.[uid] = c.[uid]
			INNER JOIN
			pangya.pangya_player_location d
			ON a.[uid] = d.[uid]
			INNER JOIN
			pangya.pangya_attendance_reward e
			ON a.[UID] = e.[UID]
			LEFT OUTER JOIN
			pangya_server_list b
			ON b.[UID] = a.game_server_id
		WHERE 
			(a.IDState = 1 AND ISNULL(DATEADD(MINUTE, a.BlockTime, a.BlockRegDate), getdate()) > getdate() OR a.IDState > 1)
	END

END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGetInformationEmail]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

/*
*   SSMA informational messages:
*   M2SS0134: Conversion of following Comment(s) is not supported : Obtêm o que está dentro do E-mail
*
*/

CREATE PROCEDURE [pangya].[ProcGetInformationEmail]  
   @IDUSER int,
   @IDMSG int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      UPDATE pangya.pangya_gift_table
         SET 
            Lida_YN = 1,
			Contador_Vista = Contador_Vista + 1
      WHERE pangya_gift_table.UID = @IDUSER AND pangya_gift_table.Msg_ID = @IDMSG

      /* 
      *   SSMA error messages:
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion

      /*
      *   SSMA warning messages:
      *   M2SS0251: CASE statement returns expressions of different data types.This may lead to ambiguous results.
      */*/

      SELECT 
         X.Msg_ID, 
         X.fromid, 
         X.giftdate, 
         X.message, 
         X.Lida_YN, 
         (CASE 
            WHEN X.item_id IS NULL THEN 0
            ELSE X.item_id
         END) AS ITEM_ID, 
         (CASE 
            WHEN X.item_typeid IS NULL THEN 0
            ELSE X.item_typeid
         END) AS ITEM_TYPEID, 
         (CASE 
            WHEN X.Flag IS NULL THEN 0
            ELSE X.Flag
         END) AS FLAG, 
         (CASE 
            WHEN X.Quantidade_item IS NULL THEN 0
            ELSE X.Quantidade_item
         END) AS QUANTIDADE_ITEM, 
         (CASE 
            WHEN X.Quantidade_Dia IS NULL THEN 0
            ELSE X.Quantidade_Dia
         END) AS QUANTIDADE_DIA, 
         (CASE 
            WHEN X.Pang IS NULL THEN 0
            ELSE X.Pang
         END) AS PANG, 
         (CASE 
            WHEN X.Cookie IS NULL THEN 0
            ELSE X.Cookie
         END) AS COOKIE, 
         (CASE 
            WHEN X.GM_ID IS NULL THEN 0
            ELSE X.GM_ID
         END) AS GM_ID, 
         (CASE 
            WHEN X.Flag_Gift IS NULL THEN 0
            ELSE X.Flag_Gift
         END) AS FLAG_GIFT, 
         (CASE 
            WHEN X.UCC_IMG_MARK IS NULL THEN N'0'
            ELSE X.UCC_IMG_MARK
         END) AS UCC_IMG_MARK, 
         (CASE 
            WHEN X.Type IS NULL THEN 0
            ELSE X.Type
         END) AS TYPE
      FROM 
         (
            SELECT 
               A.UID, 
               A.Msg_ID, 
               A.fromid, 
               A.message, 
               A.giftdate, 
               A.Contador_Vista, 
               A.Lida_YN, 
               A.Flag AS Flag_MSG, 
               B.ID_MSG, 
               B.item_id, 
               B.item_typeid, 
               B.Flag, 
               B.Quantidade_item, 
               B.Quantidade_Dia, 
               B.GET_DATE, 
               B.Pang, 
               B.Cookie, 
               B.GM_ID, 
               B.Flag_Gift, 
               /*B.UCC_IMG_MARK*/
			   ISNULL((SELECT UCCIDX FROM pangya.tu_ucc WHERE item_id = B.item_id), N'0') AS UCC_IMG_MARK, 
               B.Type
            FROM 
               (
                  SELECT 
                     pangya_gift_table.UID, 
                     pangya_gift_table.Msg_ID, 
                     pangya_gift_table.fromid, 
                     pangya_gift_table.message, 
                     pangya_gift_table.giftdate, 
                     pangya_gift_table.Flag, 
                     pangya_gift_table.Contador_Vista, 
                     pangya_gift_table.Lida_YN
                  FROM pangya.pangya_gift_table
                  WHERE pangya_gift_table.valid = 1
               )  AS A 
                  LEFT OUTER JOIN 
                  (
                     SELECT 
                        pangya_item_mail.Msg_ID AS ID_MSG, 
                        pangya_item_mail.item_id, 
                        pangya_item_mail.item_typeid, 
                        pangya_item_mail.Flag, 
                        pangya_item_mail.Quantidade_item, 
                        pangya_item_mail.Quantidade_Dia, 
                        pangya_item_mail.GET_DATE, 
                        pangya_item_mail.Pang, 
                        pangya_item_mail.Cookie, 
                        pangya_item_mail.GM_ID, 
                        pangya_item_mail.Flag_Gift, 
                        pangya_item_mail.UCC_IMG_MARK, 
                        pangya_item_mail.Type
                     FROM pangya.pangya_item_mail
                     WHERE pangya_item_mail.valid = 1
                  )  AS B 
                  ON A.Msg_ID = B.ID_MSG
         )  AS X
      WHERE X.UID = @IDUSER AND X.Msg_ID = @IDMSG      



   END
GO
