*/

CREATE PROCEDURE [pangya].[ProcGetItemBoostPangFlag]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @FLAG_RET int = 0

      IF 
         (
            /*
            *   SSMA informational messages:
            *   M2SS0134: Conversion of following Comment(s) is not supported : x2 500unit
            *
            */

            /*
            *   SSMA informational messages:
            *   M2SS0282: Binary value is converted to numeric value
            */

            SELECT pangya_item_warehouse.typeid
            FROM pangya.pangya_item_warehouse
            WHERE 
               pangya_item_warehouse.UID = @IDUSER AND 
               pangya_item_warehouse.valid = 1 AND 
               pangya_item_warehouse.C0 > 0 AND 
               pangya_item_warehouse.typeid = 436207617
         ) IS NOT NULL
         SET @FLAG_RET = @FLAG_RET | 1

      IF 
         (            SELECT pangya_item_warehouse.typeid
            FROM pangya.pangya_item_warehouse
            WHERE 
               pangya_item_warehouse.UID = @IDUSER AND 
               pangya_item_warehouse.valid = 1 AND 
               pangya_item_warehouse.C0 > 0 AND 
               pangya_item_warehouse.typeid = 436207618
         ) IS NOT NULL
         SET @FLAG_RET = @FLAG_RET | 1

      IF 
         (            SELECT pangya_item_warehouse.typeid
            FROM pangya.pangya_item_warehouse
            WHERE 
               pangya_item_warehouse.UID = @IDUSER AND 
               pangya_item_warehouse.valid = 1 AND 
               pangya_item_warehouse.C0 > 0 AND 
               pangya_item_warehouse.typeid = 436207621
         ) IS NOT NULL
         SET @FLAG_RET = @FLAG_RET | 2

      SELECT @FLAG_RET

   END
