               R.Up, 
               [@UCC_NAME] = CASE 
                  WHEN L.UCC_NAME IS NULL THEN 0
                  ELSE L.UCC_NAME
               END AS SD_NAME, 
               [@UCCIDX] = CASE 
                  WHEN L.UCCIDX IS NULL THEN 0
                  ELSE L.UCCIDX
               END AS SD_IDX, 
               [@SEQ] = CASE 
                  WHEN L.SEQ IS NULL THEN 0
                  ELSE L.SEQ
               END AS SD_SEQ, 
               [@COPIER_NICK] = CASE 
