CREATE PROCEDURE [pangya].[ProcGetItensPangRate]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @qntd int = 0

      SET @qntd = @qntd + pangya.GetCardPangRate(@IDUSER)

      SET @qntd = @qntd + pangya.GetItensPangRate(@IDUSER)

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported :  Aqui vai as roupas (Parts) que equipada da % de Exp rate
      *   mascot Pang - DESABILITADO que no mascot.iff tem o rate lá
      *   SET @mascot := (SELECT mascot_id FROM pangya_user_equip WHERE UID = IDUSER);
      *       
      *       SET @TYPEID_MASC := (SELECT typeid FROM pangya_mascot_info WHERE UID = IDUSER AND item_id = @mascot AND EndDate > NOW());
      *       
      *       CASE @TYPEID_MASC
      *   		WHEN 0x40000002 THEN	# Cocoa
      *   			SET qntd = qntd + 20;
      *   		WHEN 0x40000027 THEN	# Pangya Ninja Kun
      *   			SET qntd = qntd + 10;
      *   		WHEN 0x4000003B THEN	# Tricks Pets
      *   			SET qntd = qntd + 10; # +20 em tempo de Halloween
      *   		ELSE
      *           BEGIN
      *           END;
      *       END CASE;
      *
      */

      SELECT @qntd AS PANG_RATE_ITEM

   END
GO
