*/

CREATE PROCEDURE [pangya].[ProcGetItensSameTypeidDiffID]  
   @IDUSER int,
   @_typeid int,
   @_limit int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      SELECT TOP (@_limit) pangya_item_warehouse.item_id, pangya_item_warehouse.typeid
      FROM pangya.pangya_item_warehouse
      WHERE 
         pangya_item_warehouse.UID = @IDUSER AND 
         pangya_item_warehouse.valid = 1 AND 
         pangya_item_warehouse.Gift_flag <> 1 AND 
         pangya_item_warehouse.typeid = @_typeid AND 
         pangya_item_warehouse.item_id NOT IN 
         (
            SELECT td_char_equip_s4.ITEMID
            FROM pangya.td_char_equip_s4
            WHERE 
               td_char_equip_s4.UID = @IDUSER AND 
               td_char_equip_s4.USE_YN = 'Y' AND 
               td_char_equip_s4.EQUIP_TYPE = @_typeid
         )
         ORDER BY pangya_item_warehouse.item_id

   END
