/****** Objeto:  StoredProcedure [pangya].[ProcGetListGachaSystemPlayerItens]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetListGachaSystemPlayerItens]
	@UID INT,
	@PAGE INT,
	@TYPE INT,
	@TYPE_ITEM INT
AS
BEGIN
	IF @UID > 0 AND @PAGE >= 0
	BEGIN
		-- Declarando a variável @LINHAS
		DECLARE @LINHAS BIGINT;

		-- Total de linhas da consulta
		SELECT 
			@LINHAS = COUNT_BIG(a.[index])
		FROM 
			pangya.pangya_gacha_jp_player_win a
			INNER JOIN
			pangya.pangya_gacha_jp_all_item_list b
			ON a.typeid = b.typeid
		WHERE a.[UID] = @UID AND a.valid = 1 AND a.send_mail = 0
			AND (@TYPE = 1 -- Type 1 retorna todos os itens
			OR (@TYPE = 2 AND a.rarity_type = 0 AND ((@TYPE_ITEM = 100 AND b.char_type > 10/*Spika*/) OR @TYPE_ITEM = b.char_type)) -- Type 2 só retorna os raros, com o seu char_type
			OR (@TYPE = 3 AND a.rarity_type != 0 AND ((@TYPE_ITEM = 1 AND b.char_type = 11/*Aztec*/) OR (@TYPE_ITEM = 2 AND b.char_type != 11/*Aztec*/)))) -- Itens e Aztec

		SELECT 
			@LINHAS AS LINHAS,
			a.[index] AS ID,
			a.typeid AS TYPEID,
			a.qnty AS QNTD,
			b.[name] AS [NAME],
			c.[ICON] AS ITEM_ICON -- Adicione a nova coluna aqui
		FROM 
			pangya.pangya_gacha_jp_player_win a
			INNER JOIN
			pangya.pangya_gacha_jp_all_item_list b
			ON a.typeid = b.typeid
			INNER JOIN
			pangya.pangya_item_typelist c -- Novo JOIN para incluir a tabela pangya_item_typelist
			ON a.typeid = c.typeid -- Condição para o JOIN
		WHERE a.[UID] = @UID AND a.valid = 1 AND a.send_mail = 0
			AND (@TYPE = 1 -- Type 1 retorna todos os itens
			OR (@TYPE = 2 AND a.rarity_type = 0 AND ((@TYPE_ITEM = 100 AND b.char_type > 10/*Spika*/) OR @TYPE_ITEM = b.char_type)) -- Type 2 só retorna os raros, com o seu char_type
			OR (@TYPE = 3 AND a.rarity_type != 0 AND ((@TYPE_ITEM = 1 AND b.char_type = 11/*Aztec*/) OR (@TYPE_ITEM = 2 AND b.char_type != 11/*Aztec*/)))) -- Itens e Aztec
		ORDER BY b.REG_DATE DESC
		OFFSET (@PAGE * 50) ROWS
		FETCH NEXT 50 ROWS ONLY;
	END
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGetListGuild]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetListGuild]
	-- Add the parameters for the stored procedure here
	@PAGE INT,
	@CATEGORY INT,
	@SEARCH NVARCHAR(22),
	@SORT INT
AS
BEGIN
	
	IF @PAGE >= 0
	BEGIN

		DECLARE @LINHAS BIGINT = 0

		IF @CATEGORY = 0	-- GUILD NAME
		BEGIN

			SET @LINHAS = 

			-- Total de linhas da consulta
			(SELECT COUNT_BIG(a.GUILD_UID) AS LINHAS 
			FROM 
			pangya.pangya_guild a
			INNER JOIN
			pangya.account b
			ON a.GUILD_LEADER = b.[uid]
			WHERE 
				a.GUILD_NAME LIKE N'%' + @SEARCH + N'%'
				AND (a.GUILD_STATE NOT IN(4, 5) OR a.GUILD_CLOSURE_DATE IS NULL OR getdate() < a.GUILD_CLOSURE_DATE))

			SELECT 
				@LINHAS as LINHAS,
				a.GUILD_UID,
				a.GUILD_NAME,
				a.GUILD_MASTER,
				a.MEMBERS,
				a.GUILD_CONDITION_LEVEL,
				a.GUILD_STATE,
				a.GUILD_FLAG,
				a.GUILD_MARK_IMG_IDX,
				CAST(a.GUILD_REG_DATE as NVARCHAR(10)) as GUILD_REG_DATE
			FROM
				(
					SELECT	a.*,
							(SELECT COUNT_BIG(GUILD_UID) FROM pangya.pangya_guild_member WHERE GUILD_UID = a.GUILD_UID AND MEMBER_STATE_FLAG < 9) as MEMBERS,
							b.NICK as GUILD_MASTER
					FROM 
					pangya.pangya_guild a
					INNER JOIN
					pangya.account b
					ON a.GUILD_LEADER = b.[uid]
					WHERE 
						a.GUILD_NAME LIKE N'%' + @SEARCH + N'%'
						AND (a.GUILD_STATE NOT IN(4, 5) OR a.GUILD_CLOSURE_DATE IS NULL OR getdate() < a.GUILD_CLOSURE_DATE)
				) a
			ORDER BY
				CASE WHEN @SORT = 0 THEN a.GUILD_NAME ELSE null END,
				CASE WHEN @SORT = 1 THEN a.GUILD_MASTER ELSE null END,
				CASE WHEN @SORT = 2 THEN a.MEMBERS ELSE null END DESC,
				CASE WHEN @SORT = 3 THEN a.GUILD_CONDITION_LEVEL ELSE null END,
				CASE WHEN @SORT = 4 THEN a.GUILD_STATE ELSE null END,
				CASE WHEN @SORT = 5 THEN a.GUILD_FLAG ELSE null END,
				CASE WHEN @SORT = 6 THEN CAST(a.GUILD_REG_DATE as sql_variant) ELSE CAST(a.GUILD_REG_DATE as sql_variant) END DESC
				OFFSET (@PAGE * 12) ROWS
				FETCH NEXT 12 ROWS ONLY

		END
		ELSE	-- GUILD MASTER NICKNAME
		BEGIN

			SET @LINHAS = 

			-- Total de linhas da consulta
			(SELECT COUNT_BIG(a.GUILD_UID) AS LINHAS 
			FROM 
			pangya.pangya_guild a
			INNER JOIN
			pangya.account b
			ON a.GUILD_LEADER = b.[uid]
			WHERE 
				b.NICK LIKE N'%' + @SEARCH + N'%'
				AND (a.GUILD_STATE NOT IN(4, 5) OR a.GUILD_CLOSURE_DATE IS NULL OR getdate() < a.GUILD_CLOSURE_DATE))
			
			SELECT 
				@LINHAS as LINHAS,
				a.GUILD_UID,
				a.GUILD_NAME,
				a.GUILD_MASTER,
				a.MEMBERS,
				a.GUILD_CONDITION_LEVEL,
				a.GUILD_STATE,
				a.GUILD_FLAG,
				a.GUILD_MARK_IMG_IDX,
				CAST(a.GUILD_REG_DATE as NVARCHAR(10)) as GUILD_REG_DATE
			FROM
				(
					SELECT	a.*,
							(SELECT COUNT_BIG(GUILD_UID) FROM pangya.pangya_guild_member WHERE GUILD_UID = a.GUILD_UID AND MEMBER_STATE_FLAG < 9) as MEMBERS,
							b.NICK as GUILD_MASTER
					FROM 
					pangya.pangya_guild a
					INNER JOIN
					pangya.account b
					ON a.GUILD_LEADER = b.[uid]
					WHERE 
						b.NICK LIKE N'%' + @SEARCH + N'%'
						AND (a.GUILD_STATE NOT IN(4, 5) OR a.GUILD_CLOSURE_DATE IS NULL OR getdate() < a.GUILD_CLOSURE_DATE)
				) a
			ORDER BY
				CASE WHEN @SORT = 0 THEN a.GUILD_NAME ELSE null END,
				CASE WHEN @SORT = 1 THEN a.GUILD_MASTER ELSE null END,
				CASE WHEN @SORT = 2 THEN a.MEMBERS ELSE null END DESC,
				CASE WHEN @SORT = 3 THEN a.GUILD_CONDITION_LEVEL ELSE null END,
				CASE WHEN @SORT = 4 THEN a.GUILD_STATE ELSE null END,
				CASE WHEN @SORT = 5 THEN a.GUILD_FLAG ELSE null END,
				CASE WHEN @SORT = 6 THEN CAST(a.GUILD_REG_DATE as sql_variant) ELSE CAST(a.GUILD_REG_DATE as sql_variant) END DESC
				OFFSET (@PAGE * 12) ROWS
				FETCH NEXT 12 ROWS ONLY

		END	-- ELSE IFF CATEGORY

	END -- CHECK PAGE
	

END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGetListGuildBBS]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetListGuildBBS]
	-- Add the parameters for the stored procedure here
	@PAGE INT,
	@CATEGORY INT,
	@SEARCH NVARCHAR(22),
	@SORT INT
AS
BEGIN
	
	IF @PAGE >= 0
	BEGIN

		DECLARE @LINHAS BIGINT = 

		-- Total de linhas da consulta
		(SELECT 
			COUNT_BIG(a.SEQ) AS LINHAS
		FROM 
			pangya.pangya_guild_bbs a
		WHERE 
			[STATE] = 1 AND (@CATEGORY = 10 OR a.[TYPE] = @CATEGORY)
			AND a.TITLE LIKE N'%' + @SEARCH + N'%')

		SELECT
			@LINHAS as LINHAS,
			a.SEQ,
			a.[TYPE],
			a.TITLE,
			a.RES_COUNT,
			a.NICKNAME,
			CAST(a.REG_DATE AS NVARCHAR(10)) AS REG_DATE
		FROM
			(
				SELECT 
					a.SEQ,
					a.[TYPE],
					a.TITLE,
					(SELECT COUNT_BIG(SEQ) FROM pangya.pangya_guild_bbs_res WHERE BBS_SEQ = a.SEQ AND [STATE] = 1) AS RES_COUNT,
					(SELECT nick FROM pangya.account WHERE [UID] = a.OWNER_UID) AS NICKNAME,
					a.REG_DATE
				FROM 
					pangya.pangya_guild_bbs a
				WHERE 
					[STATE] = 1 AND (@CATEGORY = 10 OR a.[TYPE] = @CATEGORY)
					AND a.TITLE LIKE N'%' + @SEARCH + N'%'
			) a
		ORDER BY
			CASE WHEN @SORT = 0 THEN (SELECT MAX(REG_DATE) FROM pangya.pangya_guild_bbs_res WHERE BBS_SEQ = a.SEQ AND [STATE] = 1) ELSE null END DESC,
			CASE WHEN @SORT = 6 THEN a.REG_DATE ELSE a.REG_DATE END DESC,
			a.SEQ DESC
			OFFSET (@PAGE * 14) ROWS
			FETCH NEXT 14 ROWS ONLY

	END -- CHECK PAGE
END
GO
