-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetListGuildWeb]
	@OPT INT
AS
BEGIN
	
	SELECT
		a.GUILD_INTRO_IMG,
		a.GUILD_UID,
		a.GUILD_NAME,
		a.GUILD_MARK_IMG_IDX,
		a.GUILD_NEW_MARK_IDX,
		ISNULL((SELECT NICK FROM pangya.account WHERE [UID] = a.GUILD_LEADER), '') AS GUILD_MASTER,
		ISNULL((SELECT NICK FROM pangya.account WHERE [UID] = a.GUILD_SUB_MASTER), '') AS GUILD_SUB_MASTER,
		(SELECT COUNT_BIG(GUILD_UID) FROM pangya.pangya_guild_member WHERE GUILD_UID = a.GUILD_UID AND MEMBER_STATE_FLAG < 9) as MEMBERS,
		a.GUILD_CONDITION_LEVEL,
		a.GUILD_STATE,
		a.GUILD_FLAG,
		a.GUILD_PERMITION_JOIN,
		a.GUILD_POINT,
		a.GUILD_PANG,
		a.GUILD_INFO,
		a.GUILD_NOTICE,
		CAST(a.GUILD_REG_DATE AS NVARCHAR(19)) AS GUILD_REG_DATE,
		CAST(a.GUILD_ACCEPT_DATE AS NVARCHAR(19)) AS GUILD_ACCEPT_DATE,
		CAST(a.GUILD_CLOSURE_DATE AS NVARCHAR(19)) AS GUILD_CLOSURE_DATE
	FROM
		pangya.pangya_guild a
	WHERE
		@OPT = 0 OR (a.GUILD_STATE = 0/*pending*/ AND a.GUILD_MARK_IMG_IDX = 0 AND a.GUILD_NEW_MARK_IDX > 0
				 OR (a.GUILD_STATE < 3/*3 pra cima é guild bloqueado ou fechada*/ AND  a.GUILD_NEW_MARK_IDX > 0))
	ORDER BY a.GUILD_REG_DATE

END
GO
