*/

CREATE PROCEDURE [pangya].[ProcGetMapStatistics]  
   @IDUSER int,
   @tipo_in int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

	  IF @tipo_in < 10	-- Seta para zero por que está pedindo a season, aqui não implementei por que nao tem season anterior e o 5 é season atual
		SET @tipo_in = 0
      ELSE IF @tipo_in = 10
         SET @tipo_in = 51
      ELSE IF @tipo_in = 11
         SET @tipo_in = 52

      SELECT 
         pangya_record.UID, 
         pangya_record.tipo, 
         pangya_record.course, 
         pangya_record.tacada, 
         pangya_record.putt, 
         pangya_record.hole, 
         pangya_record.fairway, 
         pangya_record.holein, 
         pangya_record.puttin, 
         pangya_record.total_score, 
         pangya_record.best_score, 
         pangya_record.best_pang, 
         pangya_record.character_typeid, 
         pangya_record.event_score
      FROM pangya.pangya_record
      WHERE 
         pangya_record.UID = @IDUSER AND 
         (pangya_record.tipo = @tipo_in AND pangya_record.course < 22) AND 
         pangya_record.assist = 0
         ORDER BY pangya_record.course

   END
GO
