GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetMascotInfo]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA warning messages:
      *   M2SS0251: CASE statement returns expressions of different data types.This may lead to ambiguous results.
      */

      SELECT 
         pangya_mascot_info.item_id, 
         pangya_mascot_info.UID, 
         pangya_mascot_info.typeid, 
         pangya_mascot_info.mLevel, 
         pangya_mascot_info.mExp, 
         pangya_mascot_info.Flag, 
         pangya_mascot_info.Message, 
         pangya_mascot_info.Tipo, 
         pangya_mascot_info.IsCash, 
         pangya_mascot_info.EndDate
      FROM pangya.pangya_mascot_info
      WHERE 
         pangya_mascot_info.UID = @IDUSER AND 
         (
         CASE 
            WHEN Tipo = 1 THEN 
               CASE 
                  WHEN (pangya_mascot_info.EndDate >= getdate()) THEN 1
                  ELSE 0
               END
            ELSE 
               1
         END <> 0) AND 
         pangya_mascot_info.Valid = 1

   END
GO
