SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetMemorialNormalItemInfo]
	-- Add the parameters for the stored procedure here
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SELECT 
		a.typeid
	   ,a.tipo
	   ,CASE WHEN b.typeid IS NULL THEN a.typeid ELSE b.typeid END as item_typeid
	   ,CASE WHEN b.qntd IS NULL THEN a.qntd ELSE b.qntd END as item_qntd 
	FROM pangya.pangya_new_memorial_normal_item a
	LEFT OUTER JOIN
	pangya.pangya_new_memorial_lucky_set b
	ON a.typeid = b.set_id
	WHERE a.active = 1
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGetMemorialRareItemInfo]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [pangya].[ProcGetMemorialRareItemInfo]
AS
BEGIN
    SET NOCOUNT ON; -- Prevents the message about row count

    SELECT  
        a.tipo, 
        a.typeid,
        a.probabilidade,
        b.item_tipo,
        b.item_typeid,
        b.item_probabilidade,
        b.item_gacha_number 
    FROM pangya.pangya_new_memorial_coin a
    JOIN pangya.pangya_new_memorial_rare_item b 
        ON a.typeid = b.coin_typeid and b.item_active = 1
    ORDER BY  a.tipo, b.item_gacha_number -- Sorting by a.tipo first, then b.item_gacha_number
END;
GO
