CREATE PROCEDURE [pangya].[ProcGetMessageMemberInfo]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @u_id int = 0, 
         @unknown_1 int = 0, 
         @unknown_2 int = 0, 
         @unknown_3 int = 0, 
         @unknown_4 int = 0, 
         @unknown_5 int = 0, 
         @unknown_6 int = 0, 
         @flag_1 int = 0, 
         @flag_state int = 0, 
         @player_flag int = 0

      DECLARE
         @nickname nvarchar(23)

      DECLARE
         @apelido_in nvarchar(12)

      DECLARE
         @FINISHED int = 0

      /* 
      *   SSMA error messages:
      *   M2SS0075: Temporary tables are not supported 
      *   DROP  TEMPORARY 
      *   TABLE IF EXISTS `temp_msn`
      */



      /* 
      *   SSMA error messages:
      *   M2SS0195: DDL Statements are not valid in this context

      CREATE TABLE [pangya].temp_msn
      (
         nick nvarchar(23) NOT NULL, 
         uid int NOT NULL, 
         apelido nvarchar(12) NULL, 
         unknown1 int NULL, 
         unknown2 int NULL, 
         unknown3 int NULL, 
         unknown4 int NULL, 
         unknown5 int NULL, 
         unknown6 int NULL, 
         flag1 int NULL, 
         state_flag int NULL, 
         FLAG_PLAYER int NULL
      )      */



      /* 
      *   SSMA error messages:
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion

      DECLARE
          MSN_CURSOR CURSOR LOCAL FORWARD_ONLY FOR  
            SELECT 
               a.NICK, 
               b.uid_friend, 
               b.apelido, 
               b.unknown1, 
               b.unknown2, 
               b.unknown3, 
               b.unknown4, 
               b.unknown5, 
               b.unknown6, 
               b.flag1, 
               b.state_flag, 
               [@Flag] = 1 AS FLAG_PLAYER
            FROM pangya.account  AS a, pangya.pangya_friend_list  AS b
            WHERE b.uid = @IDUSER AND a.UID = b.uid_friend 
             UNION ALL
            /* 
            *   SSMA error messages:
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion

             (
               SELECT 
                  a.NICK, 
                  [@uid_fr] = c.MEMBER_UID AS uid_friend, 
                  [@apel] = N'' AS apelido, 
                  [@unk1] = -1 AS unknwon1, 
                  [@unk2] = 0 AS unknwon2, 
                  [@unk3] = -1 AS unknwon3, 
                  [@unk4] = 0 AS unknwon4, 
                  [@unk5] = 0 AS unknwon5, 
                  [@unk6] = 0 AS unknown6, 
                  [@flag1] = -1 AS flag1, 
                  [@frag4] = 0 AS state_flag, 
                  [@Flag] = 2 AS FLAG_PLAYER
               FROM pangya.account  AS a, pangya.pangya_guild_member  AS c
               WHERE 
                  c.GUILD_UID = 
                  (
                     SELECT i.Guild_UID
                     FROM pangya.account  AS i, pangya.pangya_guild_member  AS j
                     WHERE 
                        i.UID = @IDUSER AND 
                        i.Guild_UID = j.GUILD_UID AND 
                        j.MEMBER_UID = @IDUSER AND 
                        j.MEMBER_STATE_FLAG < 9
                  ) AND 
                  c.MEMBER_UID = a.UID AND 
                  c.MEMBER_STATE_FLAG <> 9
             )            */

      */



      /* 
      *   SSMA error messages:
      *   M2SS0267: The declaration of the identifier 'MSN_CURSOR' was converted with error(s).

      OPEN MSN_CURSOR      */



      /*
      *   SSMA informational messages:
      *   M2SS0003: The following SQL clause was ignored during conversion:
      *   MSN_LOOP : .
      *   M2SS0003: The following SQL clause was ignored during conversion:
      *   MSN_LOOP.
      */

      WHILE (1 = 1)
      
         BEGIN

            /* 
            *   SSMA error messages:
            *   M2SS0267: The declaration of the identifier 'MSN_CURSOR' was converted with error(s).

            FETCH MSN_CURSOR
                INTO 
                  @nickname, 
                  @u_id, 
                  @apelido_in, 
                  @unknown_1, 
                  @unknown_2, 
                  @unknown_3, 
                  @unknown_4, 
                  @unknown_5, 
                  @unknown_6, 
                  @flag_1, 
                  @flag_state, 
                  @player_flag            */



            IF @@FETCH_STATUS <> 0
               SET @FINISHED = 1

            IF @FINISHED = 1
               BREAK

            /* 
            *   SSMA error messages:
            *   M2SS0016: Identifier uid cannot be converted because it was not resolved.
            *   M2SS0016: Identifier temp_msn cannot be converted because it was not resolved.
            *   M2SS0016: Identifier UID cannot be converted because it was not resolved.

            IF 
               (
                  SELECT uid
                  FROM temp_msn
                  WHERE UID = @u_id
               ) IS NOT NULL
               /* 
               *   SSMA error messages:
               *   M2SS0016: Identifier temp_msn cannot be converted because it was not resolved.
               *   M2SS0016: Identifier FLAG_PLAYER cannot be converted because it was not resolved.
               *   M2SS0016: Identifier FLAG_PLAYER cannot be converted because it was not resolved.
               *   M2SS0016: Identifier UID cannot be converted because it was not resolved.

               UPDATE temp_msn
                  SET 
                     FLAG_PLAYER = FLAG_PLAYER + @player_flag
               WHERE UID = @u_id               */


            ELSE 
               /* 
               *   SSMA error messages:
               *   M2SS0289: Identifier temp_msn cannot be converted because it was not resolved.
               *   INSERT  INTO temp_msn
               *       VALUES (
               *         nickname, 
               *         u_id, 
               *         apelido_in, 
               *         unknown_1, 
               *         unknown_2, 
               *         unknown_3, 
               *         unknown_4, 
               *         unknown_5, 
               *         unknown_6, 
               *         flag_1, 
               *         flag_state, 
               *         player_flag)
               */

            */



         END

      /* 
      *   SSMA error messages:
      *   M2SS0267: The declaration of the identifier 'MSN_CURSOR' was converted with error(s).

      CLOSE MSN_CURSOR      */



      /* 
      *   SSMA error messages:
      *   M2SS0267: The declaration of the identifier 'MSN_CURSOR' was converted with error(s).

      DEALLOCATE MSN_CURSOR      */



      /* 
      *   SSMA error messages:
      *   M2SS0074: Select list item * cannot be converted.
      *   M2SS0016: Identifier temp_msn cannot be converted because it was not resolved.

      SELECT 
      FROM temp_msn      */



   END
