/****** Objeto:  StoredProcedure [pangya].[ProcGetNewAchievement]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [pangya].[ProcGetNewAchievement]
    @IDUSER int
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        a.active,
        a.TypeID,
        a.ID_ACHIEVEMENT,
        a.[status],
        b.id,
        b.typeid AS Quest_TypeID,
        COALESCE(d.TypeID, 0) AS Counter_TypeID,
        COALESCE(c.counter_item_id, 0) AS Counter_ID,
        COALESCE(d.Count_Num_Item, 0) AS Count_Num_item,
        COALESCE(CAST(dbo.UNIX_TIMESTAMP(b.[Date]) AS bigint), 0) AS Data_Sec
    FROM pangya.pangya_achievement a
    INNER JOIN pangya.pangya_quest b
        ON a.ID_ACHIEVEMENT = b.achievement_id
    OUTER APPLY (
        SELECT TOP 1 
            ISNULL(NULLIF(qs.counter_item_id, 0), sub_qs.min_counter_id) AS counter_item_id
        FROM pangya.pangya_quest qs
        LEFT JOIN (
            SELECT achievement_id, MIN(counter_item_id) AS min_counter_id
            FROM pangya.pangya_quest
            WHERE [uid] = @IDUSER AND counter_item_id <> 0
            GROUP BY achievement_id
        ) sub_qs ON qs.achievement_id = sub_qs.achievement_id
        WHERE qs.[uid] = @IDUSER AND qs.id = b.id
    ) c
    LEFT JOIN pangya.pangya_counter_item d
        ON c.counter_item_id = d.Count_ID
    WHERE a.[UID] = @IDUSER
    ORDER BY b.id;
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGetNewAuthServerKey]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetNewAuthServerKey] 
	-- Add the parameters for the stored procedure here
	@SERVER_UID INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	
	IF @SERVER_UID > 0
	BEGIN
		DECLARE @AUTH_KEY NVARCHAR(16)

		SELECT @AUTH_KEY = upper(convert(varchar(32), hashbytes('md5', convert(varchar(32), rand(), 2)), 2));

		IF NOT EXISTS(SELECT * FROM pangya.pangya_auth_key WHERE SERVER_UID = @SERVER_UID)
		BEGIN
			-- Make New Line
			INSERT INTO pangya.pangya_auth_key(SERVER_UID, [KEY], VALID) VALUES(@SERVER_UID, @AUTH_KEY, 1)
		END
		ELSE
		BEGIN
			UPDATE pangya.pangya_auth_key SET [KEY] = @AUTH_KEY, valid = 1
			WHERE [SERVER_UID] = @SERVER_UID
		END

		SELECT @AUTH_KEY AS NEW_AUTH_SERVER
	END
END
GO
