CREATE PROCEDURE [pangya].[ProcGetNewMemorialItem]
 @IDUSER int, @Coin_ID int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

		 SELECT DISTINCT C.* FROM 
    (SELECT b._typeid, b.probabilidade as prob, b.CoinID as ID, b.qntd, b.gacha_number, b.tipo
    FROM pangya.pangya_New_memorial_coin_item a, pangya.pangya_New_memorial_rare_item b
