/****** Objeto:  StoredProcedure [pangya].[ProcGetPlayerAsaState]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetPlayerAsaState]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @ANGEL int = 0, 
         @ASA int = 0

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported :  aqui é o quit rate
      *
      */

      DECLARE
         @ASA_STATE float(24) = 0.0

      /* 
      *   SSMA error messages:
      *   M2SS0109: The following expression may cause Division by Zero error
	  */

      SET @ASA_STATE = 
         (
            SELECT CASE WHEN user_info.Quitado > 0 THEN user_info.Quitado * 1.0 / user_info.Jogado * 100 ELSE 0.0 END as rate
            FROM pangya.user_info
            WHERE user_info.UID = @IDUSER
         )      



      IF @ASA_STATE < 3.0
         BEGIN

            SET @ASA = 
               (
                  /*
                  *   SSMA warning messages:
                  *   M2SS0219: Converted operator may not work exactly the same as in MySQL

                  *   SSMA informational messages:
                  *   M2SS0282: Binary value is converted to numeric value
                  *   M2SS0282: Binary value is converted to numeric value
                  *   M2SS0282: Binary value is converted to numeric value
                  *   M2SS0282: Binary value is converted to numeric value
                  *   M2SS0282: Binary value is converted to numeric value
                  *   M2SS0282: Binary value is converted to numeric value
                  *   M2SS0282: Binary value is converted to numeric value
                  *   M2SS0282: Binary value is converted to numeric value
                  *   M2SS0282: Binary value is converted to numeric value
                  *   M2SS0282: Binary value is converted to numeric value
                  *   M2SS0282: Binary value is converted to numeric value
                  *   M2SS0282: Binary value is converted to numeric value
                  *   M2SS0282: Binary value is converted to numeric value
                  */

                  SELECT a.EQUIP_TYPE
                  FROM pangya.td_char_equip_s4  AS a, pangya.pangya_user_equip  AS b
                  WHERE 
                     a.UID = @IDUSER AND 
                     a.CHAR_ITEMID = b.character_id AND 
                     a.EQUIP_TYPE IN ( 
                     134309888, 
                     134580224, 
                     134842368, 
                     135120896, 
                     135366656, 
                     135661568, 
                     135858176, 
                     136194048, 
                     136398848, 
                     136660992, 
                     137185294, 
                     137447424, 
                     138004480 )
               )

            IF @ASA <> 0
               SET @ANGEL = 1

         END

      SELECT 
         @ASA_STATE, 
         @ANGEL, 
         a.Sex, 
         b.level AS LEVEL, 
         b.Jogado AS GAME_COUNT
      FROM pangya.account  AS a, pangya.user_info  AS b
      WHERE a.UID = @IDUSER AND a.UID = b.UID

   END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGetPlayerCanWinGachaJPItens]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetPlayerCanWinGachaJPItens]
	-- Add the parameters for the stored procedure here
	@UID INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	IF @UID > 0
	BEGIN

		DECLARE @GACHA_NUM INT = ISNULL((SELECT gacha_num FROM pangya.pangya_gacha_jp_rate), 1)

		SELECT
			a.[index],
			a.gacha_num,
			a.rarity_type,
			a.typeid_1,
			a.qnty_1,
			(SELECT [name] FROM pangya.pangya_gacha_jp_all_item_list WHERE typeid = a.typeid_1) AS name_1,
			(SELECT char_type FROM pangya.pangya_gacha_jp_all_item_list WHERE typeid = a.typeid_1) AS char_type_1,
			a.typeid_2,
			a.qnty_2,
			(SELECT [name] FROM pangya.pangya_gacha_jp_all_item_list WHERE typeid = a.typeid_2) AS name_2,
			(SELECT char_type FROM pangya.pangya_gacha_jp_all_item_list WHERE typeid = a.typeid_2) AS char_type_2
		FROM
			pangya.pangya_gacha_jp_item_list a
		WHERE
			a.active = 1 AND (a.gacha_num = @GACHA_NUM OR a.gacha_num = -1)
			AND (a.rarity_type != 0 OR a.typeid_1 NOT IN(SELECT typeid FROM pangya.pangya_gacha_jp_player_win WHERE [UID] = @UID AND rarity_type = 0))

	END
END
GO
