-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetPlayerGachaSystemInfo]
	-- Add the parameters for the stored procedure here
	@UID INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	IF @UID > 0
	BEGIN
		SELECT 
			a.[UID],
			a.ID,
			a.NICK AS NICKNAME,
			b.[LEVEL],
			a.capability,
			a.IDState,
			ISNULL((SELECT top 1 c0 FROM pangya.pangya_item_warehouse WHERE [UID] = a.[UID] AND valid = 1 AND typeid = 0x1A000080), 0) AS TICKET,
			ISNULL((SELECT top 1 item_id FROM pangya.pangya_item_warehouse WHERE [UID] = a.[UID] AND valid = 1 AND typeid = 0x1A000080), -1) AS TICKET_ID,
			ISNULL((SELECT top 1 c0 FROM pangya.pangya_item_warehouse WHERE [UID] = a.[UID] AND valid = 1 AND typeid = 0x1A000083), 0) AS TICKET_SUB,
			ISNULL((SELECT top 1 item_id FROM pangya.pangya_item_warehouse WHERE [UID] = a.[UID] AND valid = 1 AND typeid = 0x1A000083), -1) AS TICKET_SUB_ID
		FROM 
			pangya.account a
			INNER JOIN
			pangya.user_info b
			ON a.[UID] = b.[UID]
		WHERE
			a.[UID] = @UID
	END
END
