/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetPlayerGuildAtividade]  
   @IDUSER int
AS
BEGIN

	IF @IDUSER > 0
	BEGIN
		
		SELECT TOP(8)
			ISNULL(c.GUILD_NAME, 'Unknown') AS GUILD_NAME,
			b.FLAG,
			CAST(b.REG_DATE AS NVARCHAR(10)) AS REG_DATE
		FROM
			pangya.account a
			INNER JOIN
			pangya.pangya_guild_atividade_player b
			ON a.[UID] = b.[UID]
			LEFT OUTER JOIN
			pangya.pangya_guild c
			ON c.Guild_UID = b.GUILD_UID
		WHERE a.[UID] = @IDUSER
		ORDER BY b.REG_DATE DESC

	END

END
GO
