-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetPlayerGuildInfo]
	-- Add the parameters for the stored procedure here
	@UID INT
AS
BEGIN
	
	IF @UID > 0
	BEGIN

		SELECT 
			a.[UID],
			a.ID,
			a.NICK AS NICKNAME,
			b.[LEVEL],
			a.capability,
			a.IDState,
			ISNULL(d.Guild_UID, 0) AS GUILD_UID,
			ISNULL(c.MEMBER_STATE_FLAG, -1) AS MEMBER_STATE_FLAG
		FROM 
			pangya.account a
			INNER JOIN
			pangya.user_info b
			ON a.[UID] = b.[UID]
			LEFT OUTER JOIN
			pangya.pangya_guild_member c
			ON a.Guild_UID = c.GUILD_UID AND a.[UID] = c.MEMBER_UID
			LEFT OUTER JOIN
			pangya.pangya_guild d
			ON d.GUILD_UID = a.Guild_UID AND (d.GUILD_STATE NOT IN(4, 5) OR d.GUILD_CLOSURE_DATE IS NULL OR getdate() < d.GUILD_CLOSURE_DATE)
		WHERE
			a.[UID] = @UID

	END
END
GO
