/****** Objeto:  StoredProcedure [pangya].[ProcGetPlayerInfoMessage]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetPlayerInfoMessage]
	-- Add the parameters for the stored procedure here
	@UID BIGINT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

   SELECT 
		a.[UID],
		a.id,
		a.nick,
		a.capability,
		ISNULL(c.guild_uid, 0) as guild_uid,
		ISNULL(c.GUILD_NAME, '') as guild_name,
		a.sex,
		b.[level],
		a.game_server_id,
		a.IDState,
		ISNULL(DATEDIFF(SECOND, getdate(), DATEADD(MINUTE, a.BlockTime, a.BlockRegDate)), -1 ) as BlockTime
	FROM
		pangya.account a
		INNER JOIN
		pangya.user_info b
		ON a.[UID] = b.[UID]
		LEFT OUTER JOIN
		(
			SELECT
				a.GUILD_UID,
				a.GUILD_NAME,
				b.MEMBER_UID
			FROM
				pangya.pangya_guild a
				INNER JOIN
				pangya.pangya_guild_member b
				ON a.GUILD_UID = b.GUILD_UID
			WHERE
				b.MEMBER_STATE_FLAG < 9
				AND (a.GUILD_STATE NOT IN(4, 5) OR a.GUILD_CLOSURE_DATE IS NULL OR getdate() < a.GUILD_CLOSURE_DATE)
		) c
		ON c.GUILD_UID = a.[GUILD_UID] AND c.MEMBER_UID = a.[UID]
	WHERE a.[UID] = @UID;
END
GO
