SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetPlayerLoginDados]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /* 
      *   SSMA error messages:
      *   M2SS0201: MySQL standard function UNIX_TIMESTAMP is not supported in current SSMA version*/

      SELECT 
         a.cap, 
         a.NICK, 
         a.IDState, 
         a.BlockTime, 
         b.[level], 
         ISNULL(c.[ip], N'') AS [ip]
      FROM 
         (
            
               /*
               *   SSMA warning messages:
               *   M2SS0250: Parameters used in N'ISNULL' function/operator are not of same data type so they are casted to Character datatype.
               */

               SELECT [uid], account.capability AS cap, account.NICK, account.IDState, ISNULL(dbo.UNIX_TIMESTAMP(DATEADD(MINUTE, BlockTime, BlockRegDate)), -1) AS BlockTime
               FROM pangya.account
               WHERE account.UID = @IDUSER
            )  AS a 
			INNER JOIN
            (
               SELECT [uid], user_info.[level]
               FROM pangya.user_info
               WHERE user_info.[UID] = @IDUSER
            )  AS b
			ON a.[uid] = b.[uid] 
            LEFT OUTER JOIN 
            (
               SELECT pangya_player_ip.[uid], pangya_player_ip.[ip]
               FROM pangya.pangya_player_ip
               WHERE pangya_player_ip.[uid] = @IDUSER
            )  AS c 
            ON c.[uid] = @IDUSER



   END
