-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetPlayerLuciaAttendanceInfo]
	@UID INT
AS
BEGIN
	
	IF @UID > 0
	BEGIN
		
		-- Verifica se o player já está cadastrado no sistema da lucia attendance, 
		-- se não tiver cria o cadastro ele liberado o ultimo dia
		IF (SELECT [UID] FROM pangya.pangya_lucia_attendance WHERE [UID] = @UID) IS NULL
			INSERT INTO pangya.pangya_lucia_attendance([UID], count_day) VALUES(@UID, 1)

		SELECT
			a.[UID],
			a.ID,
			a.NICK as NICKNAME,
			a.IDState,
			b.count_day,
			b.last_day_attendance,
			b.last_day_get_item,
			b.try_hacking_count,
			b.block_type,
			b.block_end_date
		FROM
			pangya.account a
			INNER JOIN
			pangya.pangya_lucia_attendance b
			ON a.[UID] = b.[UID]
		WHERE a.[UID] = @UID

	END
END
GO
