CREATE PROCEDURE [pangya].[ProcGetPremiumTicket]
	-- Add the parameters for the stored procedure here
	@IDUSER INT
AS
BEGIN
	SELECT TOP(1) item_id, typeid, dbo.UNIX_TIMESTAMP(ENDDATE) as unix_end_date, DATEDIFF(SECOND, CURRENT_TIMESTAMP, ENDDATE) as unix_sec_date FROM pangya.pangya_item_warehouse
					WHERE (typeid = 0x1A100002 OR typeid = 0x1A100003) AND valid = 1 AND APPLYTIME != ENDDATE AND uid = @IDUSER
END
