/****** Objeto:  StoredProcedure [pangya].[ProcGetRankPlayer]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetRankPlayer]  
   @PAGINA int,
   @tipo_rank_in int,
   @tipo_rank_seq_in int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @NUM_ROWS int = 0, 
         @TOTAL_PAGINA int = 0, 
         @INDEX int = 0, 
         @ROW int = 0

      DECLARE
         @LIMIT_PLAYER_PAG int = 12

      IF @tipo_rank_in >= 0
         BEGIN

            SET @PAGINA = 
               CASE 
                  WHEN (@PAGINA < 0) THEN 0
                  ELSE @PAGINA
               END

            SET @NUM_ROWS = 
               (
                  SELECT TOP (5000) count_big(*)
                  FROM pangya.pangya_rank_atual
                  WHERE pangya_rank_atual.tipo_rank = @tipo_rank_in AND pangya_rank_atual.tipo_rank_seq = @tipo_rank_seq_in
               )

            /* 
            *   SSMA error messages:
            *   M2SS0109: The following expression may cause Division by Zero error

            SET @TOTAL_PAGINA = floor(@NUM_ROWS * 1.0 / @LIMIT_PLAYER_PAG)            */



            /* 
            *   SSMA error messages:
            *   M2SS0109: The following expression may cause Division by Zero error

            IF ((@NUM_ROWS % @LIMIT_PLAYER_PAG) <> 0)
               SET @TOTAL_PAGINA = @TOTAL_PAGINA + 1            */



            /* 
            *   SSMA error messages:
            *   M2SS0016: Identifier IF cannot be converted because it was not resolved.

            SET @PAGINA = [IF]            */



            SET @ROW = @PAGINA * @LIMIT_PLAYER_PAG

            /* 
            *   SSMA error messages:
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion

            SELECT 
               @PAGINA, 
               @TOTAL_PAGINA AS paginas, 
               A.LAST_RANK, 
               A.NOW_RANK, 
               A.valor, 
               A.UID, 
               B.ID, 
               B.NICK, 
               D.valor AS LEVEL
            FROM 
               (
                  SELECT Z.UID, [@pos] = ISNULL(Y.position, 0)/*Z.POSITION*/ AS LAST_RANK, Z.position AS NOW_RANK, Z.valor
                  FROM 
                     (
                        SELECT 
                           pangya_rank_atual.[index], 
                           pangya_rank_atual.position, 
                           pangya_rank_atual.UID, 
                           pangya_rank_atual.tipo_rank, 
                           pangya_rank_atual.tipo_rank_seq, 
                           pangya_rank_atual.valor, 
                           pangya_rank_atual.reg_date
                        FROM pangya.pangya_rank_atual
                        WHERE pangya_rank_atual.tipo_rank = @tipo_rank_in AND pangya_rank_atual.tipo_rank_seq = @tipo_rank_seq_in
                     )  AS Z 
                        LEFT OUTER JOIN 
                        (
                           SELECT 
                              pangya_rank_antes.[index], 
                              pangya_rank_antes.position, 
                              pangya_rank_antes.UID, 
                              pangya_rank_antes.tipo_rank, 
                              pangya_rank_antes.tipo_rank_seq, 
                              pangya_rank_antes.valor, 
                              pangya_rank_antes.reg_date
                           FROM pangya.pangya_rank_antes
                           WHERE pangya_rank_antes.tipo_rank = @tipo_rank_in AND pangya_rank_antes.tipo_rank_seq = @tipo_rank_seq_in
                        )  AS Y 
                        ON Z.UID = Y.UID
               )  AS A, 
               pangya.account  AS B, 
               pangya.user_info  AS C, 
               pangya.pangya_rank_atual  AS D
            WHERE 
               A.UID = B.UID AND 
               A.UID = C.UID AND 
               D.UID = A.UID AND 
               D.tipo_rank = 2 AND 
               D.tipo_rank_seq = 3
               ORDER BY A.NOW_RANK
               OFFSET @ROW ROWS
               FETCH NEXT @LIMIT_PLAYER_PAG ROWS ONLY            */



         END
      ELSE 
         BEGIN

            SET @PAGINA = 
               CASE 
                  WHEN (@PAGINA < 0) THEN 0
                  ELSE @PAGINA
               END

            SET @NUM_ROWS = 
               (
                  SELECT count_big(*)
                  FROM pangya.account
               )

            /* 
            *   SSMA error messages:
            *   M2SS0109: The following expression may cause Division by Zero error

            SET @TOTAL_PAGINA = floor(@NUM_ROWS * 1.0 / @LIMIT_PLAYER_PAG)            */



            /* 
            *   SSMA error messages:
            *   M2SS0109: The following expression may cause Division by Zero error

            IF ((@NUM_ROWS % @LIMIT_PLAYER_PAG) <> 0)
               SET @TOTAL_PAGINA = @TOTAL_PAGINA - 1            */



            /* 
            *   SSMA error messages:
            *   M2SS0016: Identifier IF cannot be converted because it was not resolved.

            SET @PAGINA = [IF]            */



            SET @ROW = @PAGINA * @LIMIT_PLAYER_PAG

            SELECT 
               @PAGINA, 
               @TOTAL_PAGINA AS paginas, 
               0 AS LAST_RANK, 
               0 AS NOW_RANK, 
               A.UID, 
               A.ID, 
               A.NICK, 
               B.level, 
               B.Albatross AS VALOR
            FROM pangya.account  AS A, pangya.user_info  AS B
            WHERE A.UID = B.UID
               ORDER BY B.Albatross DESC, A.UID
               OFFSET @ROW ROWS
               FETCH NEXT @LIMIT_PLAYER_PAG ROWS ONLY

         END

   END
GO
