/****** Objeto:  StoredProcedure [pangya].[ProcGetScratchyCardTicket]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

/*
*   SSMA informational messages:
*   M2SS0134: Conversion of following Comment(s) is not supported : Retorna o ID do Scratchy card se usuario tiver
*
*/

CREATE PROCEDURE [pangya].[ProcGetScratchyCardTicket]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @IDITEM int = 0, 
         @QNTD int = 0, 
         @ITEMTYPEID int = 0

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported :  Ticket Scratchy Event  = 0x1A000030 
      *    Ticket Scratchy E      = 0x1A000033
      *    Ticket Scratchy Normal = 0x1A0000a3
      *
      */

      /*
      *   SSMA warning messages:
      *   M2SS0219: Converted operator may not work exactly the same as in MySQL

      *   SSMA informational messages:
      *   M2SS0282: Binary value is converted to numeric value
      *   M2SS0282: Binary value is converted to numeric value
      *   M2SS0282: Binary value is converted to numeric value
      */

      SELECT TOP (1) @IDITEM = pangya_item_warehouse.item_id, @ITEMTYPEID = pangya_item_warehouse.typeid, @QNTD = pangya_item_warehouse.C0
      FROM pangya.pangya_item_warehouse
      WHERE 
         pangya_item_warehouse.UID = @IDUSER AND 
         pangya_item_warehouse.C0 > 0 AND 
         pangya_item_warehouse.typeid IN ( 436207664, 436207667, 436207779 )
         ORDER BY pangya_item_warehouse.typeid

      IF @IDITEM > 0 AND @QNTD > 0
         BEGIN

            DECLARE
               @temp int

            SET @temp = -1

            EXECUTE pangya.USP_ADD_ITEM 
               @IDUSER, 
               0, 
               0, 
               @IDITEM, 
               @ITEMTYPEID, 
               0, 
               0, 
               @temp, 
               0, 
               0, 
               0, 
               0, 
               0, 
               0, 
               0, 
               0

            SELECT @IDITEM AS TICKET_ID

         END

   END
