/****** Objeto:  StoredProcedure [pangya].[ProcGetShopGiftLog]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- Criação da stored procedure
CREATE PROCEDURE [pangya].[ProcGetShopGiftLog]
    @IDUSER INT,
    @GIFT_ID INT
AS
BEGIN
    DECLARE @reg_date DATETIME;
    DECLARE @result INT;

    -- Obter a data de registro mais recente para o usuário e o presente específico
    SELECT TOP 1 @reg_date = reg_date
    FROM pangya.pangya_shop_gift_log
    WHERE uid = @IDUSER AND gift_id = @GIFT_ID
    ORDER BY reg_date DESC;

    -- Verificar se a data de registro é pelo menos um mês atrás
    IF @reg_date IS NULL
    BEGIN
        -- Se não houver registro, o jogador pode receber o presente
        SET @result = 1;
    END
    ELSE
    BEGIN
        -- Verificar a diferença entre a data atual e a data de registro
        IF DATEDIFF(DAY, @reg_date, GETDATE()) >= 30
        BEGIN
            SET @result = 1;
        END
        ELSE
        BEGIN
            SET @result = 0;
        END
    END

    -- Retornar o resultado
    SELECT @result AS can_receive;
END;
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGetShutdownServer]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetShutdownServer]
	-- Add the parameters for the stored procedure here
	@ID INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	--Get Shutdown Server
	DECLARE @SHUTDOWN_ID INT = 0
	DECLARE @REFRESH_TIME INT = 0

    SET @SHUTDOWN_ID = (SELECT arg1 FROM pangya_command WHERE command_id = 3 AND idx = @ID)
    
    UPDATE pangya_shutdown_list SET replayCount = replayCount - 1 WHERE id = @SHUTDOWN_ID
    
    IF (SELECT replayCount FROM pangya_shutdown_list WHERE id = @SHUTDOWN_ID) <= 0
		UPDATE pangya_command SET valid = 0 WHERE command_id = 3 AND idx = @ID
	ELSE
	BEGIN
		SET @REFRESH_TIME = (SELECT refreshTime FROM pangya_shutdown_list WHERE id = @SHUTDOWN_ID)
        
		UPDATE pangya_command SET reserveDate = dateadd(MINUTE, @REFRESH_TIME, getdate()) WHERE command_id = 3 AND idx = @ID
    END
    
	SELECT 
        datediff(SECOND, getdate(), date_shutdown) as sec
    FROM pangya_shutdown_list WHERE id = @SHUTDOWN_ID
END
GO
