-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGetTicker] 
	-- Add the parameters for the stored procedure here
	@ID INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	DECLARE @TICKER_ID INT = 0
	DECLARE @REFRESH_TIME INT = 0

	--#Pega o Ticker do pangya_command e pangya_ticker_list
    SET @TICKER_ID = (SELECT arg1 FROM pangya_command WHERE command_id = 1 AND idx = @ID)
    
    UPDATE pangya_ticker_list SET replayCount = replayCount - 1 WHERE ticker_id = @TICKER_ID
    
    IF (SELECT replayCount FROM pangya_ticker_list WHERE ticker_id = @TICKER_ID) <= 0
		UPDATE pangya_command SET valid = 0 WHERE command_id = 1 AND idx = @ID
	ELSE
	BEGIN
		SET @REFRESH_TIME = (SELECT refreshTime FROM pangya_ticker_list WHERE ticker_id = @TICKER_ID)
        
		UPDATE pangya_command SET reserveDate = DATEADD(MINUTE, @REFRESH_TIME, getdate()) WHERE command_id = 1 AND idx = @ID
    END
	
	SELECT [message], nick  FROM pangya_ticker_list WHERE ticker_id = @TICKER_ID
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGetTicketReportDados]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetTicketReportDados]  
   @ticket_report_id int
AS 
BEGIN

	IF @ticket_report_id > 0
	BEGIN

		SELECT 
			A.[idx],
			A.tipo, 
			A.trofel_typeid,
			A.reg_date,
			B.player_uid, 
			B.player_score, 
			B.player_medalha, 
			B.player_trofel, 
			B.player_pang, 
			B.player_bonus_pang, 
			B.player_exp, 
			B.player_mascot_typeid, 
			B.player_state, 
			B.flag_item_pang, 
			B.flag_premium_user, 
			D.[level], 
			C.ID, 
			C.NICK, 
			C.Guild_UID, 
			ISNULL(E.GUILD_MARK_IMG, 'guild_mark') as GUILD_MARK_IMG,
			ISNULL(E.GUILD_MARK_IMG_IDX, 0) AS GUILD_MARK_IMG_IDX,
			B.finish_date
		FROM 
			pangya.pangya_ticket_report A
			INNER JOIN 
			pangya.pangya_ticket_report_dados B
			ON A.[idx] = B.report_id
			INNER JOIN
			pangya.account C
			ON B.player_uid = C.[UID]
			INNER JOIN
			pangya.user_info D
			ON C.[UID] = D.[UID]
			LEFT OUTER JOIN
			pangya.pangya_guild E
			ON C.Guild_UID = E.GUILD_UID
		WHERE 
			A.[idx] = @ticket_report_id

	END

END
GO
