      DECLARE
         @TIKI_PTS int

      SELECT @TIKI_PTS = pangya_tiki_points.Tiki_Points
      FROM pangya.pangya_tiki_points
      WHERE pangya_tiki_points.UID = @IDUSER

      IF @TIKI_PTS IS NULL
