               VALUES (@IDUSER, 0, isnull(getdate(), getdate()), isnull(getdate(), getdate()))

            SELECT pangya_tiki_points.Tiki_Points AS TIKI_POINTS
            FROM pangya.pangya_tiki_points
            WHERE pangya_tiki_points.UID = @IDUSER

         END
      ELSE 
         SELECT @TIKI_PTS AS TIKI_POINTS

   END
