/****** Objeto:  StoredProcedure [pangya].[ProcGetUserInfo]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGetUserInfo]  
   @IDUSER int
AS 
BEGIN

  
	IF @IDUSER > 0
	BEGIN

		SELECT 
		A.ID, 
		A.[UID], 
		A.Sex, 
		A.doTutorial, 
		A.NICK, 
		A.School, 
		A.capability, 
		A.Logon, 
		A.ServerID, 
		A.MannerFlag, 
		(CASE WHEN A.LastLeaveTime IS NULL THEN 0 ELSE datediff(minute, A.LastLeaveTime, getdate()) END) AS TIMEVAL, 
		ISNULL(C.GUILD_NAME, N'') AS GUILD_NAME,
		ISNULL(C.GUILD_UID, 0) AS GUILD_UID,
		ISNULL(C.GUILD_PANG, 0) AS GUILD_PANG, 
		ISNULL(C.GUILD_POINT, 0) AS GUILD_POINT,
		ISNULL(C.GUILD_MARK_IMG_IDX, 0) AS GUILD_MARK_IMG_IDX, 
		A.[Event], 
		A.Event2, 
		D.limit_cnt, 
		A.IDState, 
		(CASE WHEN A.domainid IS NULL THEN 0 ELSE A.domainid END) AS DOMAINID, 
		A.ChannelFlag, 
		D.current_cnt, 
		D.remain_cnt, 
		D.last_update,
		B.[level],
		IIF(C.GUILD_MARK_IMG IS NULL OR C.MEMBER_STATE_FLAG > 3, N'', C.GUILD_MARK_IMG) AS GUILD_MARK_IMG,
		ISNULL(UPPER(C.GUILD_MARK_IMG), N'') AS EMBLERVER,
		ISNULL(UPPER(A.MacAddress), N'') AS MAC,
		ISNULL(A.UserIp, N'') AS UserIp
		FROM 
			pangya.account AS A 
			INNER JOIN
			pangya.pangya_papel_shop_info AS D
			ON A.[UID] = D.[UID]
			INNER JOIN
			pangya.user_info AS B 
			ON D.[UID] = B.[UID]
			INNER JOIN 
			(
				SELECT 
					E.GUILD_MARK_IMG_IDX,
					E.GUILD_MARK_IMG, 
					E.GUILD_UID, 
					E.GUILD_NAME, 
					E.MEMBER_STATE_FLAG, 
					E.GUILD_PANG, 
					E.GUILD_POINT, 
					D.[UID]
				FROM 
					pangya.account D 
					LEFT OUTER JOIN 
					(
						SELECT 
							x.GUILD_MARK_IMG_IDX,
							x.GUILD_MARK_IMG, 
							x.GUILD_UID, 
							x.GUILD_NAME, 
							y.MEMBER_STATE_FLAG, 
							y.GUILD_PANG, 
							y.GUILD_POINT
						FROM 
							pangya.pangya_guild AS x, 
							pangya.pangya_guild_member AS y
						WHERE 
							y.MEMBER_UID = @IDUSER
							AND y.MEMBER_STATE_FLAG < 9
							AND (x.GUILD_STATE NOT IN(4, 5) OR x.GUILD_CLOSURE_DATE IS NULL OR getdate() < x.GUILD_CLOSURE_DATE)
					) AS E 
					ON D.Guild_UID = E.GUILD_UID
			) AS C 
			ON C.[UID] = @IDUSER
		WHERE 
			A.[UID] = @IDUSER
	
	END

END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGetWareHouseItem]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [pangya].[ProcGetWareHouseItem]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA error messages:
      *   M2SS0135: Unparsed SQL*/
	   SELECT A.item_id, A.UID, A.typeid, A.Ano, A.C0, A.C1, A.C2, A.C3, A.C4, A.Purchase, A.Gift_flag, A.Flag, A.APPLY_DATE, A.END_DATE
         				,A.ItemType, B.CARD_CHARACTER_1, B.CARD_CHARACTER_2, B.CARD_CHARACTER_3, B.CARD_CHARACTER_4, B.CARD_CADDIE_1
         				,B.CARD_CADDIE_2, B.CARD_CADDIE_3, B.CARD_CADDIE_4, B.CARD_NPC_1, B.CARD_NPC_2, B.CARD_NPC_3, B.CARD_NPC_4
         				,A.ClubSet_WorkShop_Flag
         				,A.ClubSet_WorkShop_C0
         				,A.ClubSet_WorkShop_C1
         				,A.ClubSet_WorkShop_C2
         				,A.ClubSet_WorkShop_C3
         				,A.ClubSet_WorkShop_C4
         				,A.Mastery_Pts
         				,A.Recovery_Pts
         				,A.Level
         				,A.Up
         				,A.SD_NAME 
         				,A.SD_IDX
         				,A.SD_SEQ
         				,A.SD_COPIER_NICK
         				,A.SD_COPIER
         				,A.SD_TRADE
         				,A.SD_FLAG
         				,A.SD_STATUS
         	FROM
         		(
         			SELECT R.*,  CASE WHEN L.UCC_NAME IS NULL THEN N'' ELSE L.UCC_NAME END AS SD_NAME
         						     , CASE WHEN L.UCCIDX IS NULL THEN N'' ELSE L.UCCIDX END AS SD_IDX
         						     , CASE WHEN L.SEQ IS NULL THEN 0 ELSE L.SEQ END AS SD_SEQ
         						     , CASE WHEN L.COPIER_NICK IS NULL THEN N'' ELSE L.COPIER_NICK END AS SD_COPIER_NICK
         						     , CASE WHEN L.COPIER IS NULL THEN 0 ELSE L.COPIER END AS SD_COPIER
         						     , CASE WHEN L.TRADE IS NULL THEN 0 ELSE L.TRADE END AS SD_TRADE
         						     , CASE WHEN L.FLAG IS NULL THEN 0 ELSE L.FLAG END AS SD_FLAG
         						     , CASE WHEN L.STATUS IS NULL THEN 0 ELSE L.STATUS END AS SD_STATUS
         			FROM 
         			(
         				SELECT d.item_id
         				,d.UID
         				,d.typeid
         				, (CASE WHEN DATEDIFF(MINUTE, (CASE WHEN d.EndDate = d.Applytime THEN d.Applytime ELSE CURRENT_TIMESTAMP END), d.EndDate) > 0 THEN DATEDIFF(HOUR, CURRENT_TIMESTAMP, d.ENDDATE) ELSE -1 END) AS Ano
         				,/*ISNULL(E.c0,*/ D.c0--) AS C0
         				,/*ISNULL(E.c1,*/ D.c1--) AS C1
         				,/*ISNULL(E.c2,*/ D.c2--) AS C2
         				,/*ISNULL(E.c3,*/ D.c3--) AS C3
         				,/*ISNULL(E.c4,*/ D.c4--) AS C4
         				,(CASE WHEN DATEDIFF(MINUTE, d.applytime, d.ENDDATE) > 0 THEN dbo.UNIX_TIMESTAMP(d.applytime) ELSE 0 END) AS APPLY_DATE
         				,(CASE WHEN DATEDIFF(MINUTE, d.applytime, d.ENDDATE) > 0 THEN dbo.UNIX_TIMESTAMP(d.ENDDATE) ELSE 0 END) AS END_DATE --DATEDIFF(CURRENT_TIMESTAMP, regdate) as Date_Diff
         				,d.Gift_flag
         				,(CASE WHEN d.ENDDATE <= CURRENT_TIMESTAMP AND d.ApplyTime != d.ENDDATE THEN d.flag + 2 ELSE d.flag END) AS flag
         				,d.Purchase
         				,d.ItemType
         				,d.ClubSet_WorkShop_Flag
         				,d.ClubSet_WorkShop_C0
         				,d.ClubSet_WorkShop_C1
         				,d.ClubSet_WorkShop_C2
         				,d.ClubSet_WorkShop_C3
         				,d.ClubSet_WorkShop_C4
         				,d.Mastery_Pts
         				,d.Recovery_Pts
         				,d.Level
         				,d.Up
         				FROM 
         				(
         					SELECT * FROM pangya_item_warehouse 
         					WHERE UID = @IDUSER AND valid = 1 AND Gift_Flag = 0
         					AND (flag = 96 OR applytime = enddate OR typeid = 0x1A000042/*TICKET REPORT*/ OR enddate > CURRENT_TIMESTAMP)
         				)D
         				--LEFT OUTER JOIN
         				--(
         				--	SELECT * FROM pangya_clubset_enchant
         				--	WHERE UID = @IDUSER
         				--)E
         				--ON D.item_id = E.item_id
         			)R
         			INNER JOIN
         			(
         				SELECT  F.*,  G.UCC_NAME, G.UCCIDX, G.SEQ, G.COPIER, G.COPIER_NICK, G.TRADE, G.FLAG, G.STATUS
         				FROM 
         				(
         					SELECT item_id
         					FROM pangya_item_warehouse WHERE UID = @IDUSER AND valid = 1 AND Gift_Flag = 0
         				)F
         				LEFT OUTER JOIN
         				(
         					SELECT UCC_NAME, ITEM_ID, UCCIDX, SEQ, COPIER, COPIER_NICK, TRADE, Flag, STATUS
         					FROM TU_UCC
         				)G
         				ON F.item_id = G.item_id
         				--GROUP BY F.item_id
         			)L
         			ON R.item_id = L.item_id
         			--GROUP BY R.item_id
         		)A
         		INNER JOIN
         		(
         			SELECT 	item_id
         					, 0 AS CARD_CHARACTER_1
         					, 0 AS CARD_CHARACTER_2
         					, 0 AS CARD_CHARACTER_3
         					, 0 AS CARD_CHARACTER_4
         					, 0 AS CARD_CADDIE_1
         					, 0 AS CARD_CADDIE_2
         					, 0 AS CARD_CADDIE_3
         					, 0 AS CARD_CADDIE_4
         					, 0 AS CARD_NPC_1
         					, 0 AS CARD_NPC_2
         					, 0 AS CARD_NPC_3
         					, 0 AS CARD_NPC_4
         			FROM
         			(
         				SELECT item_id
         				FROM pangya_item_warehouse
         				WHERE UID = @IDUSER AND valid = 1 AND Gift_Flag = 0
         			)X
         			LEFT OUTER JOIN
         			(
         				SELECT TIPO, Slot, card_typeid, parts_id
         				FROM pangya_card_equip
         				WHERE UID = @IDUSER AND USE_YN = 1
         			)Y
         			ON Y.parts_id = X.item_id
         			GROUP BY item_id
         		) AS B
         	ON A.item_id = B.item_id
         	ORDER BY A.item_id
      



   END
GO
