                     D.Level, 
                     D.Up
                  FROM 
                     (
                        SELECT 
                           pangya_item_warehouse.item_id, 
                           pangya_item_warehouse.UID, 
                           pangya_item_warehouse.typeid, 
                           pangya_item_warehouse.valid, 
                           pangya_item_warehouse.regdate, 
                           pangya_item_warehouse.Gift_flag, 
                           pangya_item_warehouse.flag, 
                           pangya_item_warehouse.Applytime, 
                           pangya_item_warehouse.EndDate, 
                           pangya_item_warehouse.C0, 
                           pangya_item_warehouse.C1, 
                           pangya_item_warehouse.C2, 
                           pangya_item_warehouse.C3, 
                           pangya_item_warehouse.C4, 
                           pangya_item_warehouse.Purchase, 
                           pangya_item_warehouse.ItemType, 
                           pangya_item_warehouse.ClubSet_WorkShop_Flag, 
                           pangya_item_warehouse.ClubSet_WorkShop_C0, 
                           pangya_item_warehouse.ClubSet_WorkShop_C1, 
                           pangya_item_warehouse.ClubSet_WorkShop_C2, 
                           pangya_item_warehouse.ClubSet_WorkShop_C3, 
                           pangya_item_warehouse.ClubSet_WorkShop_C4, 
                           pangya_item_warehouse.Mastery_Pts, 
                           pangya_item_warehouse.Recovery_Pts, 
                           pangya_item_warehouse.Level, 
                           pangya_item_warehouse.Up, 
                           pangya_item_warehouse.Total_Mastery_Pts, 
                           pangya_item_warehouse.Mastery_Gasto
                        FROM pangya.pangya_item_warehouse
                        WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.Gift_flag = 0
                     )  AS D                  */


               )  AS R 
                  INNER JOIN 
                  (
                     SELECT 
                        F.item_id, 
                        G.UCC_NAME, 
                        G.UCCIDX, 
                        G.SEQ, 
                        G.COPIER, 
                        G.COPIER_NICK, 
                        G.TRADE, 
                        G.Flag, 
                        G.STATUS
                     FROM 
                        (
                           SELECT pangya_item_warehouse.item_id
                           FROM pangya.pangya_item_warehouse
                           WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.Gift_flag = 0
                        )  AS F 
                           LEFT OUTER JOIN 
                           (
                              SELECT 
                                 tu_ucc.UID, 
                                 tu_ucc.TYPEID, 
                                 tu_ucc.UCCIDX, 
                                 tu_ucc.SEQ, 
                                 tu_ucc.UCC_NAME, 
                                 tu_ucc.USE_YN, 
                                 tu_ucc.IN_DATE, 
                                 tu_ucc.COPIER, 
                                 tu_ucc.ITEM_ID, 
                                 tu_ucc.COPIER_NICK, 
                                 tu_ucc.DRAW_DT, 
                                 tu_ucc.STATUS, 
                                 tu_ucc.Flag, 
                                 tu_ucc.SKEY, 
                                 tu_ucc.TRADE
                              FROM pangya.tu_ucc
                           )  AS G 
                           ON F.item_id = G.ITEM_ID
                     GROUP BY F.item_id
                  )  AS L 
                  ON R.item_id = L.item_id
            GROUP BY R.item_id
         )  AS A 
            INNER JOIN 
            (
               /* 
               *   SSMA error messages:
               *   M2SS0198: SSMA for MySQL  does not support user variables conversion
               *   M2SS0198: SSMA for MySQL  does not support user variables conversion
               *   M2SS0198: SSMA for MySQL  does not support user variables conversion
               *   M2SS0198: SSMA for MySQL  does not support user variables conversion
               *   M2SS0198: SSMA for MySQL  does not support user variables conversion
               *   M2SS0198: SSMA for MySQL  does not support user variables conversion
               *   M2SS0198: SSMA for MySQL  does not support user variables conversion
               *   M2SS0198: SSMA for MySQL  does not support user variables conversion
               *   M2SS0198: SSMA for MySQL  does not support user variables conversion
               *   M2SS0198: SSMA for MySQL  does not support user variables conversion
               *   M2SS0198: SSMA for MySQL  does not support user variables conversion
               *   M2SS0198: SSMA for MySQL  does not support user variables conversion

               SELECT 
                  X.item_id, 
                  [@CARD_CHARCTER_1] = max(
                     CASE 
                        WHEN Y.Tipo = 0 AND Y.Slot = 1 THEN Y.card_typeid
                        ELSE 0
                     END) AS CARD_CHARACTER_1, 
                  [@CARD_CHARCTER_2] = max(
                     CASE 
                        WHEN Y.Tipo = 0 AND Y.Slot = 2 THEN Y.card_typeid
                        ELSE 0
                     END) AS CARD_CHARACTER_2, 
                  [@CARD_CHARCTER_3] = max(
                     CASE 
                        WHEN Y.Tipo = 0 AND Y.Slot = 3 THEN Y.card_typeid
                        ELSE 0
                     END) AS CARD_CHARACTER_3, 
                  [@CARD_CHARCTER_4] = max(
                     CASE 
                        WHEN Y.Tipo = 0 AND Y.Slot = 4 THEN Y.card_typeid
                        ELSE 0
                     END) AS CARD_CHARACTER_4, 
                  [@CARD_CADDIE_1] = max(
                     CASE 
                        WHEN Y.Tipo = 1 AND Y.Slot = 1 THEN Y.card_typeid
                        ELSE 0
                     END) AS CARD_CADDIE_1, 
                  [@CARD_CADDIE_2] = max(
                     CASE 
                        WHEN Y.Tipo = 1 AND Y.Slot = 2 THEN Y.card_typeid
                        ELSE 0
                     END) AS CARD_CADDIE_2, 
                  [@CARD_CADDIE_3] = max(
                     CASE 
                        WHEN Y.Tipo = 1 AND Y.Slot = 3 THEN Y.card_typeid
                        ELSE 0
                     END) AS CARD_CADDIE_3, 
                  [@CARD_CADDIE_4] = max(
                     CASE 
                        WHEN Y.Tipo = 1 AND Y.Slot = 4 THEN Y.card_typeid
                        ELSE 0
                     END) AS CARD_CADDIE_4, 
                  [@CARD_NPC_1] = max(
                     CASE 
                        WHEN Y.Tipo = 5 AND Y.Slot = 1 THEN Y.card_typeid
                        ELSE 0
                     END) AS CARD_NPC_1, 
                  [@CARD_NPC_2] = max(
                     CASE 
                        WHEN Y.Tipo = 5 AND Y.Slot = 2 THEN Y.card_typeid
                        ELSE 0
                     END) AS CARD_NPC_2, 
                  [@CARD_NPC_3] = max(
                     CASE 
                        WHEN Y.Tipo = 5 AND Y.Slot = 3 THEN Y.card_typeid
                        ELSE 0
                     END) AS CARD_NPC_3, 
                  [@CARD_NPC_4] = max(
                     CASE 
                        WHEN Y.Tipo = 5 AND Y.Slot = 4 THEN Y.card_typeid
                        ELSE 0
                     END) AS CARD_NPC_4
               FROM 
                  (
                     SELECT pangya_item_warehouse.item_id
                     FROM pangya.pangya_item_warehouse
                     WHERE 
                        pangya_item_warehouse.UID = @IDUSER AND 
                        pangya_item_warehouse.Gift_flag = 0 AND 
                        pangya_item_warehouse.item_id = @IDITEM
                  )  AS X 
                     LEFT OUTER JOIN 
                     (
                        SELECT pangya_card_equip.Tipo, pangya_card_equip.Slot, pangya_card_equip.card_typeid, pangya_card_equip.parts_id
                        FROM pangya.pangya_card_equip
                        WHERE pangya_card_equip.UID = @IDUSER AND pangya_card_equip.USE_YN = 1
                     )  AS Y 
                     ON Y.parts_id = X.item_id
               GROUP BY X.item_id               */


            )  AS B 
            ON A.item_id = B.item_id
         ORDER BY A.typeid      */



   END
