CREATE PROCEDURE [pangya].[ProcGetWebUserInfo]
    @IDUSER INT
AS
BEGIN
    SET NOCOUNT ON;

    -- =========================================================================================
    -- BLOCO 1: CONSULTA PARA USUÁRIO ESPECÍFICO (@IDUSER > 0)
    -- =========================================================================================
    IF @IDUSER > 0
    BEGIN

        SELECT
            A.ID, A.[UID], A.Sex, A.doTutorial, A.NICK, ISNULL(A.change_nick, '') AS 'last_nick',
            A.School, A.capability, A.Logon,ISNULL(A.game_server_id, '0') as 'game_server_id', A.MannerFlag,
            (CASE WHEN A.LastLeaveTime IS NULL THEN 0 ELSE datediff(minute, A.LastLeaveTime, getdate()) END) AS TIMEVAL,

            -- C (Guild) fields - Protegido (Lógica original de Guild para um único usuário)
            ISNULL(C.GUILD_NAME, N'') AS GUILD_NAME,
            ISNULL(C.GUILD_UID, 0) AS GUILD_UID,
            ISNULL(C.GUILD_PANG, 0) AS GUILD_PANG,
            ISNULL(C.GUILD_POINT, 0) AS GUILD_POINT,
            ISNULL(C.GUILD_MARK_IMG_IDX, 0) AS GUILD_MARK_IMG_IDX,
            A.[Event], A.Event2,

            -- D (pangya_papel_shop_info) fields - PROTEGIDO (LEFT JOIN)
            ISNULL(D.limit_cnt, 0) AS limit_cnt,
            A.IDState,
            ISNULL(A.BlockTime, 0) AS BlockTime,
            (CASE WHEN A.domainid IS NULL THEN 0 ELSE A.domainid END) AS DOMAINID,
            A.ChannelFlag,
            ISNULL(D.current_cnt, 0) AS current_cnt,
            ISNULL(D.remain_cnt, 0) AS remain_cnt,
            D.last_update,

            -- B (user_info) fields - PROTEGIDO (LEFT JOIN)
            ISNULL(B.[level], 0) AS [level],
            ISNULL(B.[Pang], 0) AS [Pang],
            ISNULL(B.[Cookie], 0) AS [Cookie],

            -- E (contas_beta) fields - PROTEGIDO (LEFT JOIN)
            ISNULL(UPPER(E.Email), N'') AS Email,
            E.Birthday,
            ISNULL(UPPER(E.NomeCompleto), N'') AS full_name,

            -- C (Guild) - Proteção contra NULL
            IIF(C.GUILD_MARK_IMG IS NULL OR C.MEMBER_STATE_FLAG > 3, N'', C.GUILD_MARK_IMG) AS GUILD_MARK_IMG,
            ISNULL(UPPER(C.GUILD_MARK_IMG), N'') AS EMBLERVER,

            -- A (account) fields
            ISNULL(UPPER(A.MacAddress), N'') AS MAC,
            ISNULL(A.UserIp, N'') AS UserIp,
            A.[FIRST_LOGIN] AS firstlogin,
            A.[FIRST_SET] AS firstset,

            -- L (pangya_player_location) fields - PROTEGIDO (LEFT JOIN)
            ISNULL(L.lobby, 0) AS lobby,
            ISNULL(L.room, 0) AS room,
            ISNULL(L.place, 0) AS place,

            A.logonCount,

            -- F (pangya_attendance_reward) fields - PROTEGIDO (LEFT JOIN)
            ISNULL(F.[counter], 0) AS [counter],
            A.LastLogonTime
        FROM
            pangya.account AS A

            -- Todos os Joins auxiliares mudaram para LEFT OUTER JOIN para proteção
            LEFT OUTER JOIN pangya.pangya_player_location AS L ON A.[UID] = L.[UID]
            LEFT OUTER JOIN pangya.pangya_attendance_reward AS F ON A.[UID] = F.[UID]
            LEFT OUTER JOIN pangya.pangya_papel_shop_info AS D ON A.[UID] = D.[UID]
            LEFT OUTER JOIN pangya.user_info AS B ON A.[UID] = B.[UID] -- Ligado A.[UID] diretamente
            LEFT OUTER JOIN pangya.contas_beta AS E ON E.LoginID = A.ID

            -- Subquery de Guild C (Mantida a complexidade original, mas garantindo proteção ISNULL nos campos)
            INNER JOIN 
            (
                SELECT 
                    E.GUILD_MARK_IMG_IDX, E.GUILD_MARK_IMG, E.GUILD_UID, E.GUILD_NAME, 
                    E.MEMBER_STATE_FLAG, E.GUILD_PANG, E.GUILD_POINT, D.[UID]
                FROM
                    pangya.account D
                    LEFT OUTER JOIN
                    (
                        SELECT 
                            x.GUILD_MARK_IMG_IDX, x.GUILD_MARK_IMG, x.GUILD_UID, x.GUILD_NAME,
                            y.MEMBER_STATE_FLAG, y.GUILD_PANG, y.GUILD_POINT
                        FROM
                            pangya.pangya_guild AS x
                            INNER JOIN pangya.pangya_guild_member AS y ON x.GUILD_UID = y.GUILD_UID
                        WHERE
                            y.MEMBER_UID = @IDUSER
                            AND y.MEMBER_STATE_FLAG < 9
                            AND (x.GUILD_STATE NOT IN(4, 5) OR x.GUILD_CLOSURE_DATE IS NULL OR getdate() < x.GUILD_CLOSURE_DATE)
                    ) AS E ON D.Guild_UID = E.GUILD_UID
            ) AS C ON C.[UID] = @IDUSER
            
        WHERE
            A.[UID] = @IDUSER
    END
    -- =========================================================================================
    -- BLOCO 2: CONSULTA PARA TODOS OS USUÁRIOS (@IDUSER <= 0 ou ELSE)
    -- =========================================================================================
    ELSE
    BEGIN
        SELECT
            A.ID, A.[UID], A.Sex, A.doTutorial, A.NICK, ISNULL(A.change_nick, '') AS 'last_nick',
            A.School, A.capability, A.Logon,ISNULL(A.game_server_id, '0') as 'game_server_id', A.MannerFlag,
            (CASE WHEN A.LastLeaveTime IS NULL THEN 0 ELSE datediff(minute, A.LastLeaveTime, getdate()) END) AS TIMEVAL,

            -- C (Guild) fields - PROTEGIDO (LEFT JOIN simplificado para performance em ALL)
            ISNULL(C.GUILD_NAME, N'') AS GUILD_NAME,
            ISNULL(C.GUILD_UID, 0) AS GUILD_UID,
            ISNULL(C.GUILD_PANG, 0) AS GUILD_PANG,
            ISNULL(C.GUILD_POINT, 0) AS GUILD_POINT,
            ISNULL(C.GUILD_MARK_IMG_IDX, 0) AS GUILD_MARK_IMG_IDX,
            
            A.[Event], A.Event2,

            -- D (pangya_papel_shop_info) fields - PROTEGIDO (LEFT JOIN)
            ISNULL(D.limit_cnt, 0) AS limit_cnt,
            A.IDState,
            ISNULL(A.BlockTime, 0) AS BlockTime,
            (CASE WHEN A.domainid IS NULL THEN 0 ELSE A.domainid END) AS DOMAINID,
            A.ChannelFlag,
            ISNULL(D.current_cnt, 0) AS current_cnt,
            ISNULL(D.remain_cnt, 0) AS remain_cnt,
            a.RegDate,

            -- B (user_info) fields - PROTEGIDO (LEFT JOIN)
            ISNULL(B.[level], 0) AS [level],
            ISNULL(B.[Pang], 0) AS [Pang],
            ISNULL(B.[Cookie], 0) AS [Cookie],

            -- E (contas_beta) fields - PROTEGIDO (LEFT JOIN)
            ISNULL(UPPER(E.Email), N'') AS Email,
            E.Birthday,
            ISNULL(UPPER(E.NomeCompleto), N'') AS full_name,

            -- C (Guild) - Proteção contra NULL
            IIF(C.GUILD_MARK_IMG IS NULL OR C.MEMBER_STATE_FLAG > 3, N'', C.GUILD_MARK_IMG) AS GUILD_MARK_IMG,
            ISNULL(UPPER(C.GUILD_MARK_IMG), N'') AS EMBLERVER,

            -- A (account) fields
            ISNULL(UPPER(A.MacAddress), N'') AS MAC,
            ISNULL(A.UserIp, N'') AS UserIp,
            A.[FIRST_LOGIN] AS firstlogin,
            A.[FIRST_SET] AS firstset,

            -- L (pangya_player_location) fields - PROTEGIDO (LEFT JOIN)
            ISNULL(L.lobby, 0) AS lobby,
            ISNULL(L.room, 0) AS room,
            ISNULL(L.place, 0) AS place,

            A.logonCount,

            -- F (pangya_attendance_reward) fields - PROTEGIDO (LEFT JOIN)
            ISNULL(F.[counter], 0) AS [counter],
            A.LastLogonTime
        FROM
            pangya.account AS A

            -- Todos os Joins auxiliares mudaram para LEFT OUTER JOIN para proteção
            LEFT OUTER JOIN pangya.pangya_player_location AS L ON A.[UID] = L.[UID]
            LEFT OUTER JOIN pangya.pangya_attendance_reward AS F ON A.[UID] = F.[UID]
            LEFT OUTER JOIN pangya.pangya_papel_shop_info AS D ON A.[UID] = D.[UID]
            LEFT OUTER JOIN pangya.user_info AS B ON A.[UID] = B.[UID]
            LEFT OUTER JOIN pangya.contas_beta AS E ON E.LoginID = A.ID
            
            -- LEFT JOIN para Guilds (C) - Lógica de Guild otimizada para todas as contas
            LEFT JOIN (
                SELECT
                    y.MEMBER_UID, x.GUILD_MARK_IMG_IDX, x.GUILD_MARK_IMG, x.GUILD_UID,
                    x.GUILD_NAME, y.MEMBER_STATE_FLAG, y.GUILD_PANG, y.GUILD_POINT
                FROM
                    pangya.pangya_guild AS x
                    INNER JOIN pangya.pangya_guild_member AS y
                        ON x.GUILD_UID = y.GUILD_UID
                WHERE
                    y.MEMBER_STATE_FLAG < 9
                    AND (x.GUILD_STATE NOT IN (4,5) OR x.GUILD_CLOSURE_DATE IS NULL OR GETDATE() < x.GUILD_CLOSURE_DATE)
            ) AS C ON C.MEMBER_UID = A.[UID]
            
            -- SEM CLÁUSULA WHERE para retornar todos os registros.
    END
END
GO
