/****** Objeto:  StoredProcedure [pangya].[ProcGetWTELog]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [pangya].[ProcGetWTELog] 
   @IDUSER INT,
   @OPT INT
AS
BEGIN
    SET NOCOUNT ON; 
    DECLARE @GIFT INT = 0;

    IF @OPT = 0
    BEGIN 
        -- Verifica se o registro já existe
        IF NOT EXISTS (
            SELECT 1 
            FROM pangya.pangya_world_tour_event_log 
            WHERE UID = @IDUSER
        )
        BEGIN
            -- Insere o registro caso não exista
            INSERT INTO pangya.pangya_world_tour_event_log (UID, SendGift, Finish_Data) 
            VALUES (@IDUSER, 1, GETDATE());
            SET @GIFT = 1;
        END
        ELSE
        BEGIN
            -- Registro já existe, retorna SendGift
            SET @GIFT = ISNULL((SELECT SendGift FROM pangya.pangya_world_tour_event_log WHERE UID = @IDUSER), 0);
        END
    END
    ELSE
    BEGIN 
        -- Apenas retorna o valor de SendGift ou 0 se o registro não existir
        SET @GIFT = ISNULL((SELECT SendGift FROM pangya.pangya_world_tour_event_log WHERE UID = @IDUSER), 0);
    END

    SELECT @GIFT AS GIFT;
END
GO
