/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcGrandPrixClearPlayer]  
   @IDUSER int,
   @typeid_in int,
   @flag_in int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @PLACE int = 0

      IF 
         (
            SELECT pangya_grandprix_clear.typeid
            FROM pangya.pangya_grandprix_clear
            WHERE pangya_grandprix_clear.uid = @IDUSER AND pangya_grandprix_clear.typeid = @typeid_in
         ) IS NULL
         BEGIN

            INSERT pangya.pangya_grandprix_clear(pangya.pangya_grandprix_clear.uid, pangya.pangya_grandprix_clear.typeid, pangya.pangya_grandprix_clear.flag)
               VALUES (@IDUSER, @TYPEID_IN, @FLAG_IN)

            SET @PLACE = @FLAG_IN

         END
      ELSE 
         BEGIN
            IF 
               (
                  SELECT pangya_grandprix_clear.flag
                  FROM pangya.pangya_grandprix_clear
                  WHERE pangya_grandprix_clear.uid = @IDUSER AND pangya_grandprix_clear.typeid = @typeid_in
               ) > @flag_in
               BEGIN

                  UPDATE pangya.pangya_grandprix_clear
                     SET 
                        FLAG = @FLAG_IN
                  WHERE pangya_grandprix_clear.uid = @IDUSER AND pangya_grandprix_clear.typeid = @TYPEID_IN

                  SET @PLACE = @FLAG_IN

               END
         END

      SELECT @PLACE

   END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGuildAcceptMark]    Data do Script: 03/05/2026 15:40:48 ******/
