CREATE PROCEDURE [pangya].[ProcGuildAceitaPedido]
	@OWNER_UID INT,	-- Quem fez a Ação
	@IDUSER int,
	@UID_GUILD int
AS 
BEGIN

	UPDATE pangya.pangya_guild_member
		SET 
		MEMBER_STATE_FLAG = 3
	WHERE GUILD_UID = @UID_GUILD AND MEMBER_UID = @IDUSER

	INSERT pangya.pangya_guild_atividade_player([UID], GUILD_UID, [FLAG])
		VALUES (@IDUSER, @UID_GUILD, 3)

	-- Cria log de update para o Game Server verificar e pedir para o Message Server Atualize os Membros do Club
	INSERT INTO pangya_guild_update_activity(GUILD_UID, OWNER_UPDATE, PLAYER_UID, TYPE_UPDATE) VALUES(@UID_GUILD, @OWNER_UID, @IDUSER, 0/*Accept Member*/)
END
