-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGuildBlock]
	-- Add the parameters for the stored procedure here
	@GUILD_UID INT
AS
BEGIN
	
	DECLARE @RET INT = -1

	IF @GUILD_UID > 0
	BEGIN

		IF (SELECT GUILD_UID FROM pangya.pangya_guild WHERE [GUILD_UID] = @GUILD_UID AND GUILD_STATE IN(0, 1, 2)) IS NOT NULL
		BEGIN
			
			DECLARE @GUILD_MASTER INT = (SELECT GUILD_LEADER FROM pangya.pangya_guild WHERE [GUILD_UID] = @GUILD_UID)

			IF @GUILD_MASTER IS NOT NULL
			BEGIN

				UPDATE
					pangya.pangya_guild
						SET GUILD_STATE = 3 -- GM bloqueou a Guild
				WHERE [GUILD_UID] = @GUILD_UID

				-- Insert Activity
				INSERT INTO pangya.pangya_guild_atividade_player(GUILD_UID, [UID], [FLAG])
				VALUES(@GUILD_UID, @GUILD_MASTER, 16)

				-- Sucesso
				SET @RET = 1

			END

		END
		ELSE
			SET @RET = -2	-- A guild já está bloqueada

	END

	SELECT @RET AS RET
END
