CREATE PROCEDURE [pangya].[ProcGuildCancelaPedido]  
   @IDUSER int,
   @UID_GUILD int
AS 
   BEGIN

      UPDATE pangya.account
         SET 
            GUILD_UID = 0
      WHERE [UID] = @IDUSER

      DELETE 
      FROM pangya.pangya_guild_member
      WHERE GUILD_UID = @UID_GUILD AND MEMBER_UID = @IDUSER

