/****** Objeto:  StoredProcedure [pangya].[ProcGuildChangeAuthorityMember]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGuildChangeAuthorityMember]
	-- Add the parameters for the stored procedure here
	@GUILD_UID INT,
	@MEMBER_UID INT,
	@MEMBER_AUTHORITY INT
AS
BEGIN
	-- Ret value
	DECLARE @RET INT = -1
	
	IF @GUILD_UID > 0 AND @MEMBER_UID > 0 AND @MEMBER_AUTHORITY >= 0
	BEGIN

		DECLARE @FLAG INT = (SELECT MEMBER_STATE_FLAG FROM pangya.pangya_guild_member WHERE GUILD_UID = @GUILD_UID AND MEMBER_UID = @MEMBER_UID)
		
		IF @FLAG IS NOT NULL
		BEGIN

			IF @FLAG != @MEMBER_AUTHORITY
			BEGIN

				DECLARE @OLD_SUB_MASTER INT = (SELECT GUILD_SUB_MASTER FROM pangya.pangya_guild WHERE [GUILD_UID] = @GUILD_UID)
			
				IF @OLD_SUB_MASTER IS NOT NULL
				BEGIN
					
					IF @MEMBER_AUTHORITY = 2 -- SUB MASTER
					BEGIN

						-- Update Member Authority
						UPDATE
							pangya.pangya_guild_member
								SET MEMBER_STATE_FLAG = @MEMBER_AUTHORITY
						WHERE 
							GUILD_UID = @GUILD_UID AND MEMBER_UID = @MEMBER_UID

						-- Update Guild Sub Master
						UPDATE
							pangya.pangya_guild
								SET GUILD_SUB_MASTER = @MEMBER_UID
						WHERE [GUILD_UID] = @GUILD_UID

						-- Activity member new Sub Master
						INSERT INTO pangya.pangya_guild_atividade_player(GUILD_UID, [UID], FLAG)
						VALUES(@GUILD_UID, @MEMBER_UID, 12/*Promovido a subMaster*/)

						-- Verifica se tinha um Sub Master para atualizar o state dele
						IF @OLD_SUB_MASTER > 0
						BEGIN
							
							UPDATE
								pangya.pangya_guild_member
									SET MEMBER_STATE_FLAG = 3 -- Member
							WHERE [GUILD_UID] = @GUILD_UID AND MEMBER_UID = @OLD_SUB_MASTER

							-- Activity old Sub Master to member
							INSERT INTO pangya.pangya_guild_atividade_player(GUILD_UID, [UID], [FLAG])
							VALUES(@GUILD_UID, @OLD_SUB_MASTER, 13/*Despromovido*/)
						END

					END
					ELSE	-- Membro
					BEGIN
						
						-- Update Member Authority
						UPDATE
							pangya.pangya_guild_member
								SET MEMBER_STATE_FLAG = @MEMBER_AUTHORITY
						WHERE 
							GUILD_UID = @GUILD_UID AND MEMBER_UID = @MEMBER_UID

						-- Update Guild Sub Master
						UPDATE
							pangya.pangya_guild
								SET GUILD_SUB_MASTER = 0	-- Nenhum Master
						WHERE [GUILD_UID] = @GUILD_UID

						-- Activity member new Sub Master
						INSERT INTO pangya.pangya_guild_atividade_player(GUILD_UID, [UID], FLAG)
						VALUES(@GUILD_UID, @MEMBER_UID, 13/*Despromovido*/)

					END

					SET @RET = 1	-- Trocou autoridade do membro com sucesso

				END

			END
			ELSE
				SET @RET = -2	-- Ele já é subMaster ou Membro
		END
	END

	SELECT @RET AS RET
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGuildClosure]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGuildClosure] 
	-- Add the parameters for the stored procedure here
	@GUILD_UID INT,
	@MASTER_UID INT
AS
BEGIN
	
	DECLARE @RET INT = -1

	IF @GUILD_UID > 0 AND @MASTER_UID >= 0
	BEGIN

		IF (SELECT GUILD_UID FROM pangya.pangya_guild WHERE [GUILD_UID] = @GUILD_UID AND ((@MASTER_UID = 0 AND GUILD_STATE IN(0, 1, 2, 3)) OR (@MASTER_UID > 0 AND GUILD_STATE IN(0, 1, 2)))) IS NOT NULL
		BEGIN

			-- Dias que a guild vai ficar em estado de fechamento antes de fechar
			DECLARE @DIAS INT = 7

			IF @MASTER_UID = 0	-- GM Fechou a guild
			BEGIN

				DECLARE @GUILD_MASTER INT = (SELECT GUILD_LEADER FROM pangya.pangya_guild WHERE [GUILD_UID] = @GUILD_UID)
			
				IF @GUILD_MASTER IS NOT NULL
				BEGIN

					UPDATE
						pangya.pangya_guild
							SET GUILD_STATE = 5, -- GM FECHOU A GUILD
								GUILD_CLOSURE_DATE = DATEADD(DAY, @DIAS, getdate())
					WHERE [GUILD_UID] = @GUILD_UID

					-- Insert Activity Player
					INSERT INTO pangya.pangya_guild_atividade_player(GUILD_UID, [UID], [FLAG])
					VALUES(@GUILD_UID, @GUILD_MASTER, 17)

					-- Sucesso
					SET @RET = 1

				END

			END
			ELSE
			BEGIN
			
				UPDATE
					pangya.pangya_guild
						SET GUILD_STATE = 4,	-- Player fechou a guild
							GUILD_CLOSURE_DATE = DATEADD(DAY, @DIAS, getdate())
				WHERE [GUILD_UID] = @GUILD_UID AND GUILD_LEADER = @MASTER_UID

				-- Insert Activity Player
				INSERT INTO pangya.pangya_guild_atividade_player(GUILD_UID, [UID], [FLAG])
				VALUES(@GUILD_UID, @MASTER_UID, 9)

				-- Sucesso
				SET @RET = 1
					
			END
		END
		ELSE
			SET @RET = -2	-- A guild já está fechada

	END

	SELECT @RET AS RET
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGuildKickMember]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGuildKickMember] 
	-- Add the parameters for the stored procedure here
	@OWNER_UID INT,	-- Quem fez a Ação
	@MEMBER_UID INT,
	@GUILD_UID INT
AS
BEGIN
	
	IF @GUILD_UID > 0 AND @MEMBER_UID > 0
	BEGIN

		DECLARE @FLAG INT = (SELECT MEMBER_STATE_FLAG FROM pangya.pangya_guild_member WHERE GUILD_UID = @GUILD_UID AND MEMBER_UID = @MEMBER_UID)

		IF @FLAG IS NOT NULL
		BEGIN

			IF @FLAG = 2 -- SUB MASTER
				UPDATE pangya.pangya_guild SET GUILD_SUB_MASTER = 0 WHERE GUILD_UID = @GUILD_UID

			IF @FLAG = 9
				SET @FLAG = 4 -- Rejeita pedido para entrar na guild
			ELSE
				SET @FLAG = 6 -- Kick Member (Expulsa)
		
			-- Delete from table members of guild
			DELETE FROM
				pangya.pangya_guild_member
			WHERE 
				GUILD_UID = @GUILD_UID AND MEMBER_UID = @MEMBER_UID

			-- Update Guild of player in table account
			UPDATE
				pangya.account
					SET Guild_UID = 0
			WHERE [UID] = @MEMBER_UID

			-- Insert Ativity of player in table guild atividade
			INSERT INTO pangya.pangya_guild_atividade_player(GUILD_UID, [UID], [FLAG])
			VALUES(@GUILD_UID, @MEMBER_UID, @FLAG)

			IF @FLAG = 6 -- Kick Member (Expulsa)
			BEGIN
				-- Cria log de update para o Game Server verificar e pedir para o Message Server Atualize os Membros do Club
				INSERT INTO pangya_guild_update_activity(GUILD_UID, OWNER_UPDATE, PLAYER_UID, TYPE_UPDATE) VALUES(@GUILD_UID, @OWNER_UID, @MEMBER_UID, 2/*Kick Member*/)
			END
		END

	END
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcGuildMoveMaster]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcGuildMoveMaster] 
	-- Add the parameters for the stored procedure here
	@GUILD_UID INT,
	@MEMBER_UID INT
AS
BEGIN

	DECLARE @RET INT = -1
	
	IF @GUILD_UID > 0 AND @MEMBER_UID > 0
	BEGIN

		-- Verifica se o membro que vai virar master da guild tem o level de Rookie E pra cima
		DECLARE @LEVEL INT = (SELECT [level] FROM pangya.user_info WHERE [UID] = @MEMBER_UID)

		IF @LEVEL IS NOT NULL AND @LEVEL > 0
		BEGIN

			DECLARE @OLD_MASTER INT = (SELECT GUILD_LEADER FROM pangya.pangya_guild WHERE [GUILD_UID] = @GUILD_UID)
			DECLARE @OLD_SUB_MASTER INT = (SELECT GUILD_SUB_MASTER FROM pangya.pangya_guild WHERE [GUILD_UID] = @GUILD_UID)

			IF @OLD_MASTER IS NOT NULL AND @OLD_SUB_MASTER IS NOT NULL
			BEGIN

				-- Update Master of Guild
				UPDATE
					pangya.pangya_guild
						SET GUILD_LEADER = @MEMBER_UID
					WHERE
						GUILD_UID = @GUILD_UID

				-- Update Member state flag to Master
				UPDATE
					pangya.pangya_guild_member
						SET MEMBER_STATE_FLAG = 1 -- Master
				WHERE
					GUILD_UID = @GUILD_UID AND MEMBER_UID = @MEMBER_UID

				-- Update Old Master to member
				UPDATE
					pangya.pangya_guild_member
						SET MEMBER_STATE_FLAG = 3 -- Member
				WHERE
					GUILD_UID = @GUILD_UID AND MEMBER_UID = @OLD_MASTER

				-- Verifica se o membro que virou Master era Sub Master e tira o Sub Master da Guild
				IF @OLD_SUB_MASTER = @MEMBER_UID
				BEGIN

					UPDATE
						pangya.pangya_guild
							SET GUILD_SUB_MASTER = 0	-- Zera, não tem mais sub master, só master já que o master virou membro comun
					WHERE [GUILD_UID] = @GUILD_UID

				END

				-- Insert Activity of New Master
				INSERT INTO pangya.pangya_guild_atividade_player(GUILD_UID, [UID], [FLAG])
				VALUES(@GUILD_UID, @MEMBER_UID, 11/*Promovido a master*/)

				-- Insert Activity of Old Master to member
				INSERT INTO pangya.pangya_guild_atividade_player(GUILD_UID, [UID], [FLAG])
				VALUES(@GUILD_UID, @OLD_MASTER, 5/*Promote*/)

				-- Passou o master
				INSERT INTO pangya.pangya_guild_atividade_player(GUILD_UID, [UID], [FLAG])
				VALUES(@GUILD_UID, @OLD_MASTER, 10/*Passou o master*/)

				-- Sucesso
				SET @RET = 1

			END

		END
		ELSE
			SET @RET = -2

	END

	SELECT @RET AS RET
END
GO
