/****** Objeto:  StoredProcedure [pangya].[ProcInsertAchievementAll]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

/*
*   SSMA informational messages:
*   M2SS0134: Conversion of following Comment(s) is not supported : ADD 1 ACHIEVEMENT PARA TODOS
*
*/

CREATE PROCEDURE [pangya].[ProcInsertAchievementAll]  
   @TYPEID_ACHIEVE int,
   @TYPEID_QUEST int,
   @OBJECTIVO int,
   @OPT int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @IDUSER int

      DECLARE
         @ID_ACHIEVE int

      DECLARE
         @ID_COUNTER int

      DECLARE
         @FINISHED int = 0

      DECLARE
          UID_CURSOR CURSOR LOCAL FORWARD_ONLY FOR 
            SELECT account.UID
            FROM pangya.account

      OPEN UID_CURSOR

      /*
      *   SSMA informational messages:
      *   M2SS0003: The following SQL clause was ignored during conversion:
      *   ADD_ACHIEVE : .
      *   M2SS0003: The following SQL clause was ignored during conversion:
      *   
      *   / *
      *   *    Aqui é para a nova versão do achievement
      *   *   CALL USP_CreateAchievementUser(IDUSER);
      *   * / 
      *   ADD_ACHIEVE.
      */

      WHILE (1 = 1)
      
         BEGIN

            FETCH UID_CURSOR
                INTO @IDUSER

            IF @@FETCH_STATUS <> 0
               SET @FINISHED = 1

            IF @FINISHED = 1
               BREAK

            INSERT pangya.achievement_tipo(pangya.achievement_tipo.UID, pangya.achievement_tipo.TypeID, pangya.achievement_tipo.TIPO, pangya.achievement_tipo.[Option])
               VALUES (@IDUSER, @TYPEID_ACHIEVE, 1, @OPT)

            SELECT @ID_ACHIEVE = max(achievement_tipo.ID_ACHIEVEMENT)
            FROM pangya.achievement_tipo
            WHERE achievement_tipo.UID = @IDUSER

            INSERT pangya.achievement_quest(
               pangya.achievement_quest.UID, 
               pangya.achievement_quest.ID_ACHIEVEMENT, 
               pangya.achievement_quest.TypeID_ACHIEVE, 
               pangya.achievement_quest.Count_ID, 
               pangya.achievement_quest.Data_Sec, 
               pangya.achievement_quest.Objetivo_Quest)
               VALUES (
                  @IDUSER, 
                  @ID_ACHIEVE, 
                  @TYPEID_QUEST, 
                  0, 
                  0, 
                  @OBJECTIVO)

         END

      CLOSE UID_CURSOR

      DEALLOCATE UID_CURSOR

   END
GO
