/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

/*
*   SSMA informational messages:
*   M2SS0134: Conversion of following Comment(s) is not supported : INSERI OS ACHIEVEQUEST
*
*/

CREATE PROCEDURE [pangya].[ProcInsertAchievementQuest]  
   @IDUSER int,
   @ACHIEVEMENT_TYPEID int,
   @ACHIEVEMENT_QUEST_TYPEID int,
   @COUNTER_ITEM_TYPEID int,
   @OBJECTIVE int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @IDACHIEVE int, 
         @COUNT_ITEM_ID int

      SELECT @IDACHIEVE = achievement_tipo.ID_ACHIEVEMENT
      FROM pangya.achievement_tipo
      WHERE 
         achievement_tipo.UID = @IDUSER AND 
         achievement_tipo.TypeID = @ACHIEVEMENT_TYPEID AND 
         achievement_tipo.TIPO <> 2

      IF 
         (
            SELECT max(count_item.Count_ID)
            FROM pangya.count_item
            WHERE count_item.UID = @IDUSER AND count_item.TypeID = @COUNTER_ITEM_TYPEID
         ) IS NULL
         INSERT pangya.count_item(pangya.count_item.UID, pangya.count_item.TypeID, pangya.count_item.TIPO)
            VALUES (@IDUSER, @COUNTER_ITEM_TYPEID, 1)

      SELECT @COUNT_ITEM_ID = max(count_item.Count_ID)
      FROM pangya.count_item
      WHERE count_item.UID = @IDUSER AND count_item.TypeID = @COUNTER_ITEM_TYPEID

      INSERT pangya.achievement_quest(
         pangya.achievement_quest.UID, 
         pangya.achievement_quest.ID_ACHIEVEMENT, 
         pangya.achievement_quest.TypeID_ACHIEVE, 
         pangya.achievement_quest.Count_ID, 
         pangya.achievement_quest.Data_Sec, 
         pangya.achievement_quest.Objetivo_Quest)
         VALUES (
            @IDUSER, 
            @IDACHIEVE, 
            @ACHIEVEMENT_QUEST_TYPEID, 
            @COUNT_ITEM_ID, 
            0, 
            @Objective)

   END
