-- =============================================
-- Author: Your Name
-- Create date: 2024-01-04
-- Description: Inserts IP and mask into pangya.pangya_ip_table if they don't exist
-- =============================================
CREATE PROCEDURE [pangya].[ProcInsertBlockIP]
    -- Add the parameters for the stored procedure here
    @IP VARCHAR(40),
    @MASK VARCHAR(18)
AS
BEGIN
    -- Checking for non-empty IP and MASK
    IF @IP IS NOT NULL AND @MASK IS NOT NULL
    BEGIN
        -- Checking if the IP and MASK combination doesn't exist
        IF NOT EXISTS (SELECT 1 FROM pangya.pangya_ip_table WHERE [ip] = @IP AND mask = @MASK)
        BEGIN
            -- Inserting the IP and MASK
            INSERT INTO pangya.pangya_ip_table ([ip], mask) VALUES (@IP, @MASK)
        END
    END
END
GO
