-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcInsertCard]
	-- Add the parameters for the stored procedure here
	@IDUSER INT,
	@ITEMTYPEID INT,
	@QNTD INT,
	@CARDTYPE TINYINT	-- Esse aqui eu colocou ele como 1 sempre
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	DECLARE @ITEM_ID INT = -1

    IF @ITEMTYPEID > 0 AND (SELECT [UID] FROM pangya.account WHERE [UID] = @IDUSER) IS NOT NULL
	BEGIN
		SET @ITEM_ID = ISNULL((SELECT TOP 1 card_itemid FROM pangya.pangya_card WHERE [UID] = @IDUSER AND card_typeid = @ITEMTYPEID), -1)

		IF @ITEM_ID > 0 AND @ITEM_ID IS NOT NULL
		BEGIN
			UPDATE pangya.pangya_card SET QNTD = QNTD + @QNTD, USE_YN = N'N' WHERE [UID] = @IDUSER AND card_typeid = @ITEMTYPEID
		END
		ELSE
		BEGIN
			INSERT INTO pangya.pangya_card(UID, card_typeid, card_type, QNTD, GET_DT, USE_YN)
				VALUES(@IDUSER, @ITEMTYPEID, @CARDTYPE, @QNTD, getdate(), N'N')

			SET @ITEM_ID = @@IDENTITY
		END
	END

	SELECT @ITEM_ID AS ITEM_ID
END
GO
