CREATE PROCEDURE [pangya].[ProcInsertClubSet] 
	-- Add the parameters for the stored procedure here
	@IDUSER INT,
	@GIFTFLAG TINYINT,
	@PURCHASE TINYINT,
	@ITEMTYPEID INT,
	@FLAG TINYINT,
	@TEMPO INT,
	@WORKSHOP_LEVEL INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;
	DECLARE @ITEM_ID INT = -1

    -- Insert statements for procedure here
	IF @ITEMTYPEID > 0 AND (SELECT [UID] FROM pangya.account WHERE [UID] = @IDUSER) IS NOT NULL
	BEGIN
		IF @TEMPO > 0
		BEGIN
			INSERT INTO pangya.pangya_item_warehouse(UID, typeid, valid, regdate, EndDate, Gift_flag, flag, Purchase, ItemType, [Level])
				VALUES(@IDUSER, @ITEMTYPEID, 1, getdate(), DATEADD(DAY, @TEMPO, getdate()), @GIFTFLAG, @FLAG, @PURCHASE, 2, @WORKSHOP_LEVEL)
		END
		ELSE
		BEGIN
			INSERT INTO pangya.pangya_item_warehouse(UID, typeid, valid, regdate, Gift_flag, flag, Purchase, ItemType, [Level])
				VALUES(@IDUSER, @ITEMTYPEID, 1, getdate(), @GIFTFLAG, @FLAG, @PURCHASE, 2, @WORKSHOP_LEVEL)
		END

		SET @ITEM_ID = @@IDENTITY

		INSERT INTO pangya.pangya_clubset_enchant(UID, item_id) VALUES(@IDUSER, @ITEM_ID)
	END

	SELECT @ITEM_ID AS ITEM_ID
END
GO
