/****** Objeto:  StoredProcedure [pangya].[ProcInsertHioEvent]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


-- =============================================
-- Author:      <Author,,Name>
-- Create date: <Create Date,,>
-- Description: <Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcInsertHioEvent]
    -- Add the parameters for the stored procedure here
    @UID INT ,
    @PROCESS INT
AS
BEGIN 

    IF EXISTS (SELECT 1 FROM pangya.pangya_hio_event WHERE UID = @UID)
    BEGIN
         
        -- Update the record considering the current last_day
        UPDATE pangya.pangya_hio_event
        SET PROCESS_HIOS = PROCESS_HIOS + @PROCESS
        WHERE UID = @UID;
    END
    ELSE
    BEGIN
	SET @PROCESS = (select HIO from pangya.user_info where UID = @UID)
        -- Insert a new record if no existing record is found
        INSERT INTO pangya.pangya_hio_event (UID, [START_HIOS], [PROCESS_HIOS], [STATUS])
        VALUES (@UID, @PROCESS, 0, 0);
    END

    -- Select the updated or inserted record
	SELECT a.UID, a.NICK AS NICKNAME, a.ID, a.IDState, p.PROCESS_HIOS as MY_HOLE, p.START_HIOS as START_PROCESS, p.[STATUS] as STAGE
                      FROM pangya.account a
                      LEFT JOIN pangya.pangya_hio_event p ON a.UID = p.UID
                      WHERE a.UID = @UID;
END
GO
