-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcInsertRewardToDonate]
	-- Add the parameters for the stored procedure here
	@IDUSER INT,
	@CP INT
AS
BEGIN
	
	DECLARE @MSGID INT = 0

	INSERT INTO pangya.pangya_gift_table([UID], fromid, [message], giftdate, Lida_YN, valid, [Flag], Contador_Vista)
		VALUES(@IDUSER, '@Mania', CONCAT(N'Obrigado pela sua docao(donate), aqui vai uns premios para voce. E mais ', @CP, 'CP'),
			getdate(), 0, 1, 0, 0)

	SET @MSGID = @@IDENTITY

	IF @MSGID > 0
	BEGIN

		DECLARE @item_id int

		SET @item_id = -1

		EXEC pangya.ProcInsertItemNoEmail 0, @IDUSER, @MSGID, @item_id, 2080374803, 0, 1, 0
		EXEC pangya.ProcInsertItemNoEmail 0, @IDUSER, @MSGID, @item_id, 2084569107, 0, 1, 0
		EXEC pangya.ProcInsertItemNoEmail 0, @IDUSER, @MSGID, @item_id, 2084569113, 0, 1, 0
		EXEC pangya.ProcInsertItemNoEmail 0, @IDUSER, @MSGID, @item_id, 1879113856, 0, 1, 0
		EXEC pangya.ProcInsertItemNoEmail 0, @IDUSER, @MSGID, @item_id, 268435541, 0, 1, 0

		EXEC pangya.ProcInsertCommand 4, @IDUSER, @MSGID, 0, 0, 0, 1, 0, 1, null

		UPDATE pangya.user_info SET Cookie = Cookie + @CP WHERE [UID] = @IDUSER
	END
END
GO
