CREATE PROCEDURE [pangya].[ProcInsertRoomLog]
    @NAME VARCHAR(200),
	@PLAYERS INT,
	@MAX_PLAYERS INT,
	@TIPO_EX INT,
	@UID INT,  
    @ROOMID UNIQUEIDENTIFIER, 
    @CHARACTER INT,@CADDIE INT, @MASCOT INT, @CLUB INT,
    @TIPO INT,
    @MODO INT,
    @QNTD_HOLE INT,
    @COURSE INT,
    @HOLE INT,
    @SCORE NUMERIC,
    @EXP INT,
    @PANG BIGINT,
    @BONUS_PANG BIGINT,
    @TACADA_NUM INT,
    @TOTAL_TACADA_NUM INT,
    @GIVEUP INT,
    @TIMEOUT INT,
    @ENTER_AFTER_STARTED INT,
    @FINISH_GAME INT,
    @ASSIST_FLAG INT,
    @TROFEU INT,
    @Master INT,
    @Is_ShotGame INT,
    @Is_Natural INT,
    @hit_hio INT,
    @hit_alba INT,
    @hit_eagle INT,
    @hit_birdie INT,
    @hit_par INT,
    @hit_bogey INT,
    @hit_double_bogey INT,
    @hit_triple_bogey INT
AS 
BEGIN
    SET XACT_ABORT ON;
    SET NOCOUNT ON;

    INSERT INTO pangya.pangya_room_log ([Name],[Number_Players]
           ,[Max_Players]
           ,[TipoEx],
        UID, ROOMID, CHARACTER, CADDIE, MASCOT, CLUB, TIPO, MODO, QntdHole, COURSE, HOLE, SCORE, EXP, PANG, BonusPang, 
        TACADANUM, TOTALTACADANUM, GIVEUP, TIMEOUT, ENTERAFTERSTARTED, FINISHGAME, ASSISTFLAG, 
        TROFEU, Master_UID, NaturalMode, ShotMode, [Hio_Hit], [Alba_Hit], [Eagle_Hit], [Birdie_Hit], 
        [Par_Hit], [Bogey_Hit], [DoubleBogey_Hit], [TripleBogey_Hit]
    )
    VALUES (@NAME, @PLAYERS, @MAX_PLAYERS, @TIPO_EX,
        @UID, @ROOMID, @CHARACTER, @CADDIE, @MASCOT, @CLUB, @TIPO, @MODO, @QNTD_HOLE, @COURSE, @HOLE, @SCORE, @EXP, @PANG, 
        @BONUS_PANG, @TACADA_NUM, @TOTAL_TACADA_NUM, @GIVEUP, @TIMEOUT, @ENTER_AFTER_STARTED, 
        @FINISH_GAME, @ASSIST_FLAG, @TROFEU, @Master, @Is_Natural, @Is_ShotGame, @hit_hio, @hit_alba, 
        @hit_eagle, @hit_birdie, @hit_par, @hit_bogey, @hit_double_bogey, @hit_triple_bogey
    );

    SELECT RoomId 
    FROM pangya.pangya_room_log 
    WHERE UID = @UID AND RoomId = @ROOMID;
END
