/****** Objeto:  StoredProcedure [pangya].[ProcInsertSkin]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcInsertSkin]
	-- Add the parameters for the stored procedure here
	@IDUSER INT,
	@ITEMTYPEID INT,
	@FLAG TINYINT,
	@GIFTFLAG TINYINT,
	@PURCHASE TINYINT,
	@TEMPO INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    DECLARE @ITEM_ID INT = -1

	IF @ITEMTYPEID > 0 AND (SELECT [UID] FROM pangya.account WHERE [UID] = @IDUSER) IS NOT NULL
	BEGIN
		SET @ITEM_ID = ISNULL((SELECT item_id FROM pangya.pangya_item_warehouse WHERE [UID] = @IDUSER AND typeid = @ITEMTYPEID AND valid = 1), -1)

		DECLARE @regDT datetime2 = getdate()
		DECLARE @endDT datetime2 = @regDT

		IF @ITEM_ID > 0 AND @ITEM_ID IS NOT NULL
		BEGIN
			DECLARE @diff INT = 0

			SELECT @diff = case when DATEDIFF(SECOND, getdate(), EndDate) > 0 THEN 1 ELSE 0 END FROM pangya.pangya_item_warehouse WHERE [UID] = @IDUSER AND item_id = @ITEM_ID

			UPDATE pangya.pangya_item_warehouse SET EndDate = DATEADD(DAY, @TEMPO, (case when @diff = 1 THEN EndDate ELSE getdate() END)), C3 = C3 + @TEMPO
			WHERE [UID] = @IDUSER AND item_id = @ITEM_ID 
		END
		ELSE
		BEGIN
			IF @TEMPO > 0
				SET @endDT = DATEADD(DAY, @TEMPO, getdate())

			INSERT INTO pangya_item_warehouse(UID, typeid, valid, flag, Gift_flag, Purchase, ItemType, c3, regdate, EndDate)
				VALUES(@IDUSER, @ITEMTYPEID, 1, @FLAG, @GIFTFLAG, @PURCHASE, 2, @TEMPO, @regDT, @endDT)

			SET @ITEM_ID = @@IDENTITY
		END
	END

	SELECT @ITEM_ID AS ITEM_ID
END
GO
