/****** Objeto:  StoredProcedure [pangya].[ProcMakeEmailKey]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [pangya].[ProcMakeEmailKey] 
    @NomeCompleto nvarchar(100),
    @Birthday DATETIME = NULL,
    @Sexo SMALLINT,
    @Pergunta NVARCHAR(100),
    @Resposta NVARCHAR(120) = NULL,
    @EMAIL nvarchar(100),
    @id_in nvarchar(30),
    @pass_in nvarchar(40),
    @ip_in nvarchar(20)
AS
BEGIN
    SET NOCOUNT ON;

    -- 1. Validação básica de campos nulos
    IF @NomeCompleto IS NOT NULL AND @EMAIL IS NOT NULL AND @id_in IS NOT NULL
    BEGIN
        
        -- 2. Verificação de Duplicidade (Login ou Email)
        IF EXISTS (SELECT 1 FROM [pangya].[contas_beta] WHERE [LoginID] = @id_in OR [Email] = @EMAIL)
        BEGIN
            -- Retorna um select vazio ou um código específico para indicar erro de duplicidade
            SELECT -1 AS [index], CAST(0x0 AS UNIQUEIDENTIFIER) AS key_uniq;
            RETURN;
        END

        -- 3. Inserção se não houver duplicatas
        INSERT INTO [pangya].[contas_beta] (
            [NomeCompleto],
            [Birthday],
            [Email],
            [Sexo],
            [Pergunta],
            [Resposta],
            [LoginID],
            [Senha],
            [ip_register]
        )
        VALUES (
            @NomeCompleto, 
            @Birthday, 
            @EMAIL, 
            @Sexo, 
            @Pergunta, 
            @Resposta, 
            @id_in, 
            @pass_in, 
            @ip_in
        );
            
        -- 4. Retorno do ID gerado e da Chave
        DECLARE @id BIGINT;
        SET @id = SCOPE_IDENTITY(); 
        
        SELECT [index], key_uniq 
        FROM [pangya].[contas_beta] 
        WHERE [index] = @id;
    END
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcMakeGuild]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcMakeGuild]
	-- Add the parameters for the stored procedure here
	@NAME NVARCHAR(20),
	@MASTER INT,
	@CONDITION_LEVEL SMALLINT,
	@INTRO NVARCHAR(50),
	@MASTER_COMMENT NVARCHAR(50)
AS
BEGIN

	DECLARE @GUILD_UID INT = -1
	
	IF @NAME != N'' AND @MASTER != 0
	BEGIN

		DECLARE @OTHER_GUILD INT = (
			SELECT
				a.Guild_UID
			FROM
				pangya.account a
				INNER JOIN
				pangya.pangya_guild b
				ON a.Guild_UID = b.GUILD_UID
			WHERE a.[UID] = @MASTER AND 
				(b.GUILD_STATE NOT IN(4, 5) OR b.GUILD_CLOSURE_DATE IS NULL OR getdate() < b.GUILD_CLOSURE_DATE)
		)

		IF @OTHER_GUILD IS NULL
		BEGIN

			IF DATEDIFF(HOUR, ISNULL((SELECT MAX(REG_DATE) FROM pangya.pangya_guild_atividade_player WHERE [UID] = @MASTER AND [FLAG] = 8/*Create*/), DATEADD(DAY, -1, getdate())), getdate()) >= 24/*1 Dia*/
			BEGIN

				DECLARE @PANG BIGINT = (SELECT pang FROM pangya.user_info WHERE [UID] = @MASTER)
		
				-- Verifica se o player tem os 5k de pangs para criar a guild
				IF @PANG IS NOT NULL AND @PANG >= 5000
				BEGIN

					-- Delete ele de qualquer membro de guild que ele esteja, que o OTHER_GUILD é null, se ele estava em uma guild, ela já está fechada
					DELETE FROM pangya.pangya_guild_member WHERE [MEMBER_UID] = @MASTER

					-- Cria a Guild
					INSERT INTO pangya.pangya_guild(GUILD_NAME, GUILD_LEADER, GUILD_CONDITION_LEVEL, GUILD_INFO, GUILD_NOTICE, GUILD_NEW_MARK_IDX) 
					VALUES(@NAME, @MASTER, @CONDITION_LEVEL, @INTRO, @MASTER_COMMENT, 1)

					SET @GUILD_UID = @@IDENTITY

					-- Insert Member of guild
					INSERT INTO pangya.pangya_guild_member(GUILD_UID, MEMBER_UID, MEMBER_STATE_FLAG) VALUES(@GUILD_UID, @MASTER, 1/*Master*/)

					-- Update player account  GUILD_UID
					UPDATE
						pangya.account
							SET Guild_UID = @GUILD_UID
					WHERE [UID] = @MASTER

					-- Insert Log Activety of player guild
					INSERT INTO pangya.pangya_guild_atividade_player(GUILD_UID, [UID], [FLAG]) VALUES(@GUILD_UID, @MASTER, 8/*Criou uma Guild*/)

					-- Tira os 5k de pang que gastou para criar a guild
					UPDATE
						pangya.user_info
							SET pang = @PANG - 5000
					WHERE [UID] = @MASTER

					-- Sucesso
					SELECT GUILD_UID, GUILD_NEW_MARK_IDX FROM pangya.pangya_guild WHERE GUILD_UID = @GUILD_UID

				END
				ELSE
					SET @GUILD_UID = -3	-- Não tem pangs suficiente para criar a guild

			END
			ELSE
				SET @GUILD_UID = -2	-- Não pode criar a guild, faz menos de 24 horas que ele criou outra guild

		END
		ELSE
			SET @GUILD_UID = -4	-- Player já é membro de outra guild, saia dela para poder criar outra guild

	END

	SELECT @GUILD_UID AS GUILD_UID
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcMakeUserBeta]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [pangya].[ProcMakeUserBeta]
    @NomeCompleto nvarchar(100),
    @Birthday DATETIME = NULL,
    @Sexo SMALLINT,
    @Pergunta NVARCHAR(100),
    @Resposta NVARCHAR(120) = NULL,
    @email_in nvarchar(100),
    @id_in nvarchar(30),
    @pass_in nvarchar(40),
    @ip_in nvarchar(20)
AS 
BEGIN
    SET XACT_ABORT ON
    SET NOCOUNT ON

    DECLARE @IDUSER int = 0

    -- [TRAVA DE SEGURANÇA]
    -- Verifica se o ID já existe na tabela de contas oficial.
    -- Se já existir, apenas retornamos o UID existente em vez de tentar criar de novo.
    SELECT @IDUSER = [UID] FROM pangya.account WHERE ID = @id_in

    IF (@IDUSER > 0)
    BEGIN
        -- O usuário já foi criado (provavelmente por um clique duplo anterior).
        -- Retornamos o UID e encerramos para evitar erros de Primary Key.
        SELECT @IDUSER
        RETURN
    END

    -- Se chegou aqui, o usuário não existe. Iniciamos a transação.
    BEGIN TRANSACTION
        BEGIN TRY
            -- 1. Executa a criação do usuário
            EXECUTE pangya.ProcNewUser 
                @NomeCompleto, @Birthday, @Sexo, @Pergunta, 
                @Resposta, @id_in, @pass_in, @ip_in

            -- 2. Recupera o UID (Usa o ID que acabamos de criar)
            SET @IDUSER = (SELECT [UID] FROM pangya.account WHERE ID = @id_in)

            -- 3. Associa o UID na tabela de controle beta
            UPDATE [pangya].[contas_beta] 
            SET uid = @IDUSER 
            WHERE LoginID = @id_in
            
            -- 4. Insere o registro de IP
            INSERT INTO pangya.pangya_player_ip([uid], [ip])
            VALUES (@IDUSER, @ip_in)

            COMMIT TRANSACTION
            
            -- 5. Retorna o ID para a aplicação
            SELECT @IDUSER
        END TRY
        BEGIN CATCH
            IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION
            
            -- Retorna 0 ou erro para a aplicação saber que falhou
            SELECT 0
        END CATCH
END
GO
/****** Objeto:  StoredProcedure [pangya].[ProcMakeUserBetaWithMD5]    Data do Script: 03/05/2026 15:40:48 ******/
