-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcMakeUserBetaWithMD5]  
   @id_in nvarchar(30),
   @pass_in nvarchar(40),
   @index nvarchar(100),
   @sex tinyint,
   @ip_in nvarchar(20)
AS 
BEGIN

	-- SET  XACT_ABORT  ON

	--SET  NOCOUNT  ON

	DECLARE
		@IDUSER int = 0

	IF (SELECT key_uniq FROM pangya.contas_beta WHERE [index] = @index AND finish_reg = 0) IS NOT NULL
	BEGIN

		EXECUTE pangya.ProcNewUserWithMD5 @id_in, @pass_in, @sex, @ip_in, 0

		SELECT @IDUSER = account.[UID]
		FROM pangya.account
		WHERE account.ID = @id_in

		UPDATE pangya.contas_beta SET [UID] = @IDUSER, [ip_register] = @ip_in, finish_reg = 1 WHERE [index] = @index

		INSERT pangya.pangya_player_ip(pangya.pangya_player_ip.[uid], pangya.pangya_player_ip.[ip])
			VALUES (@IDUSER, @ip_in)

		SELECT @IDUSER AS [UID]
	END
	ELSE
		SELECT -1 AS [UID]

END
GO
