/****** Objeto:  StoredProcedure [pangya].[ProcMoveItemFromMailToArmario_Old]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

/*
*   SSMA informational messages:
*   M2SS0134: Conversion of following Comment(s) is not supported : Move Item(s) do Mail Box Para o My Room do Usuario
*
*/

CREATE PROCEDURE [pangya].[ProcMoveItemFromMailToArmario_Old]  
   @IDUSER int,
   @IDMSG int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @ITEMID int, 
         @TYPE_ID int, 
         @QNTD int, 
         @QNTDDIA int

      DECLARE
         @FINISHED int = 0

      /* 
      *   SSMA error messages:
      *   M2SS0075: Temporary tables are not supported 
      *   DROP  TEMPORARY 
      *   TABLE IF EXISTS `TEMP_TYPEID`
      */



      /* 
      *   SSMA error messages:
      *   M2SS0195: DDL Statements are not valid in this context

      CREATE TABLE pangya.temp_typeid
      (
         ITEM_ID int NOT NULL, 
         TYPEID int NOT NULL, 
         QUANTIDADE int NOT NULL, 
         QNTD_DIA int NOT NULL
      )      */



      UPDATE pangya.pangya_gift_table
         SET 
            Lida_YN = 1
      WHERE pangya_gift_table.UID = @IDUSER AND pangya_gift_table.Msg_ID = @IDMSG

      DECLARE
          TYPEID_CURSOR CURSOR LOCAL FORWARD_ONLY FOR 
            SELECT pangya_item_mail.item_id AS ITEM_ID, pangya_item_mail.item_typeid AS TYPEID, pangya_item_mail.Quantidade_item AS QUANTIDADE, pangya_item_mail.Quantidade_Dia AS QNTD_DIA
            FROM pangya.pangya_item_mail
            WHERE pangya_item_mail.Msg_ID = @IDMSG AND pangya_item_mail.valid = 1

      OPEN TYPEID_CURSOR

      /*
      *   SSMA informational messages:
      *   M2SS0003: The following SQL clause was ignored during conversion:
      *   Salva_Item : .
      *   M2SS0003: The following SQL clause was ignored during conversion:
      *   Salva_Item.
      */

      WHILE (1 = 1)
      
         BEGIN

            FETCH TYPEID_CURSOR
                INTO @ITEMID, @TYPE_ID, @QNTD, @QNTDDIA

            IF @@FETCH_STATUS <> 0
               SET @FINISHED = 1

            IF @FINISHED = 1
               BREAK

            UPDATE pangya.pangya_item_mail
               SET 
                  valid = 0
            WHERE pangya_item_mail.Msg_ID = @IDMSG AND pangya_item_mail.item_typeid = @TYPE_ID

            INSERT pangya.temp_typeid(pangya.temp_typeid.ITEM_ID, pangya.temp_typeid.TYPEID, pangya.temp_typeid.QUANTIDADE, pangya.temp_typeid.QNTD_DIA)
               VALUES (@ITEMID, @TYPE_ID, @QNTD, @QNTDDIA)

         END

      CLOSE TYPEID_CURSOR

      DEALLOCATE TYPEID_CURSOR

      SELECT temp_typeid.ITEM_ID, temp_typeid.TYPEID, temp_typeid.QUANTIDADE, temp_typeid.QNTD_DIA
      FROM pangya.temp_typeid

   END
GO
