	  @NomeCompleto nvarchar(100),
    @Birthday DATETIME = NULL,
     @Sexo SMALLINT,
      @Pergunta NVARCHAR(100),
 @Resposta NVARCHAR(120) = NULL, 
   @userID nvarchar(30),
   @pass nvarchar(40),
   @IPaddr nvarchar(20) 
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	--SET NOCOUNT ON;

    DECLARE @IDUSER INT = 0;
	
	  INSERT INTO account(ID, [PASSWORD], LastLogonTime, RegDate, NICK, UserName, UserIp, LogonCount, BirthDay, NomeCompleto, Question, Answer, Sex, IDState)
    VALUES(@userID, @pass, GETDATE(), GETDATE(), @userID, @userID, @IPaddr, 1, @Birthday, @NomeCompleto, @Pergunta, @Resposta, @Sexo, 0); -- is block shop;
    

    SET @IDUSER = @@identity; --#novo e melhor modo de pegar o uid do player adicionado
    
    INSERT INTO user_info(UID) VALUES(@IDUSER);

	INSERT INTO pangya_player_location([UID]) VALUES(@IDUSER);

	INSERT INTO pangya_user_equip(UID) VALUES(@IDUSER);

	INSERT INTO pangya_last_players_user(UID) VALUES(@IDUSER);

	INSERT INTO trofel_stat(UID) VALUES(@IDUSER);

	INSERT INTO tutorial(UID) VALUES(@IDUSER);

	INSERT INTO pangya_user_macro(UID) VALUES(@IDUSER);

	INSERT INTO pangya_attendance_reward(UID) VALUES(@IDUSER);

	INSERT INTO pangya_tiki_points(UID) VALUES(@IDUSER);

	INSERT INTO pangya_myroom(UID) VALUES(@IDUSER);

	INSERT INTO pangya_dolfini_locker(UID) VALUES(@IDUSER);
    
    INSERT INTO pangya_assistente(UID) VALUES(@IDUSER);
    
    INSERT INTO pangya_grand_zodiac_pontos(UID) VALUES(@IDUSER);
    
    INSERT INTO pangya_daily_quest_player(UID, LAST_QUEST_ACCEPT, TODAY_QUEST) VALUES(@IDUSER, NULL, NULL);

	INSERT INTO pangya_papel_shop_info([UID], remain_cnt, limit_cnt) VALUES(@IDUSER, 100, 100)

	INSERT INTO td_room_data(UID, TYPEID, POS_X, POS_Y, POS_Z, POS_R)
	VALUES(@IDUSER, 1207986208, 15.2, 0, 12.5, 152);
	
	INSERT INTO td_room_data(UID, TYPEID, POS_X, POS_Y, POS_Z, POS_R)
	VALUES(@IDUSER, 1207980061, 14.125, 1.0, 0.041, 0); 

	SELECT @IDUSER as [UID];
END
