/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcPesquisaGuild]  
   @nome nvarchar(50)
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /* 
      *   SSMA error messages:
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion

      SELECT 
         a.GUILD_UID, 
         [@GUILD_NAME] = ISNULL(a.GUILD_NAME, N'') AS GUILD_NAME, 
         [@COUNT_MEMBER] = 
            (
               SELECT count_big(*)
               FROM pangya.pangya_guild_member
               WHERE pangya_guild_member.GUILD_UID = a.GUILD_UID AND pangya_guild_member.MEMBER_STATE_FLAG < 9
            ) AS GUILD_NUM_MEMBER, 
         [@GUILD_MARK] = ISNULL(a.GUILD_MARK_IMG, N'guildmark') AS GUILD_MARK_IMG, 
         a.GUILD_INFO, 
         a.GUILD_PANG, 
         a.GUILD_POINT, 
         [@MEMBER_STATE_FLAG] = 0 AS GUILD_MEMBER_IDENTITY, 
         a.GUILD_LEADER, 
         b.NICK AS GUILD_LEADER_NICK, 
         a.GUILD_REG_DATE
      FROM pangya.pangya_guild  AS a, pangya.account  AS b
      WHERE 
         a.GUILD_UID = b.Guild_UID AND 
         b.UID = a.GUILD_LEADER AND 
         charindex(a.GUILD_NAME, @nome) > 0
         ORDER BY a.GUILD_REG_DATE DESC      */



   END
