-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcRegisterManiaDonation]
	-- Add the parameters for the stored procedure here
	@ADM_UID INT,
	@IDUSER INT,
	@CASH INT,
	@PANGS INT,
	@ITEM_TYPEID_1 INT,
	@ITEM_TYPEID_2 INT,
	@ITEM_TYPEID_3 INT,
	@ITEM_TYPEID_4 INT,
	@ITEM_TYPEID_5 INT,
	@ITEM_QNTD_1 INT,
	@ITEM_QNTD_2 INT,
	@ITEM_QNTD_3 INT,
	@ITEM_QNTD_4 INT,
	@ITEM_QNTD_5 INT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    IF @IDUSER > 0  
	BEGIN
		
		DECLARE @CP INT = @CASH * 10
		DECLARE @DONATION_ID INT
		DECLARE @MSGID INT

		INSERT INTO pangya.pangya_maniadonation_log(ADM_UID, [UID], cash, cookie_point, pangs, ITEM_TYPEID_1, ITEM_TYPEID_2, ITEM_TYPEID_3, ITEM_TYPEID_4, ITEM_TYPEID_5, ITEM_QNTD_1, ITEM_QNTD_2, ITEM_QNTD_3, ITEM_QNTD_4, ITEM_QNTD_5)
			VALUES(@ADM_UID, @IDUSER, @CASH, @CP, @PANGS, @ITEM_TYPEID_1,@ITEM_TYPEID_2,@ITEM_TYPEID_3,@ITEM_TYPEID_4,@ITEM_TYPEID_5, @ITEM_QNTD_1,@ITEM_QNTD_2, @ITEM_QNTD_3, @ITEM_QNTD_4, @ITEM_QNTD_5)

		SET @DONATION_ID = @@IDENTITY

		-- UPDATE COOKIE POINT
		UPDATE pangya.user_info SET Cookie = Cookie + @CP WHERE [UID] = @IDUSER
		UPDATE pangya.user_info SET Pang = Pang + @PANGS WHERE [UID] = @IDUSER

		IF (@ITEM_TYPEID_1 != 0 AND @ITEM_QNTD_1 > 0) 
			OR (@ITEM_TYPEID_2 != 0 AND @ITEM_QNTD_2 > 0) 
			OR (@ITEM_TYPEID_3 != 0 AND @ITEM_QNTD_3 > 0) 
			OR (@ITEM_TYPEID_4 != 0 AND @ITEM_QNTD_4 > 0) 
			OR (@ITEM_TYPEID_5 != 0 AND @ITEM_QNTD_5 > 0)
		BEGIN
			
			INSERT INTO pangya.pangya_gift_table([UID], fromid, [message], giftdate, Lida_YN, valid, [Flag], Contador_Vista)
			VALUES(@IDUSER, '@Mania', CONCAT(N'\cFF0000FF,t\cDonation processed & added to your account.', @CP, ' CP', @PANGS,' PANGS'),
				getdate(), 0, 1, 0, 0)

			SET @MSGID = @@IDENTITY

			IF @MSGID > 0
			BEGIN

				DECLARE @item_id int

				SET @item_id = -1

				IF (@ITEM_TYPEID_1 != 0 AND @ITEM_QNTD_1 > 0)
				BEGIN
					INSERT INTO pangya.pangya_donation_item_log(donation_id, item_typeid, item_qntd) VALUES(@DONATION_ID, @ITEM_TYPEID_1, @ITEM_QNTD_1)

					EXEC pangya.ProcInsertItemNoEmail 0, @IDUSER, @MSGID, @item_id, @ITEM_TYPEID_1, 0, @ITEM_QNTD_1, 0
				END

				IF (@ITEM_TYPEID_2 != 0 AND @ITEM_QNTD_2 > 0)
				BEGIN
					INSERT INTO pangya.pangya_donation_item_log(donation_id, item_typeid, item_qntd) VALUES(@DONATION_ID, @ITEM_TYPEID_2, @ITEM_QNTD_2)

					EXEC pangya.ProcInsertItemNoEmail 0, @IDUSER, @MSGID, @item_id, @ITEM_TYPEID_2, 0, @ITEM_QNTD_2, 0
				END

				IF (@ITEM_TYPEID_3 != 0 AND @ITEM_QNTD_3 > 0)
				BEGIN
					INSERT INTO pangya.pangya_donation_item_log(donation_id, item_typeid, item_qntd) VALUES(@DONATION_ID, @ITEM_TYPEID_3, @ITEM_QNTD_3)

					EXEC pangya.ProcInsertItemNoEmail 0, @IDUSER, @MSGID, @item_id, @ITEM_TYPEID_3, 0, @ITEM_QNTD_3, 0
				END

				IF (@ITEM_TYPEID_4 != 0 AND @ITEM_QNTD_4 > 0)
				BEGIN
					INSERT INTO pangya.pangya_donation_item_log(donation_id, item_typeid, item_qntd) VALUES(@DONATION_ID, @ITEM_TYPEID_4, @ITEM_QNTD_4)

					EXEC pangya.ProcInsertItemNoEmail 0, @IDUSER, @MSGID, @item_id, @ITEM_TYPEID_4, 0, @ITEM_QNTD_4, 0
				END

				IF (@ITEM_TYPEID_5 != 0 AND @ITEM_QNTD_5 > 0)
				BEGIN
					INSERT INTO pangya.pangya_donation_item_log(donation_id, item_typeid, item_qntd) VALUES(@DONATION_ID, @ITEM_TYPEID_5, @ITEM_QNTD_5)

					EXEC pangya.ProcInsertItemNoEmail 0, @IDUSER, @MSGID, @item_id, @ITEM_TYPEID_5, 0, @ITEM_QNTD_5, 0
				END

				-- Comando para mostrar no jogo que o player recebeu um presente
				EXEC pangya.ProcInsertCommand 4, @IDUSER, @MSGID, 0, 0, 0, 1, 0, 1, null

			END -- IF MSG IS IS OK
		
		END -- IF CHECK ITENS IS OK TO SEND
		ELSE
		BEGIN
			
			-- Nao tem itens para enviar so invia uma mensagem
			INSERT INTO pangya.pangya_gift_table([UID], fromid, [message], giftdate, Lida_YN, valid, [Flag], Contador_Vista)
			VALUES(@IDUSER, '@Mania', CONCAT(N'\cFF0000FF,t\cDonation processed & added to your account.', @CP, 'CP'),
				getdate(), 0, 1, 0, 0)

			SET @MSGID = @@IDENTITY

			IF @MSGID > 0
			BEGIN
				-- Comando para mostrar no jogo que o player recebeu um presente
				EXEC pangya.ProcInsertCommand 4, @IDUSER, @MSGID, 0, 0, 0, 1, 0, 1, null
			END

		END	-- ELSE CHECK ITENS IS OK TO SEND

	END -- IFF CHECK UID AND CASH
END
GO
