/****** Objeto:  StoredProcedure [pangya].[ProcRegisterPE]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:      <Author,,Name>
-- Create date: <Create Date,,>
-- Description: <Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcRegisterPE]
    -- Add the parameters for the stored procedure here
    @UID INT 
AS
BEGIN
    -- Declare a variable to hold the current date
    DECLARE @CurrentDate DATE = GETDATE();
     
    -- Check if the UID exists
    IF EXISTS (SELECT 1 FROM pangya.pangya_point_event WHERE UID = @UID)
    BEGIN
         
        -- Update the record considering the current last_day
        UPDATE pangya.pangya_point_event
        SET  
            [LIMIT_BUY] = CASE 
                            WHEN [LIMIT_BUY] = 0 AND @CurrentDate > ISNULL((select last_day FROM pangya.pangya_point_event WHERE UID = @UID), @CurrentDate) 
                            THEN 5
                            ELSE [LIMIT_BUY]
                          END, 
            last_day = CASE 
                            WHEN last_day IS NULL OR last_day < @CurrentDate 
                            THEN @CurrentDate
                            ELSE last_day
                       END -- Update last_day if it is NULL or less than the current date
      
        WHERE UID = @UID;
    END
    ELSE
    BEGIN
        -- Insert a new record if no existing record is found
        INSERT INTO pangya.pangya_point_event (UID, [POINTS], [LIMIT_BUY], last_day, reg_date)
        VALUES (@UID, 0, 5, @CurrentDate, GETDATE());
    END

    -- Select the updated or inserted record
	SELECT a.UID, a.NICK AS NICKNAME, a.ID, a.IDState, p.points, p.limit_buy
                      FROM pangya.account a
                      LEFT JOIN pangya.pangya_point_event p ON a.UID = p.UID
                      WHERE a.UID = @UID;
END
GO
