CREATE PROCEDURE [pangya].[ProcRegisterTicker]
	-- Add the parameters for the stored procedure here
	@IDUSER INT,
	@SERVER_OWNER INT,
	@MSG NVARCHAR(500)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	
	IF @IDUSER > 0
	BEGIN
		--Register Ticker on pangya_command
		DECLARE @TICKER_ID INT = 0

		INSERT INTO pangya_ticker_list([MESSAGE], NICK) VALUES(@MSG, (SELECT nick FROM account WHERE [UID] = @IDUSER))

		SET @TICKER_ID = @@identity
			
		-- Envia para todos game server exceto o server que enviou para DB que ele mesmo coloca na fila de ticker dele
		INSERT INTO pangya_command(command_id, arg1, arg2, [target]) VALUES(1, @TICKER_ID, @SERVER_OWNER, 1/*Tipo 1 - Todos Game Server*/)
	END
END
