-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcRescuePassword] 
	-- Add the parameters for the stored procedure here
	@ID VARCHAR(25)
AS
BEGIN
	
	DECLARE @RET INT = -1
	DECLARE @KEY NVARCHAR(100) = N''
	DECLARE @INDEX BIGINT = 0
	DECLARE @EMAIL NVARCHAR(100) = NULL
	DECLARE @UID INT = 0

	IF @ID != ''
	BEGIN

		SET @UID = (SELECT [UID] FROM pangya.account WHERE ID = @ID)

		IF @UID IS NOT NULL
		BEGIN

			SET @EMAIL = (SELECT email FROM pangya.contas_beta WHERE [UID] = @UID);

			IF @EMAIL IS NOT NULL
			BEGIN

				IF (SELECT TOP(1) [UID] FROM pangya.pangya_rescue_pwd_log WHERE [UID] = @UID AND tipo = 1 AND [state] = 0 AND DATEADD(HOUR, 1, send_date) >= getdate()) IS NULL
				BEGIN

					INSERT INTO pangya.pangya_rescue_pwd_log([UID], tipo) VALUES(@UID, 1/*Password*/)

					SET @INDEX = @@IDENTITY

					SELECT @KEY = key_uniq FROM pangya.pangya_rescue_pwd_log WHERE [index] = @INDEX AND [UID] = @UID

					-- Sucesso ao criar o log e a chave
					SET @RET = 1

				END
				ELSE
					SET @RET = -4;	-- Já enviou um email com as instruções para recuperar a senha

			END
			ELSE
				SET @RET = -3	-- Email invalido

		END
		ELSE
			SET @RET = -2	-- ID invalido

	END

	SELECT @RET AS RET, @UID AS [UID], @INDEX AS [INDEX], @KEY AS [KEY], @EMAIL AS EMAIL
END
GO
