CREATE PROCEDURE [pangya].[ProcSaiGuild]
	@IDUSER int,
	@UID_GUILD int
AS 
BEGIN

	UPDATE pangya.account
		SET 
		GUILD_UID = 0
	WHERE [UID] = @IDUSER

	DELETE 
	FROM pangya.pangya_guild_member
	WHERE GUILD_UID = @UID_GUILD AND MEMBER_UID = @IDUSER

	INSERT pangya.pangya_guild_atividade_player([UID], GUILD_UID, [FLAG])
		VALUES (@IDUSER, @UID_GUILD, 7)

	-- Cria log de update para o Game Server verificar e pedir para o Message Server Atualize os Membros do Club
	INSERT INTO pangya_guild_update_activity(GUILD_UID, OWNER_UPDATE, PLAYER_UID, TYPE_UPDATE) VALUES(@UID_GUILD, @IDUSER/*O próprio player que saiu da Guild*/, @IDUSER, 1/*Sai Club*/)
END
