CREATE PROCEDURE [pangya].[ProcSalvaDadosPlayerGuild]  
   @IDUSER int,
   @UID_GUILD int,
   @POINT_GUILD int,
   @PANG_GUILD int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      UPDATE pangya.pangya_guild
         SET 
            GUILD_POINT = pangya_guild.GUILD_POINT + @POINT_GUILD, 
            GUILD_PANG = pangya_guild.GUILD_PANG + @PANG_GUILD
      WHERE pangya_guild.GUILD_UID = @UID_GUILD

      UPDATE pangya.pangya_guild_member
         SET 
            GUILD_POINT = pangya_guild_member.GUILD_POINT + @POINT_GUILD, 
            GUILD_PANG = pangya_guild_member.GUILD_PANG + @PANG_GUILD
      WHERE pangya_guild_member.GUILD_UID = @UID_GUILD AND pangya_guild_member.MEMBER_UID = @IDUSER

   END
