	@IDUSER INT,
	@TYPEID INT,
	@QNTD INT,
	@MSG varchar(200)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	DECLARE  @MSGID INT;
	 
	IF(ISNULL(@IDUSER, 0) > 0)
	begin 
	INSERT INTO pangya.pangya_gift_table(UID, FROMID, MESSAGE, GIFTDATE, LIDA_YN, VALID) VALUES(@IDUSER, N'@NTREEV',@MSG, getdate(), 0, 1)

