/****** Objeto:  StoredProcedure [pangya].[ProcSetAssist]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcSetAssist]  
   @IDUSER int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @ASSISTENTE int = 0

      IF 
         (
            SELECT pangya_assistente.UID
            FROM pangya.pangya_assistente
            WHERE pangya_assistente.UID = @IDUSER
         ) IS NULL
         BEGIN

            INSERT pangya.pangya_assistente(pangya.pangya_assistente.UID)
               VALUES (@IDUSER)

            SET @ASSISTENTE = 1

         END
      ELSE 
         IF 
            (
               SELECT pangya_assistente.Assist
               FROM pangya.pangya_assistente
               WHERE pangya_assistente.UID = @IDUSER
            ) = 1
            BEGIN

               UPDATE pangya.pangya_assistente
                  SET 
                     assist = 0
               WHERE pangya_assistente.UID = @IDUSER

               SET @ASSISTENTE = 0

            END
         ELSE 
            BEGIN

               UPDATE pangya.pangya_assistente
                  SET 
                     assist = 1
               WHERE pangya_assistente.UID = @IDUSER

               SET @ASSISTENTE = 1

            END

      SELECT @ASSISTENTE AS ASSISTENTE

   END
GO
