CREATE PROCEDURE [pangya].[ProcTempUpLevelClubSet]  
   @IDUSER int,
   @Taqueira_ID int,
   @Estado int,
   @TYPEID_ITEM_USADO int,
   @QNTD int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @COUNT int

      SET @COUNT = 0

      SELECT @COUNT = count_big(*)
      FROM pangya.pangya_last_up_clubset
      WHERE pangya_last_up_clubset.UID = @IDUSER

      IF @COUNT = 0
         INSERT pangya.pangya_last_up_clubset(
            pangya.pangya_last_up_clubset.item_id, 
            pangya.pangya_last_up_clubset.UID, 
            pangya.pangya_last_up_clubset.State, 
            pangya.pangya_last_up_clubset.item_usado, 
            pangya.pangya_last_up_clubset.Quantidade)
            VALUES (
               @Taqueira_ID, 
               @IDUSER, 
               @Estado, 
               @TYPEID_ITEM_USADO, 
               @QNTD)
      ELSE 
         UPDATE pangya.pangya_last_up_clubset
            SET 
               item_id = @Taqueira_ID, 
               State = @Estado, 
               item_usado = @TYPEID_ITEM_USADO, 
               Quantidade = @QNTD
         WHERE pangya_last_up_clubset.UID = @IDUSER

   END
