/****** Objeto:  StoredProcedure [pangya].[ProcTrocaNickName]    Data do Script: 03/05/2026 15:40:48 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author: <Author,,Name>
-- Create date: <Create Date,,>
-- Description: <Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcTrocaNickName]  
   @IDUSER int,
   @nickname nvarchar(22)
AS 
BEGIN
    DECLARE @RET INT = -1

    IF @IDUSER > 0 AND @nickname IS NOT NULL
    BEGIN
        DECLARE @monthsDiff INT = (SELECT IIF(change_nick IS NULL, 1, DATEDIFF(MONTH, change_nick, GETDATE())) as diff FROM pangya.account WHERE [UID] = @IDUSER)
        
        IF @monthsDiff = 1
        BEGIN
            IF (SELECT NICK FROM pangya.account WHERE NICK = @nickname) IS NULL
            BEGIN
                UPDATE a
                SET 
                    a.nick = @nickname, 
                    a.CHANGE_NICK = GETDATE()
                FROM pangya.account a
                WHERE a.UID = @IDUSER

                -- Insere o nickname antigo no log de change nickname
                INSERT INTO pangya.pangya_change_nickname_log([UID], nickname) 
                SELECT TOP(1) [UID], NICK 
                FROM pangya.account 
                WHERE [UID] = @IDUSER

                -- Atualiza a flag de first login e a data que o player pediu para trocar de nickname

                SET @RET = 1;   -- Fez o pedido de troca de nickname com sucesso
            END
            ELSE
                SET @RET = 2;   -- O nickname já existe na base de dados
        END
        ELSE
            SET @RET = 3;   -- Já pediu para trocar o nickname no mesmo mês
    END

    SELECT @RET as RET
END
GO
