CREATE PROCEDURE [pangya].[ProcUpdateClubSetStats]
	-- Add the parameters for the stored procedure here
	@IDUSER INT,
	@ITEM_ID INT,
	@PANG BIGINT,
	@C0 SMALLINT,
	@C1 SMALLINT,
	@C2 SMALLINT,
	@C3 SMALLINT,
	@C4 SMALLINT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

    -- Insert statements for procedure here
	IF @IDUSER > 0 AND @ITEM_ID > 0
	BEGIN
		UPDATE pangya.pangya_item_warehouse SET C0 = @C0, C1 = @C1, C2 = @C2, C3 = @C3, C4 = @C4
		WHERE [UID] = @IDUSER AND item_id = @ITEM_ID

		IF @PANG > 0
		BEGIN
			IF (SELECT TOP 1 [UID] FROM pangya.pangya_clubset_enchant WHERE [UID] = @IDUSER AND item_id = @ITEM_ID) IS NOT NULL
			BEGIN
				INSERT INTO pangya.pangya_clubset_enchant(UID, item_id) VALUES(@IDUSER, @ITEM_ID)
			END

			UPDATE pangya.pangya_clubset_enchant SET pang = pang + pang WHERE [UID] = @IDUSER AND item_id = @ITEM_ID
		END
	END
END
