	@_TIPO_LOCATION TINYINT,
	@_RATE BIGINT,
	@_X FLOAT,
	@_Y FLOAT,
	@_Z FLOAT
AS
BEGIN
	
	IF @_ID > 0
	BEGIN

		-- Update
		UPDATE
			[pangya].[pangya_coin_cube_location]
