/****** Objeto:  StoredProcedure [pangya].[ProcUpdateDailyQuest]    Data do Script: 03/05/2026 15:40:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcUpdateDailyQuest]  
   @achieve_quest_1_in int,
   @achieve_quest_2_in int,
   @achieve_quest_3_in int,
   @REG_DT DATETIME2
AS 
BEGIN

	SET  XACT_ABORT  ON

	-- Block TABLE
	BEGIN TRANSACTION

	IF (SELECT count_big(*) FROM pangya.pangya_daily_quest WITH (TABLOCK)) > 0

		UPDATE pangya.pangya_daily_quest
		SET 
			achieve_quest_1 = @achieve_quest_1_in, 
			achieve_quest_2 = @achieve_quest_2_in, 
			achieve_quest_3 = @achieve_quest_3_in, 
			Reg_Date = @REG_DT
		WHERE Reg_Date IS NULL OR DATEDIFF(DAY, CAST(Reg_Date AS DATE), CAST(getdate() AS DATE)) >= 1

	ELSE
		INSERT pangya.pangya_daily_quest(achieve_quest_1, achieve_quest_2, achieve_quest_3, Reg_Date)
		VALUES (@achieve_quest_1_in, @achieve_quest_2_in, @achieve_quest_3_in, @REG_DT)

	IF @@ROWCOUNT >= 1
		SELECT 1 AS OK, 0, 0, 0, null
	ELSE
	BEGIN
		SELECT 0 AS OK, * FROM pangya.pangya_daily_quest
	END

	COMMIT TRANSACTION

END
GO
