-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcUpdateGuildPoints]
	-- Add the parameters for the stored procedure here
	@UID INT,
	@POINT BIGINT,
	@PANG BIGINT,
	@FLAG_WIN TINYINT
AS
BEGIN
	
	IF @UID > 0
	BEGIN

		UPDATE pangya.pangya_guild
			SET GUILD_POINT = GUILD_POINT + @POINT,
				GUILD_PANG = GUILD_PANG + @PANG,
				GUILD_WIN = IIF(@FLAG_WIN = 0/*WIN*/, GUILD_WIN + 1, GUILD_WIN),
				GUILD_LOSE = IIF(@FLAG_WIN = 1/*LOSE*/, GUILD_LOSE + 1, GUILD_LOSE),
				GUILD_DRAW = IIF(@FLAG_WIN = 2/*DRAW*/, GUILD_DRAW + 1, GUILD_DRAW)
		WHERE GUILD_UID = @UID
	END
END
