/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcUpdateLogHole]
   @UID int,  
   @ROOMID uniqueidentifier, 
   @CHARACTER int,
   @TIPO int,
   @MODO int,
   @QNTD_HOLE int,
   @COURSE int,
   @HOLE int,
   @SCORE numeric,
   @EXP int,
   @PANG bigint,
   @BONUS_PANG bigint,
   @TACADA_NUM int,
   @TOTAL_TACADA_NUM int,
   @GIVEUP int,
   @TIMEOUT int,
   @ENTER_AFTER_STARTED int,
   @FINISH_GAME int,
   @ASSIST_FLAG int,
   @TROFEU int, @Master int, @Is_ShotGame int,@Is_Natural int
AS 
   BEGIN

   DECLARE @UPDATE INT =0;
      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

IF EXISTS (SELECT * FROM pangya.pangya_room_log WHERE RoomId = @RoomId and UID = @UID)
	begin
 UPDATE pangya.pangya_room_log
    SET
        [Character] = @Character,
        [Tipo] = @Tipo,
        [Modo] = @Modo,
        [QntdHole] = @QNTD_HOLE,
        [Course] = @Course,
        [Hole] = @Hole,
        [Score] = @Score,
        [Exp] = @Exp,
        [Pang] = @Pang,
        [BonusPang] = @BONUS_PANG,
        [TacadaNum] = @TACADA_NUM,
        [TotalTacadaNum] = @TOTAL_TACADA_NUM,
        [GiveUp] = @GiveUp,
        [TimeOut] = @TimeOut,
        [EnterAfterStarted] = @ENTER_AFTER_STARTED,
        [FinishGame] = @FINISH_GAME,
        [AssistFlag] = @ASSIST_FLAG,
        [Trofeu] = @Trofeu
    WHERE RoomId = @RoomId AND UID = @UID;

	SET @UPDATE = 1;
end
else
begin
INSERT pangya.pangya_room_log(UID, RoomID,
   CHARACTER,
   TIPO,
   MODO,
   QntdHole,
   COURSE,
   HOLE,
   SCORE,
   EXP,
   PANG,
   BonusPang,
   TACADANUM,
   TOTALTACADANUM,
   GIVEUP,
   TIMEOUT,
   ENTERAFTERSTARTED,
   FINISHGAME,
   ASSISTFLAG,
   TROFEU, Master_UID, NaturalMode, ShotMode)
         VALUES (@UID,
		   @ROOMID, 
		   @CHARACTER,
		   @TIPO,
		   @MODO,
		   @QNTD_HOLE,
		   @COURSE,
		   @HOLE,
		   @SCORE,
		   @EXP,
		   @PANG,
		   @BONUS_PANG,
		   @TACADA_NUM,
		   @TOTAL_TACADA_NUM,
		   @GIVEUP,
		   @TIMEOUT,
		   @ENTER_AFTER_STARTED,
		   @FINISH_GAME,
		   @ASSIST_FLAG,
		   @TROFEU,  @Master, @Is_ShotGame,@Is_Natural)
end
select @UPDATE as valor
   END



