CREATE PROCEDURE [pangya].[ProcUpdateLoginRewardEvent]
	@ID BIGINT,
	@NAME NVARCHAR(50),
	@TYPE TINYINT,
	@DAYS_TO_GIFT INT,
	@N_TIMES_GIFT INT,
	@ITEM_TYPEID INT,
	@ITEM_QNTD INT,
	@ITEM_QNTD_TIME INT,
	@IS_END TINYINT,
	@END_DATE DATETIME2(7)
AS
BEGIN
	
	IF @ID > 0 AND @NAME != N'@Mania'
	BEGIN

		UPDATE pangya.pangya_login_reward
			SET
				[name] = @NAME,
				[type] = @TYPE,
				[days_to_gift] = @DAYS_TO_GIFT,
				[n_times_gift] = @N_TIMES_GIFT,
				[item_typeid] = @ITEM_TYPEID,
				[item_qntd] = @ITEM_QNTD,
				[item_qntd_time] = @ITEM_QNTD_TIME,
				[is_end] = @IS_END,
				[end_date] = @END_DATE
		WHERE
			[index] = @ID

		SELECT @ID AS ID

	END
	ELSE
		SELECT -1 AS ID
END
