-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcUpdateMapStatistics]
	-- Add the parameters for the stored procedure here
	@IDUSER INT,
	@TIPO TINYINT,
	@COURSE TINYINT,
	@TACADA INT,
	@PUTT INT,
	@HOLE INT,
	@FAIRWAY INT,
	@HOLEIN INT,
	@PUTTIN INT,
	@TOTAL_SCORE INT,
	@BEST_SCORE SMALLINT,
	@BEST_PANG BIGINT,
	@CHARACTER_TYPEID INT,
	@EVENT_SCORE TINYINT,
	@ASSIST TINYINT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	
	IF @IDUSER > 0
	BEGIN
		IF (SELECT tacada FROM pangya.pangya_record WHERE [UID] = @IDUSER AND tipo = @TIPO AND course = @COURSE AND assist = @ASSIST) IS NULL
		BEGIN
			INSERT INTO pangya.pangya_record([uid], tipo, course, tacada, putt, hole, fairway, holein, puttin, total_score, best_score, best_pang, character_typeid, event_score, assist)
				VALUES(@IDUSER, @TIPO, @COURSE, @TACADA, @PUTT, @HOLE, @FAIRWAY, @HOLEIN, @PUTTIN, @TOTAL_SCORE, @BEST_SCORE, @BEST_PANG, @CHARACTER_TYPEID, @EVENT_SCORE, @ASSIST)
		END
		ELSE
		BEGIN
			UPDATE pangya.pangya_record 
				SET tacada = @TACADA,
					putt = @PUTT,
					hole = @HOLE,
					fairway = @FAIRWAY,
					holein = @HOLEIN,
					puttin = @PUTTIN,
					total_score = @TOTAL_SCORE,
					best_score = @BEST_SCORE,
					best_pang = @BEST_PANG,
					character_typeid = @CHARACTER_TYPEID,
					event_score = @EVENT_SCORE
				WHERE [UID] = @IDUSER AND tipo = @TIPO AND course = @COURSE AND assist = @ASSIST

		END
	END
END
