-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcUpdatePapelShopConfig]
	@NUMERO INT,
	@PRICE_NORMAL BIGINT,
	@PRICE_BIG BIGINT,
	@LIMITTED_PER_DAY TINYINT,
	@UPDATE_DATE DATETIME2
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET XACT_ABORT ON

	-- Block TABLE
	BEGIN TRANSACTION

	IF (SELECT count_big(*) FROM pangya.pangya_papel_shop_config WITH (TABLOCK)) > 0
	BEGIN
		
		UPDATE pangya.pangya_papel_shop_config
			SET Numero = @NUMERO,
				Price_Normal = @PRICE_NORMAL,
				Price_Big = @PRICE_BIG,
				Limitted_YN = @LIMITTED_PER_DAY,
				Update_Date = @UPDATE_DATE
		WHERE Update_Date IS NULL OR DATEDIFF(DAY, CAST(Update_Date AS DATE), CAST(getdate() AS DATE)) >= 1

	END
	ELSE
		INSERT INTO pangya.pangya_papel_shop_config(Numero, Price_Normal, Price_Big, Limitted_YN, Update_Date)
			VALUES(@NUMERO, @PRICE_NORMAL, @PRICE_BIG, @LIMITTED_PER_DAY, @UPDATE_DATE)

	IF @@ROWCOUNT >= 1
		SELECT 1 AS OK, 0, 0, 0, 0, null
	ELSE
		SELECT 0 AS OK, * FROM pangya.pangya_papel_shop_config

	COMMIT TRANSACTION

END
GO
