-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[ProcUpdateRateConfigInfo]
	-- Add the parameters for the stored procedure here
	@SERVER_UID INT,
	@GRAND_ZODIAC_EVENT SMALLINT,
	@SCRATCHY SMALLINT,
	@PAPEL_SHOP_RARE_ITEM SMALLINT,
	@PAPEL_SHOP_COOKIE_ITEM SMALLINT,
	@TREASURE SMALLINT,
	@PANG SMALLINT,
	@EXP SMALLINT,
	@CLUB_MASTERY SMALLINT,
	@CHUVA SMALLINT,
	@MEMORIAL_SHOP SMALLINT,
	@ANGEL_EVENT SMALLINT,
	@GRAND_PRIX_EVENT SMALLINT,
	@GOLDEN_TIME_EVENT SMALLINT,
	@LOGIN_REWARD_EVENT SMALLINT,
	@BOT_GM_EVENT SMALLINT,
	@SMART_CALCULATOR SMALLINT
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	IF @SERVER_UID > 0
	BEGIN

		IF (SELECT [UID] FROM pangya.pangya_config WHERE [UID] = @SERVER_UID) IS NOT NULL
		BEGIN	-- Update
			UPDATE pangya.pangya_config
				SET GrandZodiacEventTime = @GRAND_ZODIAC_EVENT,
					ScratchyPorPointRate = @SCRATCHY,
					PapelShopRareItemRate = @PAPEL_SHOP_RARE_ITEM,
					PapelShopCookieItemRate = @PAPEL_SHOP_COOKIE_ITEM,
					TreasureRate = @TREASURE,
					PangRate = @PANG,
					ExpRate = @EXP,
					ClubMasteryRate = @CLUB_MASTERY,
					ChuvaRate = @CHUVA,
					MemorialShopRate = @MEMORIAL_SHOP,
					AngelEvent = @ANGEL_EVENT,
					GrandPrixEvent = @GRAND_PRIX_EVENT,
					GoldenTimeEvent = @GOLDEN_TIME_EVENT,
					LoginRewardEvent = @LOGIN_REWARD_EVENT,
					BotGMEvent = @BOT_GM_EVENT,
					SmartCalculator = @SMART_CALCULATOR
			WHERE [UID] = @SERVER_UID
		END
		ELSE
		BEGIN
			-- Cria um novo server config rate
			INSERT INTO pangya.pangya_config([UID], GrandZodiacEventTime, ScratchyPorPointRate, PapelShopRareItemRate, PapelShopCookieItemRate, TreasureRate, PangRate, ExpRate, ClubMasteryRate, ChuvaRate, MemorialShopRate, AngelEvent, GrandPrixEvent, GoldenTimeEvent, LoginRewardEvent, BotGMEvent, SmartCalculator)
				VALUES(@SERVER_UID, @GRAND_ZODIAC_EVENT, @SCRATCHY, @PAPEL_SHOP_RARE_ITEM, @PAPEL_SHOP_COOKIE_ITEM, @TREASURE, @PANG, @EXP, @CLUB_MASTERY, @CHUVA, @MEMORIAL_SHOP, @ANGEL_EVENT, @GRAND_PRIX_EVENT, @GOLDEN_TIME_EVENT, @LOGIN_REWARD_EVENT, @BOT_GM_EVENT, @SMART_CALCULATOR)
		END

	END
END
