CREATE PROCEDURE [pangya].[ProcUpdateRoomLog]
 @NAME VARCHAR(200),
	@PLAYERS INT,
	@MAX_PLAYERS INT,
	@TIPO_EX INT,
	@UID INT,  
   @ROOMID UNIQUEIDENTIFIER, 
   @CHARACTER INT,
   @CADDIE INT, @MASCOT INT, @CLUB INT,
   @TIPO INT,
   @MODO INT,
   @QNTD_HOLE INT,
   @COURSE INT,
   @HOLE INT,
   @SCORE NUMERIC,
   @EXP NUMERIC,
   @PANG BIGINT,
   @BONUS_PANG BIGINT,
   @TACADA_NUM NUMERIC,
   @TOTAL_TACADA_NUM NUMERIC,
   @GIVEUP NUMERIC,
   @TIMEOUT NUMERIC,
   @ENTER_AFTER_STARTED BIT,
   @FINISH_GAME BIT,
   @ASSIST_FLAG NUMERIC,
   @TROFEU NUMERIC, 
   @Master NUMERIC, 
   @Is_ShotGame NUMERIC,
   @Is_Natural NUMERIC,
   @hit_hio INT,
   @hit_alba INT,
   @hit_eagle INT,
   @hit_birdie INT,
   @hit_par INT,
   @hit_bogey INT,
   @hit_double_bogey INT,
   @hit_triple_bogey INT
AS 
BEGIN
   DECLARE @UPDATE INT = 0;

   SET XACT_ABORT ON;
   SET NOCOUNT ON;

   IF EXISTS (SELECT 1 FROM pangya.pangya_room_log WHERE RoomId = @RoomId AND UID = @UID)
   BEGIN
       UPDATE pangya.pangya_room_log
       SET
	   [NAME] = @NAME,
	   [Number_Players] = @PLAYERS,
           [Max_Players] = @MAX_PLAYERS,
           [TipoEx] = @TIPO_EX,
           [Character] = @CHARACTER,
		   [CADDIE] = @CADDIE, [MASCOT] = @MASCOT, [CLUB] = @CLUB,
           [Tipo] = @TIPO,
           [Modo] = @MODO,
           [QntdHole] = @QNTD_HOLE,
           [Course] = @COURSE,
           [Hole] = @HOLE,
           [Score] = @SCORE,
           [Exp] = @EXP,
           [Pang] = @PANG,
           [BonusPang] = @BONUS_PANG,
           [TacadaNum] = @TACADA_NUM,
           [TotalTacadaNum] = @TOTAL_TACADA_NUM,
           [GiveUp] = [GiveUp] + @GIVEUP,
           [TimeOut] = @TIMEOUT,
           [EnterAfterStarted] = @ENTER_AFTER_STARTED,
           [FinishGame] = @FINISH_GAME,
           [AssistFlag] = @ASSIST_FLAG,
           [Trofeu] = @TROFEU,
           [Hio_Hit] =@hit_hio,
           [Alba_Hit] = @hit_alba,
           [Eagle_Hit] = @hit_eagle,
           [Birdie_Hit] = @hit_birdie,
           [Par_Hit] =@hit_par,
           [Bogey_Hit] = @hit_bogey,
           [DoubleBogey_Hit] = @hit_double_bogey,
           [TripleBogey_Hit] = @hit_triple_bogey
       WHERE RoomId = @RoomId AND UID = @UID; 

       SET @UPDATE = 1;
   END
   ELSE
   BEGIN
       INSERT INTO pangya.pangya_room_log ([Name],[Number_Players]
           ,[Max_Players]
           ,[TipoEx],
        UID, ROOMID, CHARACTER, CADDIE, MASCOT, CLUB, TIPO, MODO, QntdHole, COURSE, HOLE, SCORE, EXP, PANG, BonusPang, 
        TACADANUM, TOTALTACADANUM, GIVEUP, TIMEOUT, ENTERAFTERSTARTED, FINISHGAME, ASSISTFLAG, 
        TROFEU, Master_UID, NaturalMode, ShotMode, [Hio_Hit], [Alba_Hit], [Eagle_Hit], [Birdie_Hit], 
        [Par_Hit], [Bogey_Hit], [DoubleBogey_Hit], [TripleBogey_Hit]
    )
    VALUES (@NAME, @PLAYERS, @MAX_PLAYERS, @TIPO_EX,
        @UID, @ROOMID, @CHARACTER, @CADDIE, @MASCOT, @CLUB, @TIPO, @MODO, @QNTD_HOLE, @COURSE, @HOLE, @SCORE, @EXP, @PANG, 
        @BONUS_PANG, @TACADA_NUM, @TOTAL_TACADA_NUM, @GIVEUP, @TIMEOUT, @ENTER_AFTER_STARTED, 
        0, @ASSIST_FLAG, @TROFEU, @Master, @Is_Natural, @Is_ShotGame, @hit_hio, @hit_alba, 
        @hit_eagle, @hit_birdie, @hit_par, @hit_bogey, @hit_double_bogey, @hit_triple_bogey
    );
   END

   SELECT @UPDATE;
END
GO
