/****** Objeto:  StoredProcedure [pangya].[ProcUpdateTikiPoints]    Data do Script: 03/05/2026 15:40:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [pangya].[ProcUpdateTikiPoints]  
   @IDUSER int,
   @ITEM_TP int
AS 
BEGIN
   SET XACT_ABORT ON
   SET NOCOUNT ON
   DECLARE @OKAY INT = 0;
   -- Verifica se o usuário possui pontos suficientes antes de tentar subtrair
  IF @ITEM_TP > 0 
  BEGIN
   IF EXISTS (SELECT 1 FROM [pangya].[pangya_item_warehouse]
              WHERE uid = @IDUSER AND typeid = 436208294 AND valid = 1 AND C0 >= @ITEM_TP)
   BEGIN
      -- Atualiza a quantidade de Tiki Points
      UPDATE [pangya].[pangya_item_warehouse]
      SET [C0] = [C0] - @ITEM_TP
      WHERE uid = @IDUSER AND typeid = 436208294 AND valid = 1
     set @OKAY = 1;
   END
  END
   ELSE
   BEGIN
     set @OKAY = 0;
   END
   select @OKAY as [OKAY]
END
GO
