/****** Objeto:  StoredProcedure [pangya].[ProcUpRankClubSet]    Data do Script: 03/05/2026 15:40:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

/*
*   SSMA informational messages:
*   M2SS0134: Conversion of following Comment(s) is not supported : Up Rank do CLubSet
*
*/

CREATE PROCEDURE [pangya].[ProcUpRankClubSet]  
   @IDUSER int,
   @Taqueira_ID int,
   @State int,
   @Mastery int,
   @State2 int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @OPT int = -1

      /* 
      *   SSMA error messages:
      *   M2SS0198: SSMA for MySQL  does not support user variables conversion

      IF ([@LEVEL] = pangya.GetRankClubSet(@IDUSER, @taqueira_id, 1)) = 5
         SET @OPT = 1      */



      IF @OPT < 0
         BEGIN

            /*
            *   SSMA informational messages:
            *   M2SS0134: Conversion of following Comment(s) is not supported : State Rank e Level Normal
            *
            */

            IF @State = 0
               UPDATE pangya.pangya_item_warehouse
                  SET 
                     ClubSet_WorkShop_C0 = pangya_item_warehouse.ClubSet_WorkShop_C0 + 1
               WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID
            ELSE 
               IF @State = 1
                  UPDATE pangya.pangya_item_warehouse
                     SET 
                        ClubSet_WorkShop_C1 = pangya_item_warehouse.ClubSet_WorkShop_C1 + 1
                  WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID
               ELSE 
                  IF @State = 2
                     UPDATE pangya.pangya_item_warehouse
                        SET 
                           ClubSet_WorkShop_C2 = pangya_item_warehouse.ClubSet_WorkShop_C2 + 1
                     WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID
                  ELSE 
                     IF @State = 3
                        UPDATE pangya.pangya_item_warehouse
                           SET 
                              ClubSet_WorkShop_C3 = pangya_item_warehouse.ClubSet_WorkShop_C3 + 1
                        WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID
                     ELSE 
                        IF @State = 4
                           UPDATE pangya.pangya_item_warehouse
                              SET 
                                 ClubSet_WorkShop_C4 = pangya_item_warehouse.ClubSet_WorkShop_C4 + 1
                           WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID

            /* 
            *   SSMA error messages:
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion

            UPDATE pangya.pangya_item_warehouse
               SET 
                  `Level` = [@LEVEL], 
                  Up = 1, 
                  Recovery_Pts = 0, 
                  Mastery_Pts = pangya_item_warehouse.Mastery_Pts - @Mastery, 
                  Mastery_Gasto = pangya_item_warehouse.Mastery_Gasto + @Mastery
            WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID            */



         END
      ELSE 
         BEGIN

            /*
            *   SSMA informational messages:
            *   M2SS0134: Conversion of following Comment(s) is not supported : State Rank e Level Normal
            *
            */

            IF @State = 0
               UPDATE pangya.pangya_item_warehouse
                  SET 
                     ClubSet_WorkShop_C0 = pangya_item_warehouse.ClubSet_WorkShop_C0 + 1
               WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID
            ELSE 
               IF @State = 1
                  UPDATE pangya.pangya_item_warehouse
                     SET 
                        ClubSet_WorkShop_C1 = pangya_item_warehouse.ClubSet_WorkShop_C1 + 1
                  WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID
               ELSE 
                  IF @State = 2
                     UPDATE pangya.pangya_item_warehouse
                        SET 
                           ClubSet_WorkShop_C2 = pangya_item_warehouse.ClubSet_WorkShop_C2 + 1
                     WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID
                  ELSE 
                     IF @State = 3
                        UPDATE pangya.pangya_item_warehouse
                           SET 
                              ClubSet_WorkShop_C3 = pangya_item_warehouse.ClubSet_WorkShop_C3 + 1
                        WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID
                     ELSE 
                        IF @State = 4
                           UPDATE pangya.pangya_item_warehouse
                              SET 
                                 ClubSet_WorkShop_C4 = pangya_item_warehouse.ClubSet_WorkShop_C4 + 1
                           WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID

            /* 
            *   SSMA error messages:
            *   M2SS0198: SSMA for MySQL  does not support user variables conversion

            UPDATE pangya.pangya_item_warehouse
               SET 
                  `Level` = [@LEVEL], 
                  Up = 1, 
                  Recovery_Pts = 0, 
                  Mastery_Pts = pangya_item_warehouse.Mastery_Pts - @Mastery, 
                  Mastery_Gasto = pangya_item_warehouse.Mastery_Gasto + @Mastery
            WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID            */



            /*
            *   SSMA informational messages:
            *   M2SS0134: Conversion of following Comment(s) is not supported :  State 2 Rank S
            *
            */

            IF @State2 = 0
               UPDATE pangya.pangya_item_warehouse
                  SET 
                     ClubSet_WorkShop_C0 = pangya_item_warehouse.ClubSet_WorkShop_C0 + 1
               WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID
            ELSE 
               IF @State2 = 1
                  UPDATE pangya.pangya_item_warehouse
                     SET 
                        ClubSet_WorkShop_C1 = pangya_item_warehouse.ClubSet_WorkShop_C1 + 1
                  WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID
               ELSE 
                  IF @State2 = 2
                     UPDATE pangya.pangya_item_warehouse
                        SET 
                           ClubSet_WorkShop_C2 = pangya_item_warehouse.ClubSet_WorkShop_C2 + 1
                     WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID
                  ELSE 
                     IF @State2 = 3
                        UPDATE pangya.pangya_item_warehouse
                           SET 
                              ClubSet_WorkShop_C3 = pangya_item_warehouse.ClubSet_WorkShop_C3 + 1
                        WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID
                     ELSE 
                        IF @State2 = 4
                           UPDATE pangya.pangya_item_warehouse
                              SET 
                                 ClubSet_WorkShop_C4 = pangya_item_warehouse.ClubSet_WorkShop_C4 + 1
                           WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.item_id = @Taqueira_ID

         END

      SELECT @OPT

   END
