/****** Objeto:  StoredProcedure [pangya].[ProcVerificaAuthKeys]    Data do Script: 03/05/2026 15:40:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcVerificaAuthKeys]  
   @IDUSER int,
   @key_in nvarchar(8),
   @OPT_IN smallint
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @RET int = 0

      IF @OPT_IN = 0
         BEGIN
            IF 
               CASE 
                  WHEN 
                     (
                        SELECT authkey.AuthKey
                        FROM pangya.authkey
                        WHERE authkey.UID = @IDUSER
                     ) = @key_in THEN 0
                  WHEN 
                     (
                        SELECT authkey.AuthKey
                        FROM pangya.authkey
                        WHERE authkey.UID = @IDUSER
                     ) > @key_in THEN 1
                  WHEN 
                     (
                        SELECT authkey.AuthKey
                        FROM pangya.authkey
                        WHERE authkey.UID = @IDUSER
                     ) < @key_in THEN -1
                  ELSE NULL
               END = 0
               SET @RET = 1
         END
      ELSE 
         BEGIN
            IF 
               CASE 
                  WHEN 
                     (
                        SELECT authkey.AuthKey_login
                        FROM pangya.authkey
                        WHERE authkey.UID = @IDUSER
                     ) = @key_in THEN 0
                  WHEN 
                     (
                        SELECT authkey.AuthKey_login
                        FROM pangya.authkey
                        WHERE authkey.UID = @IDUSER
                     ) > @key_in THEN 1
                  WHEN 
                     (
                        SELECT authkey.AuthKey_login
                        FROM pangya.authkey
                        WHERE authkey.UID = @IDUSER
                     ) < @key_in THEN -1
                  ELSE NULL
               END = 0
               SET @RET = 1
         END

      IF @RET = 1
         UPDATE pangya.authkey
            SET 
               valid = 1
         WHERE authkey.UID = @IDUSER

      SELECT @RET

   END
GO
