/****** Objeto:  StoredProcedure [pangya].[ProcVerificaNick]    Data do Script: 03/05/2026 15:40:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[ProcVerificaNick]  
   @IDUSER int,
   @NICK_USER nvarchar(30),
   @OPT smallint
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported : Verifica o NICK se EXITES OPT = 0
      *
      */

      IF @OPT = 0
         SELECT account.UID
         FROM pangya.account
         WHERE account.NICK = @NICK_USER
      ELSE 
         BEGIN
            IF @OPT = 1
               /*
               *   SSMA informational messages:
               *   M2SS0134: Conversion of following Comment(s) is not supported :  VERIFICA NICK PARA TROCAR
               *
               *   M2SS0134: Conversion of following Comment(s) is not supported : Tem espaço
               *
               *   M2SS0134: Conversion of following Comment(s) is not supported :  TEM CARACTERES INVALIDOS NO NICK
               *
               */

               IF @NICK_USER LIKE N'% %'
                  SELECT -3 AS UID
               ELSE 
                  /* 
                  *   SSMA error messages:
                  *   M2SS0210: Conversion of  Regexp or Rlike  Operators is not supported.

                  IF NULL
                     SELECT -4 AS UID
                  ELSE 
                     IF (
                        (
                           SELECT account.capability
                           FROM pangya.account
                           WHERE account.UID = @IDUSER
                        ) & 4) = 4
                        SELECT account.UID
                        FROM pangya.account
                        WHERE account.NICK = @NICK_USER
                     ELSE 
                        IF 
                           (
                              SELECT account.change_nick
                              FROM pangya.account
                              WHERE account.UID = @IDUSER
                           ) IS NOT NULL AND 
                           (
                              SELECT datediff(week, account.change_nick, getdate()) AS DT_CH_NICK
                              FROM pangya.account
                              WHERE account.UID = @IDUSER
                           ) < 2
                           SELECT -5 AS UID
                        ELSE 
                           IF (upper(@NICK_USER) LIKE N'%GM%' OR upper(@NICK_USER) LIKE N'%ADM%')
                              SELECT -2 AS UID
                           ELSE 
                              SELECT account.UID
                              FROM pangya.account
                              WHERE account.NICK = @NICK_USER                  */


                  DECLARE
                     @db_null_statement int
         END

   END
GO
