CREATE PROCEDURE [pangya].[ProcVerifyID]
    @ID VARCHAR(25)
AS
BEGIN
    SET NOCOUNT ON;

    IF @ID <> ''
    BEGIN 
        SELECT TOP 1 [uid], [id] 
        FROM (
            SELECT [uid], [id] FROM [pangya].[account]
            UNION
            SELECT [index] AS [uid], [LoginID] AS [id] FROM [pangya].[contas_beta]
        ) AS TotalAccounts
        WHERE CAST([id] AS BINARY(25)) = CAST(@ID AS BINARY(25));
    END
END
GO
