/****** Objeto:  StoredProcedure [pangya].[ProcVerifyPass]    Data do Script: 03/05/2026 15:40:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [pangya].[ProcVerifyPass]
    @IDUSER INT,
    @PASS VARCHAR(32)
AS
BEGIN
    SET NOCOUNT ON;

    -- Realiza a busca unificada entre a conta ativa e a conta beta
     SELECT TOP 1 [uid] 
    FROM (
        -- Busca na tabela principal
        SELECT [uid], [password] 
        FROM [pangya].[account]
        
        UNION ALL
         
        SELECT [uid], [Senha] AS [password] 
        FROM [pangya].[contas_beta]
    ) AS TotalAuth
    WHERE [uid] = @IDUSER AND [password] = UPPER(@PASS);

END
GO
