/****** Objeto:  StoredProcedure [pangya].[UpdateWorldTourEvent]    Data do Script: 03/05/2026 15:40:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [pangya].[UpdateWorldTourEvent]
    @UID INT,
    @Course INT,
    @Completed BIT,
    @FinishDate DATETIME2 = NULL
AS
BEGIN
    SET NOCOUNT ON;

    IF @FinishDate IS NULL
        SET @FinishDate = SYSDATETIME();

    -- Atualiza ou insere o progresso do curso
    MERGE pangya.pangya_world_tour_event AS target
    USING (SELECT @UID AS UID, @Course AS Course) AS source
    ON target.UID = source.UID AND target.Course = source.Course
    WHEN MATCHED THEN
        UPDATE SET Completed = @Completed, Finish_Data = @FinishDate
    WHEN NOT MATCHED THEN
        INSERT (UID, Course, Completed, Finish_Data)
        VALUES (@UID, @Course, @Completed, @FinishDate);

    -- Retorna se o jogador completou todos os 21 cursos
    SELECT 
        @UID AS UID,
        CASE WHEN COUNT(*) = 21 AND SUM(CASE WHEN Completed = 1 THEN 1 ELSE 0 END) = 21
             THEN 1 ELSE 0 END AS IsEnd
    FROM pangya.pangya_world_tour_event
    WHERE UID = @UID;
END
GO
