CREATE PROCEDURE [pangya].[USP_ADD_FURNITURE]  
   @IDUSER int,
   @IDITEM int,
   @ITEMTYPEID int,
   @F_X float(24),
   @F_Y float(24),
   @F_Z float(24),
   @F_R float(24)
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported : Add Item Furniture (Item My Room)
      *
      */

      IF @IDITEM <= 0
         SELECT @IDITEM = td_room_data.MYROOM_ID
         FROM pangya.td_room_data
         WHERE td_room_data.UID = @IDUSER AND td_room_data.TYPEID = @ITEMTYPEID

      IF @IDITEM > 0
         BEGIN
            DECLARE
               @db_null_statement int
         END
      ELSE 
         BEGIN

            INSERT pangya.td_room_data(
               pangya.td_room_data.UID, 
               pangya.td_room_data.TYPEID, 
               pangya.td_room_data.POS_X, 
               pangya.td_room_data.POS_Y, 
               pangya.td_room_data.POS_Z, 
               pangya.td_room_data.POS_R)
               VALUES (
                  @IDUSER, 
                  @ITEMTYPEID, 
                  @F_X, 
                  @F_Y, 
                  @F_Z, 
                  @F_R)

            SELECT @IDITEM = max(td_room_data.MYROOM_ID)
            FROM pangya.td_room_data
            WHERE td_room_data.UID = @IDUSER

         END

      SELECT @IDITEM AS ITEM_ID

   END
