				BEGIN
				INSERT INTO pangya_item_warehouse(UID, typeid, valid, regdate, Gift_flag, flag, Purchase, ItemType, c0, c1, c2, c3, c4, EndDate)
				VALUES(@IDUSER, @ITEMTYPEID, 1, getdate(), @GIFTFLAG, @TYPEFLAG, 0, 2, @C_0, @C_1, @C_2, @C_3, @C_4, DATEADD(DAY, @TEMPO, GETDATE()));
				END
								
ELSE
