				VALUES(@IDUSER, @ITEMTYPEID, 1, getdate(), @GIFTFLAG, @TYPEFLAG, 0, 2, @C_0, @C_1, @C_2, @C_3, @C_4);
					END;
					SET @IDITEM = (SELECT MAX(item_id) FROM pangya_item_warehouse WHERE UID = @IDUSER AND typeid = @ITEMTYPEID)

					INSERT INTO pangya_clubset_enchant(uid, item_id) VALUES(@IDUSER, @IDITEM);
				END;

