					BEGIN
						UPDATE pangya_caddie_information SET parts_typeid = @ITEMTYPEID, parts_EndDate = DATEADD(DAY, @TEMPO, getdate())
						WHERE UID = @IDUSER AND item_id = @IDITEM;
					END;
				END
			/*ELSE
				BEGIN
				END;*/

			SELECT @IDITEM AS ITEM_ID;
		END
	ELSE IF @NUMERO = 45 --# Trofel Especial
		BEGIN
			IF (SELECT item_id FROM pangya_trofel_especial WHERE UID = @IDUSER AND typeid = @ITEMTYPEID) IS NULL
			BEGIN
				INSERT INTO pangya_trofel_especial(UID, TYPEID, QNTD) VALUES(@IDUSER, @ITEMTYPEID, 1);
			END
            ELSE
			BEGIN
				UPDATE pangya_trofel_especial SET qntd = qntd + 1 WHERE UID = @IDUSER AND typeid = @ITEMTYPEID;
            END
            
            SELECT ITEM_ID FROM pangya_trofel_especial WHERE UID = @IDUSER AND typeid = @ITEMTYPEID;
        END
	ELSE IF @NUMERO = 47 --# Trofel Grand Prix
		BEGIN
			IF (SELECT item_id FROM pangya_trofel_grandprix WHERE UID = @IDUSER AND typeid = @ITEMTYPEID) IS NULL
			BEGIN
				INSERT INTO pangya_trofel_grandprix(UID, TYPEID, QNTD) VALUES(@IDUSER, @ITEMTYPEID, 1);
			END
            ELSE
			BEGIN
				UPDATE pangya_trofel_grandprix SET qntd = qntd + 1 WHERE UID = @IDUSER AND typeid = @ITEMTYPEID;
            END
            
            SELECT ITEM_ID FROM pangya_trofel_grandprix WHERE UID = @IDUSER AND typeid = @ITEMTYPEID;
        END;
	ELSE IF @NUMERO = 60 --# HairStyle
		BEGIN
			SET @ITEM_TYPE = 0x4000000 | @C_1;

			UPDATE pangya_character_information SET default_hair = @C_0 
			WHERE UID = @IDUSER AND typeid = @ITEM_TYPE;
			
			SELECT 0 AS ITEM_ID;
		END
	ELSE IF @NUMERO = 62 --# HairStyle 2
		BEGIN
			SET @ITEM_TYPE = 0x4000000 | @C_1;

			UPDATE pangya_character_information SET default_hair = @C_0 
			WHERE UID = @IDUSER AND typeid = @ITEM_TYPE;

			SELECT 0 AS ITEM_ID;
		END;
	ELSE IF @NUMERO = 64 --#Mascot
		BEGIN
			IF @IDITEM <= 0
			BEGIN
				IF (SELECT item_id FROM pangya_mascot_info WHERE UID = @IDUSER AND typeid = @ITEMTYPEID AND valid = 0) IS NOT NULL
				BEGIN
					SELECT @IDITEM = item_id
					FROM pangya_mascot_info
					WHERE UID = @IDUSER AND typeid = @ITEMTYPEID AND valid = 0;

					SET @C_0 = 1;
				END
				ELSE
				BEGIN
					SELECT @IDITEM = item_id
					FROM pangya_mascot_info
					WHERE UID = @IDUSER AND typeid = @ITEMTYPEID AND valid = 1;
				END
			END

			IF @IDITEM > 0
				BEGIN
					IF @TEMPO > 0
					BEGIN
						IF (SELECT EndDate FROM pangya_mascot_info WHERE UID = @IDUSER AND item_id = @IDITEM) <= getdate() --# novo mascot, msm que já tinha, mas @TEMPO acabou
						BEGIN
							UPDATE pangya_mascot_info SET Period = Period + @TEMPO, EndDate = DATEADD(DAY, @TEMPO, getdate()), message = 'Pangya'
							WHERE UID = @IDUSER AND item_id = @IDITEM;
						END
						ELSE
						BEGIN
							UPDATE pangya_mascot_info SET Period = Period + @TEMPO, EndDate = DATEADD(DAY, @TEMPO, EndDate)
							WHERE UID = @IDUSER AND item_id = @IDITEM;
						END
					END
					ELSE IF @C_0 < 0
					BEGIN
						UPDATE pangya_mascot_info SET valid = 0
						WHERE UID = @IDUSER AND item_id = @IDITEM;
					END
					ELSE IF @C_0 > 0
					BEGIN
						UPDATE pangya_mascot_info SET valid = 1, message = 'Pangya'
						WHERE UID = @IDUSER AND item_id = @IDITEM;
					END
				END;
			ELSE
				BEGIN
					IF @TEMPO = 0 --# Mascot Sem Limit de @TEMPO
					BEGIN
						INSERT INTO pangya_mascot_info(UID, typeid, Flag, Tipo, RegDate, Period, EndDate, IsCash, Valid)
								VALUES(@IDUSER, @ITEMTYPEID, 0, 0, getdate(), @TEMPO, DATEADD(DAY , @TEMPO, getdate()), 1, 1);
					END;
					ELSE	--# Mascot com limit de @TEMPO
					BEGIN
						INSERT INTO pangya_mascot_info(UID, typeid, Flag, Tipo, RegDate, Period, EndDate, IsCash, Valid)
								VALUES(@IDUSER, @ITEMTYPEID, 0, 1, getdate(), @TEMPO, DATEADD(DAY , @TEMPO, getdate()), 0, 1);
					END

					SELECT @IDITEM = MAX(item_id) FROM pangya_mascot_info WHERE UID = @IDUSER AND typeid = @ITEMTYPEID;
				END

			SELECT @IDITEM AS ITEM_ID;
		END
	ELSE IF @NUMERO = 56 --# Skiin (Background, Frame, Sticker, Slot)
	BEGIN
		IF @IDITEM <= 0
		BEGIN
			SELECT @IDITEM = item_id FROM pangya_item_warehouse 
			WHERE UID = @IDUSER AND typeid = @ITEMTYPEID;
		END

		IF @IDITEM > 0
			BEGIN
				IF @TEMPO > 0								--#flag 64 pq os anyigos estava errado isso é só para concerta
				BEGIN
					UPDATE pangya_item_warehouse SET valid = 1, flag = 64, EndDate = CASE WHEN EndDate <= getdate() THEN DATEADD(DAY, @TEMPO, getdate()) ELSE DATEADD(DAY, @TEMPO, EndDate) END
					WHERE UID = @IDUSER AND item_id = @IDITEM;
				END
				ELSE IF @C_0 < 0
				BEGIN
					UPDATE pangya_item_warehouse SET valid = 0
					WHERE UID = @IDUSER AND item_id = @IDITEM;
				END
				ELSE IF @C_0 > 0
				BEGIN
					UPDATE pangya_item_warehouse SET valid = 1
					WHERE UID = @IDUSER AND item_id = @IDITEM;
				END
			END;
		ELSE
			BEGIN
				INSERT INTO pangya_item_warehouse(UID, typeid, valid, regdate, Gift_flag, flag, C0, Purchase, ItemType, EndDate)
						VALUES(@IDUSER, @ITEMTYPEID, 1, getdate(), @GIFTFLAG, @TYPEFLAG, 0, 0, 2, DATEADD(DAY, @TEMPO, getdate()));

				SELECT @IDITEM = MAX(ITEM_ID) FROM pangya_item_warehouse WHERE UID = @IDUSER;
			END;

		SELECT @IDITEM AS ITEM_ID;
	END
	ELSE IF @NUMERO = 57 --# Cutin e Título
	BEGIN
		IF @IDITEM <= 0
		BEGIN
			SELECT @IDITEM = item_id FROM pangya_item_warehouse 
			WHERE UID = @IDUSER AND typeid = @ITEMTYPEID;
		END

		IF @IDITEM > 0
			BEGIN
				IF @TEMPO > 0								--#flag 64 pq os anyigos estava errado isso é só para concerta
				BEGIN
					UPDATE pangya_item_warehouse SET valid = 1, flag = 64, EndDate = CASE WHEN EndDate <= getdate() THEN DATEADD(DAY, @TEMPO, getdate()) ELSE DATEADD(DAY, @TEMPO, EndDate) END
					WHERE UID = @IDUSER AND item_id = @IDITEM;
				END
				ELSE IF @C_0 < 0
				BEGIN
					UPDATE pangya_item_warehouse SET valid = 0
					WHERE UID = @IDUSER AND item_id = @IDITEM;
				END
				ELSE IF @C_0 > 0
				BEGIN
					UPDATE pangya_item_warehouse SET valid = 1
					WHERE UID = @IDUSER AND item_id = @IDITEM;
				END
			END
		ELSE
			BEGIN
				INSERT INTO pangya_item_warehouse(UID, typeid, valid, regdate, Gift_flag, flag, C0, Purchase, ItemType)
						VALUES(@IDUSER, @ITEMTYPEID, 1, getdate(), @GIFTFLAG, @TYPEFLAG, 0, 0, 2);

				SELECT @IDITEM = MAX(ITEM_ID) FROM pangya_item_warehouse WHERE UID = @IDUSER;
			END;
		
		SELECT @IDITEM AS ITEM_ID;
	END
	ELSE IF @NUMERO = 72 --#Furniture - Chama a procedure do Furniture
		BEGIN
			exec USP_ADD_FURNITURE @IDUSER, @IDITEM, @ITEMTYPEID, @X, @Y, @Z, @R
		END
	ELSE IF @NUMERO = 108 --# 0x6C COUNTER ITEM_TYPE
	BEGIN
		IF @IDITEM > 0 AND @C_0 < 0 AND @C_1 != 0
		BEGIN
			UPDATE count_item SET count_num_item = 0, Data_Sec = 0 WHERE UID = @IDUSER AND count_id = @IDITEM;
            SELECT @IDITEM as ITEM_ID;
		END
        ELSE IF @IDITEM > 0 AND @C_0 < 0 AND @C_1 = 0
		BEGIN
			DELETE FROM count_item WHERE UID = @IDUSER AND count_id = @IDITEM;
            SELECT @IDITEM as ITEM_ID;
		END
		ELSE IF @IDITEM > 0 AND @C_0 > 0 --# att o countador do count_item
		BEGIN
            exec USP_ATT_COUNTER_ITEM @IDUSER, @ITEMTYPEID, @IDITEM, @C_0, @C_3, @C_4
            SELECT @IDITEM as ITEM_ID;
		END
		ELSE IF @IDITEM > 0 AND @C_0 = 0 AND @C_1 != 0
		BEGIN
			DELETE FROM count_item WHERE UID = @IDUSER AND count_id = @IDITEM;
            SELECT @IDITEM as ITEM_ID;
		END
		ELSE IF @IDITEM > 0 AND @C_0 = 0 AND @C_1 = 0
		BEGIN
			UPDATE count_item SET count_num_item = @C_0, Data_Sec = 0 WHERE UID = @IDUSER AND count_id = @IDITEM;
            SELECT @IDITEM as ITEM_ID;
		END
        ELSE
		BEGIN
			SELECT count_id AS ITEM_ID FROM count_item WHERE UID = @IDUSER AND TypeID = @ITEMTYPEID;
		END
	END
	ELSE IF @NUMERO = 112 --#Aux Part
		BEGIN
			IF @IDITEM <= 0
			BEGIN
				SELECT @IDITEM = item_id
				FROM pangya_item_warehouse
				WHERE UID = @IDUSER AND typeid = @ITEMTYPEID;
			END
			
			IF @IDITEM > 0
				BEGIN
					--DECLARE @ATIVO INT
						--	,@C0_QNTD INT;

					SELECT @ATIVO = valid FROM pangya_item_warehouse WHERE UID = @IDUSER AND item_id = @IDITEM;
					IF @ATIVO = 1
					BEGIN
						UPDATE pangya_item_warehouse SET C0 = C0 + @C_0 WHERE UID = @IDUSER AND item_id = @IDITEM;

						SELECT @C0_QNTD = C0 FROM pangya_item_warehouse WHERE UID = @IDUSER AND item_id = @IDITEM;
						IF @C0_QNTD <= 0
						BEGIN
							UPDATE pangya_item_warehouse SET valid = 0, C0 = 0 WHERE UID = @IDUSER AND item_id = @IDITEM;
						END
					END
					ELSE
					BEGIN
						UPDATE pangya_item_warehouse SET C0 = C0 + @C_0, valid = 1 WHERE UID = @IDUSER AND item_id = @IDITEM;
					END;
				END;
			ELSE
				BEGIN
					INSERT INTO pangya_item_warehouse(UID, typeid, valid, regdate, Gift_flag, flag, C0, Purchase, ItemType)
							VALUES(@IDUSER, @ITEMTYPEID, 1, getdate(), @GIFTFLAG, @TYPEFLAG, @C_0, 0, 2);

					SELECT @IDITEM = MAX(ITEM_ID) FROM pangya_item_warehouse WHERE UID = @IDUSER;
				END
			
			SELECT @IDITEM AS ITEM_ID
		END
	ELSE IF @NUMERO = 120 --# Daily quest achievement
    BEGIN
		SELECT ID_ACHIEVEMENT AS ITEM_ID FROM achievement_tipo WHERE UID = @IDUSER AND TypeID = @ITEMTYPEID AND [OPTION] = 1;
    END;
	ELSE IF @NUMERO = 124 --#Pangya Card Pack #1, #2, #3, #4
	BEGIN
		IF @IDITEM <= 0
		BEGIN
			SELECT @IDITEM = card_itemid FROM pangya_card 
			WHERE UID = @IDUSER AND card_typeid = @ITEMTYPEID;
		END

		IF @IDITEM > 0
			BEGIN
				BEGIN
					DECLARE @ATIVO_C CHAR;
					--DECLARE	@C0_QNTD INT;

					SELECT @ATIVO_C = USE_YN FROM pangya_card WHERE UID = @IDUSER AND card_itemid = @IDITEM;
					IF @ATIVO_C = 'N'
					BEGIN
						UPDATE pangya_card SET QNTD = QNTD + @C_0 WHERE UID = @IDUSER AND card_itemid = @IDITEM;

						SELECT @C0_QNTD = QNTD FROM pangya_card WHERE UID = @IDUSER AND card_itemid = @IDITEM;
						IF @C0_QNTD <= 0
						BEGIN
							UPDATE pangya_card SET USE_YN = 'Y', QNTD = 0 WHERE UID = @IDUSER AND card_itemid = @IDITEM;
						END
					END
					ELSE
					BEGIN
						UPDATE pangya_card SET QNTD = QNTD + @C_0, USE_YN = 'N' WHERE UID = @IDUSER AND card_itemid = @IDITEM;
					END;
				END;
			END;
		ELSE
			BEGIN
				INSERT INTO pangya_card(UID, card_typeid, card_type, QNTD, GET_DT, USE_YN)
						VALUES(@IDUSER, @ITEMTYPEID, 1, @C_0, getdate(), 'N');

				SELECT @IDITEM = MAX(CARD_ITEMID) FROM pangya_card WHERE UID = @IDUSER;
			END

		SELECT @IDITEM AS ITEM_ID;
	END
	ELSE IF @NUMERO = 125 --#Card NPC
	BEGIN
		IF @IDITEM <= 0
		BEGIN
			SELECT @IDITEM = card_itemid FROM pangya_card 
			WHERE UID = @IDUSER AND card_typeid = @ITEMTYPEID;
		END

		IF @IDITEM > 0
				BEGIN
					--DECLARE @ATIVO_C CHAR;
					--DECLARE	@C0_QNTD INT;
					
					SELECT @ATIVO_C = USE_YN FROM pangya_card WHERE UID = @IDUSER AND card_itemid = @IDITEM;
					IF @ATIVO = 'N'
					BEGIN
						UPDATE pangya_card SET QNTD = QNTD + @C_0 WHERE UID = @IDUSER AND card_itemid = @IDITEM;

						SELECT @C0_QNTD = QNTD FROM pangya_card WHERE UID = @IDUSER AND card_itemid = @IDITEM;
						IF @C0_QNTD <= 0
						BEGIN
							UPDATE pangya_card SET USE_YN = 'Y', QNTD = 0 WHERE UID = @IDUSER AND card_itemid = @IDITEM;
						END
					END;
					ELSE
					BEGIN
						UPDATE pangya_card SET QNTD = QNTD + @C_0, USE_YN = 'N' WHERE UID = @IDUSER AND card_itemid = @IDITEM;
					END;
				END;
		ELSE
			BEGIN
				INSERT INTO pangya_card(UID, card_typeid, card_type, QNTD, GET_DT, USE_YN)
						VALUES(@IDUSER, @ITEMTYPEID, 1, @C_0, getdate(), 'N');

				SELECT @IDITEM = MAX(CARD_ITEMID) FROM pangya_card WHERE UID = @IDUSER;
			END;

		SELECT @IDITEM AS ITEM_ID;
	END
	ELSE
		BEGIN  --#Por outros itens
			IF @IDITEM <= 0
			BEGIN
				SELECT @IDITEM = item_id FROM pangya_item_warehouse 
				WHERE UID = @IDUSER AND typeid = @ITEMTYPEID;
			END

			IF @IDITEM <= 0
				BEGIN
					INSERT INTO pangya_item_warehouse(UID, typeid, valid, regdate, Gift_flag, flag, C0, Purchase, ItemType, c1, c2, c3, c4)
							VALUES(@IDUSER, @ITEMTYPEID, 1, getdate(), @GIFTFLAG, @TYPEFLAG, @C_0, 0, 2, @C_1, @C_2, @C_3, @C_4);

					SELECT @IDITEM = MAX(ITEM_ID) FROM pangya_item_warehouse WHERE UID = @IDUSER;
				END;

			SELECT @IDITEM AS ITEM_ID;
		END;


END
GO
