CREATE PROCEDURE [pangya].[USP_ATT_COUNTER_ITEM]  
   @IDUSER int,
   @count_typeid int,
   @id_count int,
   @qntd int,
   @quest_typeid_high smallint,
   @quest_typeid_low smallint
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      /*
      *   SSMA informational messages:
      *   M2SS0134: Conversion of following Comment(s) is not supported : INSERT INTO pangya_quest_clear(UID, QUEST_ID, `OPTION`) SELECT IDUSER, IDX, 1 FROM achievement_quest
      *   			WHERE UID = IDUSER AND Data_Sec = 0 AND typeid_achieve = @quest_typeid
      *   				AND objetivo_quest <= (SELECT count_num_item FROM count_item WHERE UID = IDUSER AND count_id = id_count) GROUP BY IDX;
      *
      *   M2SS0134: Conversion of following Comment(s) is not supported : SET @quest_typeid := (quest_typeid_high << 16) | quest_typeid_low;
      *   		
      *           SET @min_objetivo := (SELECT MIN(objetivo_quest) FROM achievement_quest 
      *   				WHERE Data_Sec = 0 
      *   					AND ID_ACHIEVEMENT = (SELECT ID_ACHIEVEMENT FROM achievement_quest WHERE UID = IDUSER AND count_id = id_count LIMIT 1));
      *           
      *
      */

      IF 
         @IDUSER > 0 AND 
         @count_typeid > 0 AND 
         @id_count > 0 AND 
         @qntd > 0
         UPDATE pangya.count_item
            SET 
               count_num_item = count_item.Count_Num_Item + @qntd
         WHERE 
            count_item.UID = @IDUSER AND 
            count_item.Data_Sec = 0 AND 
            count_item.Count_ID = @id_count

   END
GO
/****** Objeto:  StoredProcedure [pangya].[USP_ATT_COURSE_REWARD_TREASURE]    Data do Script: 03/05/2026 15:40:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[USP_ATT_COURSE_REWARD_TREASURE]
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      UPDATE pangya.pangya_course_reward_treasure
         SET 
            PANGREWARD = 
               CASE 
                  WHEN (pangya_course_reward_treasure.PANGREWARD < 950) THEN pangya_course_reward_treasure.PANGREWARD + 50
                  ELSE 
                     CASE 
                        WHEN (pangya_course_reward_treasure.PANGREWARD < 1000) THEN 1000
                        ELSE pangya_course_reward_treasure.PANGREWARD
                     END
               END

