CREATE PROCEDURE [pangya].[USP_ATT_COURSE_REWARD_TREASURE_ONE]  
   @course_in int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      UPDATE pangya.pangya_course_reward_treasure
         SET 
            PANGREWARD = 
               CASE 
                  WHEN ((pangya_course_reward_treasure.PANGREWARD - 1) < 700) THEN 700
                  ELSE pangya_course_reward_treasure.PANGREWARD - 1
               END
      WHERE pangya_course_reward_treasure.COURSE = @course_in

   END
GO
