CREATE PROCEDURE [pangya].[USP_EXP_MASCOT_ATT]
	-- Add the parameters for the stored procedure here
	@IDUSER int,
	@mascot_id int,
	@xp int
AS
BEGIN
	DECLARE @mEXP_LVL INT = 0;
	DECLARE @mLvl INT,
			@exp INT

	SET @mLvl = (SELECT mLevel FROM pangya_mascot_info WHERE UID = @IDUSER AND item_id = @mascot_id);
    
    IF @mLvl < 9
	BEGIN
		SET @exp = (SELECT mExp FROM pangya_mascot_info WHERE UID = @IDUSER AND item_id = @mascot_id) + @xp;
		
		WHILE 1 = 1
		BEGIN
			SET @mEXP_LVL = 50 + (10 + (10 * @mLvl));
			
			IF @exp >= @mEXP_LVL
			BEGIN
				SET @mLvl = @mLvl + 1;
                
                IF @mLvl = 9
				BEGIN
					UPDATE pangya_mascot_info SET mExp = 0, mLevel = @mLvl
					WHERE UID = @IDUSER AND item_id = @mascot_id;
                    BREAK
				END
                ELSE
				BEGIN
					SET @exp = @exp - @mEXP_LVL;
					
					UPDATE pangya_mascot_info SET mExp = @exp, mLevel = @mLvl
					WHERE UID = @IDUSER AND item_id = @mascot_id;
                END
			END
			ELSE
			BEGIN
				UPDATE pangya_mascot_info SET mExp = @exp WHERE UID = @IDUSER AND item_id = @mascot_id;
                BREAK
			END
		END
	END
END
