CREATE PROCEDURE [pangya].[USP_FLUSH_STAT_CHARACTER]  
   @IDUSER int,
   @IDITEM int,
   @C_0 int,
   @C_1 int,
   @C_2 int,
   @C_3 int,
   @C_4 int,
   @PANG_IN bigint
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      UPDATE pangya.pangya_character_information
         SET 
            PCL0 = pangya_character_information.PCL0 + @C_0, 
            PCL1 = pangya_character_information.PCL1 + @C_1, 
            PCL2 = pangya_character_information.PCL2 + @C_2, 
            PCL3 = pangya_character_information.PCL3 + @C_3, 
            PCL4 = pangya_character_information.PCL4 + @C_4
      WHERE pangya_character_information.UID = @IDUSER AND pangya_character_information.item_id = @IDITEM

      UPDATE pangya.user_info
         SET 
            pang = user_info.Pang - @PANG_IN
      WHERE user_info.UID = @IDUSER

   END
GO
/****** Objeto:  StoredProcedure [pangya].[USP_FLUSH_STAT_CLUBSET]    Data do Script: 03/05/2026 15:40:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[USP_FLUSH_STAT_CLUBSET]  
   @IDUSER int,
   @IDITEM int,
   @C_0 int,
   @C_1 int,
   @C_2 int,
   @C_3 int,
   @C_4 int,
   @PANG_IN bigint
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @item int

      SET @item = 0

      SELECT @item = pangya_clubset_enchant.item_id
      FROM pangya.pangya_clubset_enchant
      WHERE pangya_clubset_enchant.uid = @IDUSER AND pangya_clubset_enchant.item_id = @IDITEM

      IF @item = 0
         /*
         *   SSMA informational messages:
         *   M2SS0214: The Default Values for the Columns have been added in the Insert Statement based on Project setttings.
         */

         INSERT pangya.pangya_clubset_enchant(
            pangya.pangya_clubset_enchant.uid, 
            pangya.pangya_clubset_enchant.item_id, 
            pangya.pangya_clubset_enchant.pang, 
            pangya.pangya_clubset_enchant.c0, 
            pangya.pangya_clubset_enchant.c1, 
            pangya.pangya_clubset_enchant.c2, 
            pangya.pangya_clubset_enchant.c3, 
            pangya.pangya_clubset_enchant.c4)
            VALUES (
               @IDUSER, 
               @IDITEM, 
               0, 
               0, 
               0, 
               0, 
               0, 
               0)

      UPDATE pangya.pangya_clubset_enchant
         SET 
            C0 = pangya_clubset_enchant.c0 + @C_0, 
            C1 = pangya_clubset_enchant.c1 + @C_1, 
            C2 = pangya_clubset_enchant.c2 + @C_2, 
            C3 = pangya_clubset_enchant.c3 + @C_3, 
            C4 = pangya_clubset_enchant.c4 + @C_4, 
            pang = pangya_clubset_enchant.pang + @PANG_IN
      WHERE pangya_clubset_enchant.uid = @IDUSER AND pangya_clubset_enchant.item_id = @IDITEM

      UPDATE pangya.user_info
         SET 
            pang = user_info.Pang - @PANG_IN
      WHERE user_info.UID = @IDUSER

   END
GO
