/****** Objeto:  StoredProcedure [pangya].[USP_ITEM_ACTIVE_ATT]    Data do Script: 03/05/2026 15:40:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[USP_ITEM_ACTIVE_ATT]  
   @IDUSER int,
   @ITEMTYPEID int
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      IF 
         (
            SELECT pangya_user_equip.item_slot_1
            FROM pangya.pangya_user_equip
            WHERE pangya_user_equip.UID = @IDUSER AND pangya_user_equip.item_slot_1 = @ITEMTYPEID
         ) IS NOT NULL
         UPDATE pangya.pangya_user_equip
            SET 
               item_slot_1 = 0
         WHERE pangya_user_equip.UID = @IDUSER
      ELSE 
         IF 
            (
               SELECT pangya_user_equip.item_slot_2
               FROM pangya.pangya_user_equip
               WHERE pangya_user_equip.UID = @IDUSER AND pangya_user_equip.item_slot_2 = @ITEMTYPEID
            ) IS NOT NULL
            UPDATE pangya.pangya_user_equip
               SET 
                  item_slot_2 = 0
            WHERE pangya_user_equip.UID = @IDUSER
         ELSE 
            IF 
               (
                  SELECT pangya_user_equip.item_slot_3
                  FROM pangya.pangya_user_equip
                  WHERE pangya_user_equip.UID = @IDUSER AND pangya_user_equip.item_slot_3 = @ITEMTYPEID
               ) IS NOT NULL
               UPDATE pangya.pangya_user_equip
                  SET 
                     item_slot_3 = 0
               WHERE pangya_user_equip.UID = @IDUSER
            ELSE 
               IF 
                  (
                     SELECT pangya_user_equip.item_slot_4
                     FROM pangya.pangya_user_equip
                     WHERE pangya_user_equip.UID = @IDUSER AND pangya_user_equip.item_slot_4 = @ITEMTYPEID
                  ) IS NOT NULL
                  UPDATE pangya.pangya_user_equip
                     SET 
                        item_slot_4 = 0
                  WHERE pangya_user_equip.UID = @IDUSER
               ELSE 
                  IF 
                     (
                        SELECT pangya_user_equip.item_slot_5
                        FROM pangya.pangya_user_equip
                        WHERE pangya_user_equip.UID = @IDUSER AND pangya_user_equip.item_slot_5 = @ITEMTYPEID
                     ) IS NOT NULL
                     UPDATE pangya.pangya_user_equip
                        SET 
                           item_slot_5 = 0
                     WHERE pangya_user_equip.UID = @IDUSER
                  ELSE 
                     IF 
                        (
                           SELECT pangya_user_equip.item_slot_6
                           FROM pangya.pangya_user_equip
                           WHERE pangya_user_equip.UID = @IDUSER AND pangya_user_equip.item_slot_6 = @ITEMTYPEID
                        ) IS NOT NULL
                        UPDATE pangya.pangya_user_equip
                           SET 
                              item_slot_6 = 0
                        WHERE pangya_user_equip.UID = @IDUSER
                     ELSE 
                        IF 
                           (
                              SELECT pangya_user_equip.item_slot_7
                              FROM pangya.pangya_user_equip
                              WHERE pangya_user_equip.UID = @IDUSER AND pangya_user_equip.item_slot_7 = @ITEMTYPEID
                           ) IS NOT NULL
                           UPDATE pangya.pangya_user_equip
                              SET 
                                 item_slot_7 = 0
                           WHERE pangya_user_equip.UID = @IDUSER
                        ELSE 
                           IF 
                              (
                                 SELECT pangya_user_equip.item_slot_8
                                 FROM pangya.pangya_user_equip
                                 WHERE pangya_user_equip.UID = @IDUSER AND pangya_user_equip.item_slot_8 = @ITEMTYPEID
                              ) IS NOT NULL
                              UPDATE pangya.pangya_user_equip
                                 SET 
                                    item_slot_8 = 0
                              WHERE pangya_user_equip.UID = @IDUSER
                           ELSE 
                              IF 
                                 (
                                    SELECT pangya_user_equip.item_slot_9
                                    FROM pangya.pangya_user_equip
                                    WHERE pangya_user_equip.UID = @IDUSER AND pangya_user_equip.item_slot_9 = @ITEMTYPEID
                                 ) IS NOT NULL
                                 UPDATE pangya.pangya_user_equip
                                    SET 
                                       item_slot_9 = 0
                                 WHERE pangya_user_equip.UID = @IDUSER
                              ELSE 
                                 BEGIN
                                    IF 
                                       (
                                          SELECT pangya_user_equip.item_slot_10
                                          FROM pangya.pangya_user_equip
                                          WHERE pangya_user_equip.UID = @IDUSER AND pangya_user_equip.item_slot_10 = @ITEMTYPEID
                                       ) IS NOT NULL
                                       UPDATE pangya.pangya_user_equip
                                          SET 
                                             item_slot_10 = 0
                                       WHERE pangya_user_equip.UID = @IDUSER
                                 END

      SELECT pangya_item_warehouse.item_id
      FROM pangya.pangya_item_warehouse
      WHERE pangya_item_warehouse.UID = @IDUSER AND pangya_item_warehouse.typeid = @ITEMTYPEID

   END
GO
