   @IDUSER int,
   @Macro_1 nvarchar(64),
   @Macro_2 nvarchar(64),
   @Macro_3 nvarchar(64),
   @Macro_4 nvarchar(64),
   @Macro_5 nvarchar(64),
   @Macro_6 nvarchar(64),
   @Macro_7 nvarchar(64),
   @Macro_8 nvarchar(64),
   @Macro_9 nvarchar(64),
   @Macro_10 nvarchar(64)
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      UPDATE pangya.pangya_user_macro
         SET 
            Macro1 = 
               CASE 
                  WHEN @Macro_1 IS NOT NULL THEN @Macro_1
                  ELSE N'Pangya!'
               END, 
            Macro2 = 
               CASE 
                  WHEN @Macro_2 IS NOT NULL THEN @Macro_2
                  ELSE N'Pangya!'
               END, 
            Macro3 = 
