/****** Objeto:  StoredProcedure [pangya].[USP_SAVE_ROOM]    Data do Script: 03/05/2026 15:40:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*
*   SSMA informational messages:
*   M2SS0003: The following SQL clause was ignored during conversion:
*   DEFINER = `root`@`localhost`.
*/

CREATE PROCEDURE [pangya].[USP_SAVE_ROOM]  
   @IDUSER int,
   @IDITEM int,
   @IDTYPE int,
   @NO_ROOM int,
   @X float(24),
   @Y float(24),
   @Z float(24),
   @R float(24),
   @YN_USE smallint
AS 
   BEGIN

      SET  XACT_ABORT  ON

      SET  NOCOUNT  ON

      DECLARE
         @Contador int, 
         @Contador2 int

      SELECT @Contador = count_big(*)
      FROM pangya.td_room_data
      WHERE td_room_data.UID = @IDUSER AND td_room_data.MYROOM_ID = @IDITEM

      SELECT @Contador2 = count_big(*)
      FROM pangya.td_room_data

      IF @Contador > 0
         UPDATE pangya.td_room_data
            SET 
               ROOM_NO = @NO_ROOM, 
               POS_X = @X, 
               POS_Y = @Y, 
               POS_Z = @Z, 
               POS_R = @R, 
               DISPLAY_YN = 
                  CASE 
                     WHEN @YN_USE = 1 THEN N'Y'
                     ELSE N'N'
                  END
         WHERE td_room_data.UID = @IDUSER AND td_room_data.MYROOM_ID = @IDITEM
      ELSE 
         IF @IDITEM IS NULL OR @IDITEM = 0
            BEGIN
               INSERT pangya.td_room_data(
                  pangya.td_room_data.UID, 
                  pangya.td_room_data.ROOM_NO, 
                  pangya.td_room_data.TYPEID, 
                  pangya.td_room_data.POS_X, 
                  pangya.td_room_data.POS_Y, 
                  pangya.td_room_data.POS_Z, 
                  pangya.td_room_data.POS_R, 
                  pangya.td_room_data.MOD_SEQ, 
                  pangya.td_room_data.DISPLAY_YN, 
                  pangya.td_room_data.MOD_DT)
                  VALUES (
                     @IDUSER, 
                     @NO_ROOM, 
                     @IDTYPE, 
                     @X, 
                     @Y, 
                     @Z, 
                     @R, 
                     @Contador2 + 1, 
                     N'Y', 
                     getdate())
            END
         ELSE 
            BEGIN

               SET  IDENTITY_INSERT pangya.td_room_data  ON

               INSERT pangya.td_room_data(
                  pangya.td_room_data.UID, 
                  pangya.td_room_data.ROOM_NO, 
                  pangya.td_room_data.TYPEID, 
                  pangya.td_room_data.MYROOM_ID, 
                  pangya.td_room_data.POS_X, 
                  pangya.td_room_data.POS_Y, 
                  pangya.td_room_data.POS_Z, 
                  pangya.td_room_data.POS_R, 
                  pangya.td_room_data.MOD_SEQ, 
                  pangya.td_room_data.DISPLAY_YN, 
                  pangya.td_room_data.MOD_DT)
                  VALUES (
                     @IDUSER, 
                     @NO_ROOM, 
                     @IDTYPE, 
                     @IDITEM, 
                     @X, 
                     @Y, 
                     @Z, 
                     @R, 
                     @Contador2 + 1, 
                     N'Y', 
                     getdate())

               SET  IDENTITY_INSERT pangya.td_room_data  OFF

            END

   END
GO
/****** Objeto:  StoredProcedure [pangya].[USP_UPDATE_GUILD_RANKING]    Data do Script: 03/05/2026 15:40:49 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [pangya].[USP_UPDATE_GUILD_RANKING]
AS
BEGIN

	DECLARE @GUID INT
	DECLARE @RANK INT = 1

	DECLARE tmp CURSOR FOR
		SELECT 
			GUILD_UID 
		FROM pangya.pangya_guild
		WHERE GUILD_POINT <> 0 AND GUILD_PANG <> 0 AND (GUILD_WIN <> 0 OR GUILD_LOSE <> 0 OR GUILD_DRAW <> 0)
			AND (GUILD_STATE NOT IN(4, 5) OR GUILD_CLOSURE_DATE IS NULL OR getdate() < GUILD_CLOSURE_DATE)
		ORDER BY GUILD_WIN DESC, GUILD_LOSE, GUILD_DRAW, GUILD_POINT DESC, GUILD_PANG DESC

	OPEN tmp
	FETCH NEXT FROM tmp INTO @GUID
	WHILE @@FETCH_STATUS = 0
	BEGIN

		IF (SELECT GUILD_UID FROM pangya.pangya_guild_ranking WHERE GUILD_UID = @GUID) IS NOT NULL
		BEGIN
		
			-- Já tem a Guild no Rank Atualiza
			UPDATE pangya.pangya_guild_ranking
				SET LAST_RANK = [RANK],
					[RANK] = @RANK,
					REG_DATE = getdate()
			WHERE GUILD_UID = @GUID

		END
		ELSE
		BEGIN

			-- Não tem a Guild no Rank Adiciona
			INSERT INTO pangya.pangya_guild_ranking(GUILD_UID, [RANK], LAST_RANK, REG_DATE)
			VALUES(@GUID, @RANK, -1/*LAST RANK*/, getdate())
		END

		-- SOMA RANK + 1
		SET @RANK = @RANK + 1

		-- FETCH NEXT
		FETCH NEXT FROM tmp INTO @GUID
	END

	CLOSE tmp
	DEALLOCATE tmp

